export const HomeScreen: React.FC = () => {
  const { createGame, joinGame, reconnectGame } = useGame();
  const [view, setView] = useState<'MAIN' | 'JOIN' | 'CREATE'>('MAIN');
  const [joinCode, setJoinCode] = useState('');
  const [playerName, setPlayerName] = useState('');
  const [avatarUrl, setAvatarUrl] = useState<string | undefined>(undefined);
  const [showCamera, setShowCamera] = useState(false);

  const [activeSession, setActiveSession] = useState<{ code: string, id: string } | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
      const params = new URLSearchParams(window.location.search);
      const urlCode = params.get('code');
      if (urlCode) {
          setJoinCode(urlCode.toUpperCase());
          setView('JOIN');
      }

      const storedCode = sessionStorage.getItem('imposter_gameCode');
      const storedId = sessionStorage.getItem('imposter_playerId');

      if (storedCode && storedId) {
          setActiveSession({ code: storedCode, id: storedId });
      }
  }, []);

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setAvatarUrl(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleJoin = (e: React.FormEvent) => {
    e.preventDefault();
    if (joinCode && playerName && avatarUrl) {
      joinGame(joinCode, playerName, avatarUrl);
    }
  };

  const handleRejoin = () => {
      if (activeSession) {
          reconnectGame(activeSession.code, activeSession.id);
      }
  };

  const clearSession = () => {
      sessionStorage.removeItem('imposter_gameCode');
      sessionStorage.removeItem('imposter_playerId');
      setActiveSession(null);
  };

  const handleCreate = (e: React.FormEvent) => {
      e.preventDefault();
      if (playerName && avatarUrl) {
          createGame(playerName, avatarUrl);
      }
  }

  const renderPhotoUpload = () => (
    <div className="flex flex-col items-center gap-4 mb-4">
        {showCamera && (
            <Camera 
                onCapture={(img) => { setAvatarUrl(img); setShowCamera(false); }}
                onCancel={() => setShowCamera(false)}
            />
        )}

        <div className={`w-32 h-32 rounded-full bg-slate-800 border-4 flex items-center justify-center overflow-hidden relative transition-all ${!avatarUrl ? 'border-game-primary border-dashed animate-pulse' : 'border-game-accent shadow-lg scale-105'}`}>
            {avatarUrl ? (
                <img src={avatarUrl} alt="Preview" className="w-full h-full object-cover" />
            ) : (
                <div className="text-center p-2 text-slate-500">
                    <span className="text-4xl">👤</span>
                </div>
            )}
        </div>

        <div className="flex gap-2 w-full">
            <Button 
                type="button" 
                variant="secondary" 
                className="flex-1 py-2 text-xs"
                onClick={() => fileInputRef.current?.click()}
            >
                Upload
            </Button>
            <Button 
                type="button" 
                variant="secondary" 
                className="flex-1 py-2 text-xs"
                onClick={() => setShowCamera(true)}
            >
                Take Selfie
            </Button>
        </div>

        <input 
            type="file" 
            ref={fileInputRef} 
            className="hidden" 
            accept="image/*" 
            onChange={handleImageUpload}
        />

        {avatarUrl && <button type="button" onClick={() => setAvatarUrl(undefined)} className="text-xs text-red-400 hover:text-red-300">Remove Photo</button>}
    </div>
  );

  return (
    <div className="flex flex-col items-center justify-center min-h-screen p-6 text-center relative overflow-hidden">
      <div className="absolute top-0 left-0 w-full h-full overflow-hidden pointer-events-none">
         <div className="absolute top-0 left-1/4 w-72 h-72 bg-purple-500 rounded-full mix-blend-multiply filter blur-3xl opacity-20 animate-blob"></div>
         <div className="absolute top-0 right-1/4 w-72 h-72 bg-indigo-500 rounded-full mix-blend-multiply filter blur-3xl opacity-20 animate-blob animation-delay-2000"></div>
         <div className="absolute -bottom-8 left-1/3 w-72 h-72 bg-pink-500 rounded-full mix-blend-multiply filter blur-3xl opacity-20 animate-blob animation-delay-4000"></div>
      </div>

      <div className="z-10 w-full max-w-md space-y-8">
        <div className="animate-fade-in-down">
          <GameLogo />
          <h1 className="text-6xl font-black tracking-tighter text-transparent bg-clip-text bg-gradient-to-r from-indigo-200 via-purple-200 to-pink-200 mb-1 drop-shadow-lg">IMPOSTER</h1>
          <p className="text-indigo-200/60 text-sm uppercase tracking-[0.5em] font-medium">Digital Deduction</p>
        </div>

        {view === 'MAIN' && (
          <div className="flex flex-col gap-4 animate-fade-in-up">
            {activeSession && (
                <div className="bg-indigo-500/20 border border-indigo-500/50 p-4 rounded-xl flex items-center justify-between">
                    <div className="text-left">
                        <p className="text-xs text-indigo-300 font-bold uppercase">Game Found</p>
                        <p className="text-white font-mono">{activeSession.code}</p>
                    </div>
                    <div className="flex gap-2">
                        <Button onClick={handleRejoin} className="!py-2 !px-4 text-sm">REJOIN</Button>
                        <button onClick={clearSession} className="text-slate-500 hover:text-white px-2">✕</button>
                    </div>
                </div>
            )}

            <Button onClick={() => setView('CREATE')} className="shadow-indigo-500/20">
              CREATE GAME
            </Button>
            <Button variant="secondary" onClick={() => setView('JOIN')} className="backdrop-blur-sm">
              JOIN GAME
            </Button>
          </div>
        )}

        {view === 'JOIN' && (
          <form onSubmit={handleJoin} className="flex flex-col gap-4 bg-slate-900/50 backdrop-blur-xl p-8 rounded-3xl shadow-2xl border border-white/10 animate-fade-in-up">
            <h2 className="text-xl font-bold mb-2 text-white">Join Lobby</h2>
            {renderPhotoUpload()}
            <input 
              type="text" 
              placeholder="GAME CODE" 
              className="w-full bg-black/30 border border-white/10 p-4 rounded-xl text-center text-xl font-mono uppercase focus:border-indigo-500 focus:ring-2 focus:ring-indigo-500/50 outline-none transition-all placeholder:text-slate-500 text-white"
              value={joinCode}
              onChange={e => setJoinCode(e.target.value.toUpperCase())}
            />
             <input 
              type="text" 
              placeholder="YOUR NAME" 
              className="w-full bg-black/30 border border-white/10 p-4 rounded-xl text-center text-xl focus:border-indigo-500 focus:ring-2 focus:ring-indigo-500/50 outline-none transition-all placeholder:text-slate-500 text-white"
              value={playerName}
              onChange={e => setPlayerName(e.target.value)}
            />
            <div className="flex gap-3 mt-4">
                <Button type="button" variant="secondary" onClick={() => setView('MAIN')} className="flex-1">
                    Back
                </Button>
                <Button type="submit" variant="primary" className="flex-1" disabled={!joinCode || !playerName || !avatarUrl}>
                    Enter
                </Button>
            </div>
          </form>
        )}

        {view === 'CREATE' && (
          <form onSubmit={handleCreate} className="flex flex-col gap-4 bg-slate-900/50 backdrop-blur-xl p-8 rounded-3xl shadow-2xl border border-white/10 animate-fade-in-up">
            <h2 className="text-xl font-bold mb-2 text-white">Create Game</h2>
            {renderPhotoUpload()}
             <input 
              type="text" 
              placeholder="YOUR NAME" 
              className="w-full bg-black/30 border border-white/10 p-4 rounded-xl text-center text-xl focus:border-indigo-500 focus:ring-2 focus:ring-indigo-500/50 outline-none transition-all placeholder:text-slate-500 text-white"
              value={playerName}
              onChange={e => setPlayerName(e.target.value)}
            />
            <div className="flex gap-3 mt-4">
                <Button type="button" variant="secondary" onClick={() => setView('MAIN')} className="flex-1">
                    Back
                </Button>
                <Button type="submit" variant="primary" className="flex-1" disabled={!playerName || !avatarUrl}>
                    Create
                </Button>
            </div>
          </form>
        )}
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { useGame } from '../context/GameContext';
import { Button } from '../components/Button';
import { Avatar } from '../components/Avatar';

export const VotingScreen: React.FC = () => {
  const { state, submitVote, myPlayerId, amIGameHost } = useGame();
  const { players, clues, votes } = state;

  const [selectedSuspect, setSelectedSuspect] = useState<string | null>(null);

  const myVote = myPlayerId ? votes[myPlayerId] : null;
  const humanPlayers = players.filter(p => !p.isBot && !p.isHost);
  const candidates = players.filter(p => !p.isHost);

  // --- HOST VIEW: MONITORING ---
  if (amIGameHost) {
      const voteCount = humanPlayers.filter(p => votes[p.id]).length;
      return (
          <div className="min-h-screen bg-game-bg flex flex-col items-center justify-center p-6 text-center">
              <h2 className="text-2xl font-black text-white mb-2 uppercase tracking-widest">Voting Progress</h2>
              <p className="text-slate-400 mb-8">You are moderating. Waiting for players...</p>

              <div className="w-full max-w-md bg-game-surface p-6 rounded-3xl border border-white/10 shadow-2xl space-y-4">
                  <div className="flex justify-between items-center mb-4">
                      <span className="text-xs font-bold text-slate-500 uppercase">Status</span>
                      <span className="text-xs font-bold text-game-primary uppercase">{voteCount} / {humanPlayers.length} Voted</span>
                  </div>

                  {humanPlayers.map(p => (
                      <div key={p.id} className="flex items-center justify-between bg-slate-900/50 p-3 rounded-xl border border-slate-700">
                          <div className="flex items-center gap-3">
                              <Avatar seed={p.avatarSeed} url={p.avatarUrl} size="sm" />
                              <span className="font-bold">{p.name}</span>
                          </div>
                          {votes[p.id] ? (
                              <span className="text-game-success text-xs font-black uppercase">✓ Voted</span>
                          ) : (
                              <span className="text-slate-500 text-xs font-black uppercase animate-pulse">Waiting...</span>
                          )}
                      </div>
                  ))}
              </div>
          </div>
      );
  }

  // --- PLAYER VIEW: DONE VOTING ---
  if (myVote) {
      return (
          <div className="min-h-screen bg-game-bg flex flex-col items-center justify-center p-6 text-center">
              <div className="w-20 h-20 bg-game-success/20 rounded-full flex items-center justify-center mb-6 animate-bounce-in">
                  <span className="text-4xl">✓</span>
              </div>
              <h2 className="text-2xl font-black text-white mb-2 uppercase tracking-widest">Vote Cast!</h2>
              <p className="text-slate-400">Waiting for other players to decide...</p>
          </div>
      );
  }

  // --- PLAYER VIEW: CASTING VOTE ---
  const handleConfirmVote = () => {
      if (selectedSuspect && myPlayerId) {
          submitVote(myPlayerId, selectedSuspect);
      }
  };

  return (
    <div className="min-h-screen bg-game-bg flex flex-col p-4">
      <div className="text-center mb-6">
          <h2 className="text-2xl font-black text-white mb-1 uppercase tracking-widest">CAST YOUR VOTE</h2>
          <p className="text-xs text-game-danger font-bold uppercase tracking-widest">Identify the Imposter</p>
      </div>

      {clues.length > 0 && (
        <div className="bg-slate-800/50 rounded-xl p-4 mb-6 max-h-48 overflow-y-auto border border-slate-700">
             <h3 className="text-[10px] font-black text-slate-500 uppercase mb-3 tracking-widest">Round Summary</h3>
             <div className="space-y-4">
                 {players.filter(p => !p.isHost).map(p => {
                     const playerClues = clues.filter(c => c.playerId === p.id);
                     if (playerClues.length === 0) return null;
                     return (
                         <div key={p.id} className="flex justify-between items-start border-b border-slate-700 pb-2">
                            <div className="flex items-center gap-2">
                                <Avatar seed={p.avatarSeed} url={p.avatarUrl} size="sm" />
                                <span className="font-bold text-sm">{p.name}</span>
                            </div>
                            <div className="flex flex-col items-end">
                                {playerClues.map((c, i) => (
                                    <span key={i} className="text-game-accent italic text-xs">"{c.text}"</span>
                                ))}
                            </div>
                         </div>
                     )
                 })}
             </div>
        </div>
      )}

      <div className="flex-1">
          <div className="grid grid-cols-3 gap-4">
              {candidates.map(p => {
                  const isSelected = selectedSuspect === p.id;
                  const isSelf = p.id === myPlayerId;

                  return (
                      <div key={p.id} className="relative">
                          <button
                            onClick={() => !isSelf && setSelectedSuspect(p.id)}
                            disabled={isSelf}
                            className={`w-full flex flex-col items-center p-3 rounded-xl transition-all border-2 ${isSelf ? 'opacity-30 grayscale border-transparent' : ''} ${isSelected ? 'bg-game-danger/20 border-game-danger scale-105 shadow-lg' : 'border-slate-800 hover:bg-slate-800'}`}
                          >
                             <Avatar seed={p.avatarSeed} url={p.avatarUrl} size="md" />
                             <span className="mt-2 text-[10px] font-black uppercase truncate w-full text-center">{p.name}</span>
                          </button>
                          {isSelected && (
                              <div className="absolute -top-1 -right-1 bg-game-danger text-white rounded-full p-1 shadow-lg z-10">
                                  <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={4} d="M5 13l4 4L19 7" /></svg>
                              </div>
                          )}
                      </div>
                  );
              })}
          </div>
      </div>

      <div className="mt-6 p-4 bg-slate-900/60 rounded-2xl border border-white/5">
          <Button onClick={handleConfirmVote} disabled={!selectedSuspect} fullWidth variant="danger">
              CONFIRM VOTE
          </Button>
      </div>
    </div>
  );
};

import React, { useEffect, useState } from 'react';
import { useGame } from '../context/GameContext';
import { Avatar } from '../components/Avatar';
import { Button } from '../components/Button';

export const RevealScreen: React.FC = () => {
  const { state, startImposterGuess, amIGameHost } = useGame();
  const { players } = state;

  const [stage, setStage] = useState(0); 

  const maxVotes = Math.max(...players.map(p => p.voteCount));
  const accusedPlayers = players.filter(p => p.voteCount === maxVotes);

  useEffect(() => {
    const t1 = setTimeout(() => setStage(1), 3000); 
    const t2 = setTimeout(() => setStage(2), 6000); 
    return () => { clearTimeout(t1); clearTimeout(t2); };
  }, []);

  return (
    <div className="min-h-screen bg-game-bg flex flex-col items-center justify-center p-6 text-center">

      {stage === 0 && (
        <div className="w-full grid grid-cols-3 gap-8 animate-fade-in">
           {players.filter(p => !p.isHost).map(p => (
               <div key={p.id} className="relative flex flex-col items-center">
                   <Avatar seed={p.avatarSeed} url={p.avatarUrl} name={p.name} size="lg" />
                   {p.voteCount > 0 && (
                       <div className="absolute -top-2 -right-2 bg-white text-black font-black w-8 h-8 rounded-full flex items-center justify-center shadow-lg transform scale-110">
                           {p.voteCount}
                       </div>
                   )}
               </div>
           ))}
        </div>
      )}

      {stage === 1 && (
        <div className="animate-shake">
            <h1 className="text-4xl font-black text-white tracking-widest mb-4 uppercase">The Imposter Was...</h1>
            <div className="w-16 h-16 border-4 border-game-primary border-t-transparent rounded-full animate-spin mx-auto"></div>
        </div>
      )}

      {stage === 2 && (
        <div className="w-full max-w-lg space-y-8 animate-bounce-in">
             <div className="grid grid-cols-3 gap-4 opacity-50 grayscale pointer-events-none">
                 {players.filter(p => !p.isImposter && !p.isHost).map(p => (
                     <Avatar key={p.id} seed={p.avatarSeed} url={p.avatarUrl} name={p.name} size="sm" />
                 ))}
             </div>

             <div className="py-8 border-y border-game-danger/50 bg-game-danger/10 relative overflow-hidden">
                 <div className="absolute inset-0 bg-red-500/5 animate-pulse"></div>
                 <h2 className="text-game-danger font-black text-3xl uppercase tracking-widest mb-6 relative z-10">IMPOSTERS REVEALED</h2>
                 <div className="flex justify-center gap-6 relative z-10">
                     {players.filter(p => p.isImposter).map(p => (
                         <div key={p.id} className="flex flex-col items-center transform scale-125">
                              <Avatar seed={p.avatarSeed} url={p.avatarUrl} size="xl" className="ring-4 ring-game-danger rounded-full" />
                              <span className="mt-4 font-bold text-white text-xl">{p.name}</span>
                              {accusedPlayers.some(acc => acc.id === p.id) ? (
                                  <span className="text-game-danger font-black uppercase mt-1 animate-pulse">CAUGHT!</span>
                              ) : (
                                  <span className="text-game-success font-black uppercase mt-1">HIDDEN!</span>
                              )}
                         </div>
                     ))}
                 </div>
             </div>

             <div className="space-y-4">
                 {amIGameHost ? (
                     <>
                        <p className="text-indigo-400 font-bold uppercase text-xs tracking-widest">You are the Host</p>
                        <Button 
                            onClick={startImposterGuess} 
                            className="w-full max-w-xs animate-pulse"
                        >
                            PROCEED TO FINAL GUESS &rarr;
                        </Button>
                     </>
                 ) : (
                     <p className="text-slate-500 animate-pulse uppercase text-sm font-bold tracking-widest">
                         Waiting for Host to proceed...
                     </p>
                 )}
             </div>
        </div>
      )}
    </div>
  );
};

import React, { useState } from 'react';
import { useGame } from '../context/GameContext';
import { Button } from '../components/Button';
import { Avatar } from '../components/Avatar';
import { GamePhase } from '../types';

export const ImposterGuessScreen: React.FC = () => {
  const { state, submitImposterGuess, judgeImposterGuess, myPlayerId, amIGameHost } = useGame();
  const { phase, players, clues, imposterGuess, topic } = state;

  const [guessInput, setGuessInput] = useState('');

  const me = players.find(p => p.id === myPlayerId);
  const imposter = players.find(p => p.isImposter);
  const host = players.find(p => p.id === state.currentHostId);

  const isMeImposter = me?.isImposter;

  // 1. Imposter View (Final Guess Input)
  if (phase === GamePhase.IMPOSTER_GUESS) {
      if (isMeImposter) {
          return (
              <div className="min-h-screen bg-game-bg flex flex-col p-6">
                  <div className="text-center mb-6">
                      <span className="text-6xl block mb-2">🤫</span>
                      <h2 className="text-2xl font-black text-white uppercase tracking-widest">FINAL CHANCE</h2>
                      <p className="text-game-danger text-sm font-bold uppercase">Guess the secret topic to win!</p>
                  </div>

                  <div className="bg-slate-800 rounded-2xl p-4 flex-1 mb-6 overflow-y-auto border border-slate-700 shadow-inner">
                      <h3 className="text-slate-500 font-black uppercase text-[10px] mb-4 tracking-widest sticky top-0 bg-slate-800 py-1">Clue History</h3>
                      <div className="space-y-4">
                          {clues.length === 0 ? (
                               <p className="text-slate-500 italic text-center py-8">No clues recorded this round.</p>
                          ) : (
                              clues.map((clue, idx) => {
                                  const author = players.find(p => p.id === clue.playerId);
                                  return (
                                      <div key={idx} className="flex items-center gap-3">
                                          <Avatar seed={author?.avatarSeed || '0'} url={author?.avatarUrl} size="sm" />
                                          <div className="bg-slate-700/50 p-3 rounded-xl rounded-tl-none border border-white/5">
                                              <p className="text-white font-medium italic">"{clue.text}"</p>
                                          </div>
                                      </div>
                                  )
                              })
                          )}
                      </div>
                  </div>

                  <div className="space-y-4 bg-slate-900/60 p-6 rounded-3xl border border-white/10">
                      <input 
                          type="text"
                          className="w-full bg-black/40 border-2 border-slate-700 p-4 rounded-xl text-center text-xl text-white focus:border-game-primary outline-none transition-all uppercase font-bold"
                          placeholder="What was the topic?"
                          value={guessInput}
                          onChange={e => setGuessInput(e.target.value.toUpperCase())}
                          autoFocus
                      />
                      <Button fullWidth onClick={() => submitImposterGuess(guessInput)} disabled={!guessInput.trim()}>
                          SUBMIT GUESS
                      </Button>
                  </div>
              </div>
          );
      } else {
          // Others View
          return (
              <div className="min-h-screen bg-game-bg flex flex-col items-center justify-center p-6 text-center">
                  <Avatar seed={imposter?.avatarSeed || '0'} url={imposter?.avatarUrl} size="xl" className="mb-6 animate-pulse" />
                  <h2 className="text-2xl font-black text-white mb-2 uppercase tracking-widest">WAITING FOR {imposter?.name}</h2>
                  <p className="text-slate-400 max-w-xs">The Imposter is trying to guess the secret topic...</p>
                  <div className="mt-8">
                      <div className="w-12 h-12 border-4 border-game-danger border-t-transparent rounded-full animate-spin mx-auto"></div>
                  </div>
              </div>
          );
      }
  }

  // 2. Host Review View (Judging)
  if (phase === GamePhase.HOST_REVIEW) {
      if (amIGameHost) {
          return (
              <div className="min-h-screen bg-game-bg flex flex-col items-center justify-center p-6 text-center">
                  <div className="mb-8">
                      <span className="text-xs uppercase font-black text-indigo-400 tracking-widest block mb-1">Moderator Review</span>
                      <h2 className="text-3xl font-black text-white">IS IT CORRECT?</h2>
                  </div>

                  <div className="bg-slate-800 p-8 rounded-3xl border-2 border-indigo-500/30 w-full max-w-md mb-8 shadow-2xl space-y-8">
                      <div className="bg-slate-900/50 p-4 rounded-2xl">
                          <span className="text-[10px] uppercase font-black text-slate-500 tracking-widest">The Secret Topic Was</span>
                          <h3 className="text-3xl font-black text-game-success tracking-tight mt-1 uppercase">{topic}</h3>
                      </div>

                      <div className="relative">
                          <div className="absolute inset-x-0 top-1/2 h-px bg-slate-700"></div>
                          <span className="relative z-10 bg-slate-800 px-4 text-xs font-black text-slate-500">VERSUS</span>
                      </div>

                      <div className="bg-slate-900/50 p-4 rounded-2xl">
                           <span className="text-[10px] uppercase font-black text-slate-500 tracking-widest">{imposter?.name} Guessed</span>
                           <h3 className="text-3xl font-black text-white tracking-tight mt-1 uppercase italic">"{imposterGuess}"</h3>
                      </div>
                  </div>

                  <div className="flex gap-4 w-full max-w-md">
                      <button 
                        onClick={() => judgeImposterGuess(false)}
                        className="flex-1 bg-game-danger hover:bg-red-600 text-white font-black py-5 rounded-2xl shadow-lg flex flex-col items-center transition-transform active:scale-95"
                      >
                          <span className="text-3xl mb-1">✗</span>
                          WRONG
                      </button>
                      <button 
                        onClick={() => judgeImposterGuess(true)}
                        className="flex-1 bg-game-success hover:bg-green-600 text-white font-black py-5 rounded-2xl shadow-lg flex flex-col items-center transition-transform active:scale-95"
                      >
                          <span className="text-3xl mb-1">✓</span>
                          CLOSE ENOUGH
                      </button>
                  </div>
              </div>
          );
      } else {
          return (
              <div className="min-h-screen bg-game-bg flex flex-col items-center justify-center p-6 text-center">
                  <Avatar seed={host?.avatarSeed || '0'} url={host?.avatarUrl} size="lg" className="mb-4 animate-pulse" />
                  <h2 className="text-2xl font-black text-white mb-2 uppercase tracking-widest">Host is Judging</h2>
                  <p className="text-slate-400">Wait for the final verdict...</p>
                  <div className="mt-8 flex gap-2">
                       <div className="w-3 h-3 bg-indigo-500 rounded-full animate-bounce"></div>
                       <div className="w-3 h-3 bg-indigo-500 rounded-full animate-bounce delay-100"></div>
                       <div className="w-3 h-3 bg-indigo-500 rounded-full animate-bounce delay-200"></div>
                  </div>
              </div>
          );
      }
  }

  return null;
};

export enum GamePhase {
  HOME = 'HOME',
  LOBBY = 'LOBBY',
  SETUP = 'SETUP', 
  TOPIC_SELECTION = 'TOPIC_SELECTION',
  ROLE_REVEAL = 'ROLE_REVEAL', 
  ROUND_STARTER = 'ROUND_STARTER', 
  DISCUSSION = 'DISCUSSION', 
  PASS_DEVICE = 'PASS_DEVICE', 
  CLUES = 'CLUES',
  VOTING = 'VOTING',
  REVEAL = 'REVEAL',
  IMPOSTER_GUESS = 'IMPOSTER_GUESS',
  HOST_REVIEW = 'HOST_REVIEW',
  SCOREBOARD = 'SCOREBOARD',
  WINNER = 'WINNER'
}

export enum PlayerRole {
  HOST = 'HOST',
  PLAYER = 'PLAYER',
  IMPOSTER = 'IMPOSTER'
}

export interface Player {
  id: string;
  name: string;
  avatarSeed: string; 
  avatarUrl?: string; 
  isHost: boolean;
  isImposter: boolean;
  isBot: boolean; 
  score: number;
  voteCount: number;
  isReady: boolean; 
}

export interface Clue {
  playerId: string;
  text: string;
  timestamp: number;
}

export interface GameConfig {
  mode: 'IN_PERSON' | 'PHONE';
  imposterCount: number;
}

export interface GameState {
  gameCode: string;
  phase: GamePhase;
  players: Player[];
  config: GameConfig;

  currentTurnIndex: number;
  clueRound: number; 

  currentHostId: string | null; 
  hostIndex: number; 
  pastHostIds: string[]; 

  topic: string;
  category: string; 
  topicImage?: string; 

  clues: Clue[];
  votes: Record<string, string>; 
  imposterGuess: string | null;
  imposterGuessCorrect: boolean | null;
  winningPlayerId: string | null;

  nextPlayerTurnId: string | null; 
}

export interface GameContextType {
  state: GameState;
  isHost: boolean; 
  isNetworkHost: boolean; 
  myPlayerId: string | null;
  amIGameHost: boolean; 
  createGame: (name: string, avatarUrl?: string) => void;
  joinGame: (code: string, name: string, avatarUrl?: string) => void;
  reconnectGame: (code: string, playerId: string) => void; 
  updateConfig: (config: Partial<GameConfig>) => void;
  startGame: () => void;
  setTopic: (topic: string, category: string, image?: string, manualImposterIds?: string[]) => void;
  submitClue: (text: string) => void;
  submitVote: (voterId: string, votedForId: string) => void;
  submitImposterGuess: (guess: string) => void;
  judgeImposterGuess: (isCorrect: boolean) => void;
  acknowledgeRoundEnd: (playerId: string) => void;
  resetGame: () => void;
  addBot: () => void;
  confirmPassDevice: () => void;
  finishRoleReveal: () => void;
  startVoting: () => void;
  confirmStarter: () => void;
  startImposterGuess: () => void;
}

import React, { createContext, useContext, useState, useEffect, useRef } from 'react';
import { GamePhase, GameState, Player, GameConfig, GameContextType } from '../types';
import Peer, { DataConnection } from 'peerjs';

type GameAction = 
  | { type: 'SYNC_STATE'; state: GameState }
  | { type: 'JOIN_REQUEST'; player: Player }
  | { type: 'UPDATE_CONFIG'; config: Partial<GameConfig> }
  | { type: 'START_GAME' }
  | { type: 'SET_TOPIC'; topic: string; category: string; image?: string; manualImposterIds?: string[] }
  | { type: 'SUBMIT_CLUE'; text: string }
  | { type: 'SUBMIT_VOTE'; voterId: string; votedForId: string }
  | { type: 'START_VOTING' }
  | { type: 'CONFIRM_STARTER' }
  | { type: 'START_IMPOSTER_GUESS' }
  | { type: 'SUBMIT_GUESS'; guess: string }
  | { type: 'JUDGE_GUESS'; isCorrect: boolean }
  | { type: 'ACK_ROUND_END'; playerId: string }
  | { type: 'RESET_GAME' }
  | { type: 'ADD_BOT' };

const GameContext = createContext<GameContextType | undefined>(undefined);

const INITIAL_STATE: GameState = {
  gameCode: '',
  phase: GamePhase.HOME,
  players: [],
  config: { mode: 'IN_PERSON', imposterCount: 1 },
  currentTurnIndex: 0,
  clueRound: 1,
  currentHostId: null,
  hostIndex: 0,
  pastHostIds: [],
  topic: '',
  category: '',
  clues: [],
  votes: {},
  imposterGuess: null,
  imposterGuessCorrect: null,
  winningPlayerId: null,
  nextPlayerTurnId: null,
};

const PEER_PREFIX = 'imposter-game-v1-';

export const GameProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [state, setState] = useState<GameState>(INITIAL_STATE);
  const [isHost, setIsHost] = useState(false);
  const [myPlayerId, setMyPlayerId] = useState<string | null>(null);

  const peerRef = useRef<Peer | null>(null);
  const connectionsRef = useRef<DataConnection[]>([]);
  const hostConnRef = useRef<DataConnection | null>(null);

  useEffect(() => {
    const storedId = sessionStorage.getItem('imposter_playerId');
    if (storedId) setMyPlayerId(storedId);
  }, []);

  useEffect(() => {
    if (myPlayerId) sessionStorage.setItem('imposter_playerId', myPlayerId);
    if (state.gameCode) sessionStorage.setItem('imposter_gameCode', state.gameCode);
  }, [myPlayerId, state.gameCode]);

  // Bot Host Shortcut: If a bot is the host, it automatically picks Pizza
  useEffect(() => {
    if (isHost && state.phase === GamePhase.TOPIC_SELECTION) {
      const currentHost = state.players.find(p => p.id === state.currentHostId);
      if (currentHost?.isBot) {
        const timer = setTimeout(() => {
          setTopic('PIZZA', 'Food/Drink');
        }, 1500);
        return () => clearTimeout(timer);
      }
    }
  }, [state.phase, state.currentHostId, isHost]);

  const broadcastState = (newState: GameState) => {
    connectionsRef.current.forEach(conn => {
      if (conn.open) {
        conn.send({ type: 'SYNC_STATE', state: newState });
      }
    });
  };

  const sendActionToHost = (action: GameAction) => {
    if (hostConnRef.current && hostConnRef.current.open) {
      hostConnRef.current.send(action);
    }
  };

  const processAction = (action: GameAction, currentState: GameState): GameState => {
    switch (action.type) {
        case 'JOIN_REQUEST':
            const existingIdx = currentState.players.findIndex(p => p.id === action.player.id);
            if (existingIdx !== -1) {
                const updatedPlayers = [...currentState.players];
                updatedPlayers[existingIdx] = {
                    ...updatedPlayers[existingIdx],
                    name: action.player.name,
                    avatarUrl: action.player.avatarUrl || updatedPlayers[existingIdx].avatarUrl
                };
                return { ...currentState, players: updatedPlayers };
            }
            if (currentState.players.some(p => p.name === action.player.name)) return currentState;
            return { ...currentState, players: [...currentState.players, action.player] };

        case 'UPDATE_CONFIG':
            return { ...currentState, config: { ...currentState.config, ...action.config } };

        case 'ADD_BOT': {
             const names = ["Alex", "Jordan", "Taylor", "Casey", "Jamie", "Riley", "Morgan", "Quinn"];
             const botPlayer: Player = {
                id: "BOT-" + Math.random().toString(36).substr(2, 9),
                name: names[Math.floor(Math.random() * names.length)] + " (Bot)",
                avatarSeed: Math.random().toString(),
                isHost: false,
                isImposter: false,
                isBot: true,
                score: 0,
                voteCount: 0,
                isReady: true
             };
             return { ...currentState, players: [...currentState.players, botPlayer] };
        }

        case 'START_GAME': {
            if (currentState.players.length < 3) return currentState;
            const randHostIdx = Math.floor(Math.random() * currentState.players.length);
            const hostId = currentState.players[randHostIdx].id;
            const newPlayers = currentState.players.map(p => ({
                ...p,
                isHost: p.id === hostId,
                isImposter: false,
                voteCount: 0,
                isReady: false
            }));
            return {
                ...currentState,
                players: newPlayers,
                currentHostId: hostId,
                pastHostIds: [hostId],
                phase: GamePhase.TOPIC_SELECTION,
                clues: [],
                votes: {},
                topic: '',
            };
        }

        case 'SET_TOPIC': {
            const hostId = currentState.currentHostId;
            const manualImposterIds = action.manualImposterIds || [];
            const shuffled = [...currentState.players];
            const imposterIndices = new Set<number>();

            if (manualImposterIds.length > 0) {
                 manualImposterIds.forEach(id => {
                     const idx = shuffled.findIndex(p => p.id === id);
                     if (idx !== -1) imposterIndices.add(idx);
                 });
            } else {
                 while (imposterIndices.size < currentState.config.imposterCount) {
                    const idx = Math.floor(Math.random() * shuffled.length);
                    if (shuffled[idx].id !== hostId && !imposterIndices.has(idx)) {
                        imposterIndices.add(idx);
                    }
                }
            }

            const newPlayers = shuffled.map((p, idx) => ({
                ...p,
                isHost: p.id === hostId,
                isImposter: imposterIndices.has(idx),
                isReady: false
            }));

            const eligibleStarterIndices = newPlayers
                .map((p, idx) => p.isHost ? -1 : idx)
                .filter(idx => idx !== -1);
            const randomStarterIndex = eligibleStarterIndices[Math.floor(Math.random() * eligibleStarterIndices.length)];

            return {
                ...currentState,
                players: newPlayers,
                currentTurnIndex: randomStarterIndex,
                topic: action.topic,
                category: action.category,
                topicImage: action.image,
                phase: GamePhase.ROLE_REVEAL
            };
        }

        case 'CONFIRM_STARTER':
            return { ...currentState, phase: GamePhase.DISCUSSION };

        case 'START_VOTING': {
             const bots = currentState.players.filter(p => p.isBot && !p.isHost);
             let simulatedVotes = { ...currentState.votes };
             if (bots.length > 0) {
                 simulatedVotes = simulateBotVotes(currentState.players, currentState.config.imposterCount, simulatedVotes);
             }
             return { ...currentState, votes: simulatedVotes, phase: GamePhase.VOTING };
        }

        case 'SUBMIT_CLUE': {
            const currentPlayer = currentState.players[currentState.currentTurnIndex];
            const newClues = [...currentState.clues, { playerId: currentPlayer.id, text: action.text, timestamp: Date.now() }];
            const activePlayerCount = currentState.players.length - 1;
            const totalCluesNeeded = activePlayerCount * 2;

            let nIdx = (currentState.currentTurnIndex + 1) % currentState.players.length;
            let nRound = currentState.clueRound;
            let nClues = [...newClues];

            while(true) {
                const p = currentState.players[nIdx];
                if (nClues.length >= totalCluesNeeded) break;
                if (p.isHost) {
                    nIdx = (nIdx + 1) % currentState.players.length;
                    continue;
                }
                if (p.isBot) {
                    nClues.push({ playerId: p.id, text: `AI: ${['Interesting...', 'I see.', 'Yes.', 'Maybe.'][Math.floor(Math.random()*4)]}`, timestamp: Date.now() });
                    nIdx = (nIdx + 1) % currentState.players.length;
                    continue;
                }
                break;
            }

            if (nClues.length >= totalCluesNeeded) {
                 const botVotes = simulateBotVotes(currentState.players, currentState.config.imposterCount, {});
                 return { ...currentState, clues: nClues, votes: botVotes, phase: GamePhase.VOTING };
            }

            if (nClues.length >= activePlayerCount) nRound = 2;

            return {
                ...currentState,
                clues: nClues,
                currentTurnIndex: nIdx,
                clueRound: nRound,
                phase: GamePhase.CLUES
            };
        }

        case 'SUBMIT_VOTE': {
            const newVotes = { ...currentState.votes, [action.voterId]: action.votedForId };
            const votingHumans = currentState.players.filter(p => !p.isBot && !p.isHost);
            const humansWhoVoted = votingHumans.filter(h => newVotes[h.id]);

            if (humansWhoVoted.length === votingHumans.length) {
                const updatedPlayers = currentState.players.map(p => {
                    const votesReceived = Object.values(newVotes).filter(id => id === p.id).length;
                    return { ...p, voteCount: votesReceived };
                });
                return { ...currentState, players: updatedPlayers, votes: newVotes, phase: GamePhase.REVEAL };
            }
            return { ...currentState, votes: newVotes };
        }

        case 'START_IMPOSTER_GUESS':
             return { ...currentState, phase: GamePhase.IMPOSTER_GUESS };

        case 'SUBMIT_GUESS':
             return { ...currentState, imposterGuess: action.guess, phase: GamePhase.HOST_REVIEW };

        case 'JUDGE_GUESS': {
            let maxVotes = 0;
            currentState.players.forEach(p => { if(p.voteCount > maxVotes) maxVotes = p.voteCount; });
            const accusedPlayers = currentState.players.filter(p => p.voteCount === maxVotes);

            const newPlayers = currentState.players.map(p => {
                let points = p.score;
                if (p.isHost) return p;
                if (p.isImposter) {
                    const isCaught = accusedPlayers.some(accused => accused.id === p.id);
                    if (!isCaught) points += 1;
                    if (action.isCorrect) points += 2;
                } else {
                    const votedForId = currentState.votes[p.id];
                    const votedForPerson = currentState.players.find(pl => pl.id === votedForId);
                    if (votedForPerson && votedForPerson.isImposter) points += 1;
                }
                return { ...p, score: points, isReady: false };
            });
            return { ...currentState, players: newPlayers, imposterGuessCorrect: action.isCorrect, phase: GamePhase.SCOREBOARD };
        }

        case 'ACK_ROUND_END': {
             const updatedPlayers = currentState.players.map(p => (p.id === action.playerId || p.isBot) ? { ...p, isReady: true } : p);
             const humans = updatedPlayers.filter(p => !p.isBot);
             if (humans.every(p => p.isReady)) {
                if (currentState.phase === GamePhase.ROLE_REVEAL) {
                    return {
                        ...currentState,
                        players: updatedPlayers.map(p => ({ ...p, isReady: false })), 
                        phase: currentState.config.mode === 'IN_PERSON' ? GamePhase.ROUND_STARTER : GamePhase.CLUES
                    };
                }
                const potentialHosts = currentState.players.filter(p => !currentState.pastHostIds.includes(p.id));
                if (potentialHosts.length === 0) { 
                     const sorted = [...updatedPlayers].sort((a,b) => b.score - a.score);
                     return { ...currentState, players: updatedPlayers, winningPlayerId: sorted[0].id, phase: GamePhase.WINNER };
                }
                const nextHost = potentialHosts[Math.floor(Math.random() * potentialHosts.length)];
                return {
                    ...currentState,
                    players: updatedPlayers.map(p => ({ ...p, isHost: p.id === nextHost.id, isImposter: false, isReady: false, voteCount: 0 })),
                    currentHostId: nextHost.id,
                    pastHostIds: [...currentState.pastHostIds, nextHost.id],
                    phase: GamePhase.TOPIC_SELECTION,
                    clues: [],
                    votes: {},
                    topic: '',
                    imposterGuess: null,
                };
             }
             return { ...currentState, players: updatedPlayers };
        }

        case 'RESET_GAME':
             return { ...INITIAL_STATE, gameCode: currentState.gameCode, phase: GamePhase.LOBBY, players: [] };

        default:
            return currentState;
    }
  };

  const simulateBotVotes = (allPlayers: Player[], imposterCount: number, existingVotes: Record<string,string>): Record<string, string> => {
    const votes: Record<string, string> = { ...existingVotes };
    const imposters = allPlayers.filter(p => p.isImposter);
    const nonImposters = allPlayers.filter(p => !p.isImposter && !p.isHost);
    allPlayers.filter(p => p.isBot && !p.isHost).forEach(bot => {
        if (bot.isImposter) {
            const target = nonImposters[Math.floor(Math.random() * nonImposters.length)];
            if (target) votes[bot.id] = target.id;
        } else {
            const target = allPlayers.filter(p => !p.isHost && p.id !== bot.id)[0];
            if (target) votes[bot.id] = target.id;
        }
    });
    return votes;
  };

  const dispatch = (action: GameAction) => {
    if (isHost) {
        const newState = processAction(action, state);
        setState(newState);
        broadcastState(newState);
    } else {
        sendActionToHost(action);
    }
  };

  const createGame = (name: string, avatarUrl?: string) => {
    const code = Math.random().toString(36).substring(2, 7).toUpperCase();
    const playerId = Math.random().toString(36).substr(2, 9);
    const creatorPlayer: Player = {
        id: playerId, name, avatarSeed: Math.random().toString(), avatarUrl,
        isHost: false, isImposter: false, isBot: false, score: 0, voteCount: 0, isReady: false
    };
    const newState = { ...INITIAL_STATE, gameCode: code, phase: GamePhase.LOBBY, players: [creatorPlayer] };
    const peer = new Peer(PEER_PREFIX + code);
    peer.on('open', (id) => {
        setIsHost(true);
        setMyPlayerId(playerId);
        setState(newState);
    });
    peer.on('connection', (conn) => {
        connectionsRef.current.push(conn);
        conn.on('data', (data: any) => {
            setState(current => {
                const updated = processAction(data as GameAction, current);
                connectionsRef.current.forEach(c => { if (c.open) c.send({ type: 'SYNC_STATE', state: updated }); });
                return updated;
            });
        });
        setState(current => { conn.send({ type: 'SYNC_STATE', state: current }); return current; });
    });
    peerRef.current = peer;
  };

  const connectToPeer = (code: string, playerId: string, playerData?: Partial<Player>) => {
    const peer = new Peer(); 
    peer.on('open', () => {
        const conn = peer.connect(PEER_PREFIX + code);
        conn.on('open', () => {
            hostConnRef.current = conn;
            setIsHost(false);
            setMyPlayerId(playerId);
            const player: Player = {
                id: playerId, name: playerData?.name || "Unknown", avatarSeed: playerData?.avatarSeed || Math.random().toString(),
                avatarUrl: playerData?.avatarUrl, isHost: false, isImposter: false, isBot: false, score: 0, voteCount: 0, isReady: false
            };
            conn.send({ type: 'JOIN_REQUEST', player });
        });
        conn.on('data', (data: any) => { if (data.type === 'SYNC_STATE') setState(data.state); });
    });
    peerRef.current = peer;
  };

  const joinGame = (code: string, name: string, avatarUrl?: string) => {
      const storedId = sessionStorage.getItem('imposter_playerId');
      const playerId = storedId || Math.random().toString(36).substr(2, 9);
      connectToPeer(code, playerId, { name, avatarUrl });
  };

  const reconnectGame = (code: string, playerId: string) => connectToPeer(code, playerId);
  const updateConfig = (config: Partial<GameConfig>) => dispatch({ type: 'UPDATE_CONFIG', config });
  const startGame = () => dispatch({ type: 'START_GAME' });
  const addBot = () => dispatch({ type: 'ADD_BOT' });
  const setTopic = (topic: string, category: string, image?: string, manualImposterIds?: string[]) => dispatch({ type: 'SET_TOPIC', topic, category, image, manualImposterIds });
  const finishRoleReveal = () => myPlayerId && dispatch({ type: 'ACK_ROUND_END', playerId: myPlayerId });
  const confirmStarter = () => dispatch({ type: 'CONFIRM_STARTER' });
  const startVoting = () => dispatch({ type: 'START_VOTING' });
  const confirmPassDevice = () => { };
  const startImposterGuess = () => dispatch({ type: 'START_IMPOSTER_GUESS' });
  const submitClue = (text: string) => dispatch({ type: 'SUBMIT_CLUE', text });
  const submitVote = (voterId: string, votedForId: string) => dispatch({ type: 'SUBMIT_VOTE', voterId, votedForId });
  const submitImposterGuess = (guess: string) => dispatch({ type: 'SUBMIT_GUESS', guess });
  const judgeImposterGuess = (isCorrect: boolean) => dispatch({ type: 'JUDGE_GUESS', isCorrect });
  const acknowledgeRoundEnd = (playerId: string) => dispatch({ type: 'ACK_ROUND_END', playerId });
  const resetGame = () => dispatch({ type: 'RESET_GAME' });

  const amIGameHost = !!state.currentHostId && state.currentHostId === myPlayerId;

  return (
    <GameContext.Provider value={{
      state, isHost, isNetworkHost: isHost, myPlayerId, amIGameHost, createGame, joinGame, reconnectGame, updateConfig, startGame, setTopic, submitClue, submitVote, submitImposterGuess, judgeImposterGuess, acknowledgeRoundEnd, resetGame, addBot, confirmPassDevice,
      finishRoleReveal, startVoting, confirmStarter, startImposterGuess
    }}>
      {children}
    </GameContext.Provider>
  );
};

export const useGame = () => {
  const context = useContext(GameContext);
  if (!context) throw new Error("useGame must be used within a GameProvider");
  return context;
};

