      <circle cx="50" cy="50" r="12" fill="url(#irisGradient)" className="animate-pulse" />
      <circle cx="50" cy="50" r="5" fill="#0f172a" />
      <circle cx="47" cy="47" r="2" fill="white" fillOpacity="0.8" />
    </svg>
  </div>
);

export const HomeScreen: React.FC = () => {
  const { createGame, joinGame, reconnectGame } = useGame();
  const [view, setView] = useState<'MAIN' | 'JOIN' | 'CREATE'>('MAIN');
  const [joinCode, setJoinCode] = useState('');
  const [playerName, setPlayerName] = useState('');
  const [avatarUrl, setAvatarUrl] = useState<string | undefined>(undefined);
  const [showCamera, setShowCamera] = useState(false);
  const [activeSession, setActiveSession] = useState<{ code: string, id: string } | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
      const params = new URLSearchParams(window.location.search);
      const urlCode = params.get('code');
      if (urlCode) {
          setJoinCode(urlCode.toUpperCase());
          setView('JOIN');
      }
      const storedCode = sessionStorage.getItem('imposter_gameCode');
      const storedId = sessionStorage.getItem('imposter_playerId');
      if (storedCode && storedId) setActiveSession({ code: storedCode, id: storedId });
  }, []);

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setAvatarUrl(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  const handleJoin = (e: React.FormEvent) => {
    e.preventDefault();
    if (joinCode && playerName && avatarUrl) joinGame(joinCode, playerName, avatarUrl);
  };

  const handleRejoin = () => activeSession && reconnectGame(activeSession.code, activeSession.id);
  const clearSession = () => {
      sessionStorage.removeItem('imposter_gameCode');
      sessionStorage.removeItem('imposter_playerId');
      setActiveSession(null);
  };

  const handleCreate = (e: React.FormEvent) => {
      e.preventDefault();
      if (playerName && avatarUrl) createGame(playerName, avatarUrl);
  }

  const renderPhotoUpload = () => (
    <div className="flex flex-col items-center gap-4 mb-4">
        {showCamera && (
            <Camera 
                onCapture={(img) => { setAvatarUrl(img); setShowCamera(false); }}
                onCancel={() => setShowCamera(false)}
            />
        )}
        <div className={`w-32 h-32 rounded-full bg-slate-800 border-4 flex items-center justify-center overflow-hidden relative transition-all ${!avatarUrl ? 'border-game-primary border-dashed animate-pulse' : 'border-game-accent shadow-lg scale-105'}`}>
            {avatarUrl ? <img src={avatarUrl} alt="Preview" className="w-full h-full object-cover" /> : <span className="text-4xl text-slate-500">👤</span>}
        </div>
        <div className="flex gap-2 w-full">
            <Button type="button" variant="secondary" className="flex-1 py-2 text-xs" onClick={() => fileInputRef.current?.click()}>Upload</Button>
            <Button type="button" variant="secondary" className="flex-1 py-2 text-xs" onClick={() => setShowCamera(true)}>Take Selfie</Button>
        </div>
        <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleImageUpload} />
    </div>
  );

  return (
    <div className="flex flex-col items-center justify-center min-h-screen p-6 text-center relative overflow-hidden">
      <div className="absolute top-0 left-0 w-full h-full overflow-hidden pointer-events-none opacity-20">
         <div className="absolute top-0 left-1/4 w-72 h-72 bg-purple-500 rounded-full blur-3xl animate-blob"></div>
         <div className="absolute top-0 right-1/4 w-72 h-72 bg-indigo-500 rounded-full blur-3xl animate-blob animation-delay-2000"></div>
      </div>
      <div className="z-10 w-full max-w-md space-y-8">
        <div className="animate-fade-in-down">
          <GameLogo />
          <h1 className="text-6xl font-black tracking-tighter text-transparent bg-clip-text bg-gradient-to-r from-indigo-200 via-purple-200 to-pink-200 mb-1 drop-shadow-lg">IMPOSTER</h1>
          <p className="text-indigo-200/60 text-sm uppercase tracking-[0.5em] font-medium">Digital Deduction</p>
        </div>
        {view === 'MAIN' && (
          <div className="flex flex-col gap-4 animate-fade-in-up">
            {activeSession && (
                <div className="bg-indigo-500/20 border border-indigo-500/50 p-4 rounded-xl flex items-center justify-between">
                    <div className="text-left"><p className="text-xs text-indigo-300 font-bold uppercase">Game Found</p><p className="text-white font-mono">{activeSession.code}</p></div>
                    <div className="flex gap-2"><Button onClick={handleRejoin} className="!py-2 !px-4 text-sm">REJOIN</Button><button onClick={clearSession} className="text-slate-500 px-2">✕</button></div>
                </div>
            )}
            <Button onClick={() => setView('CREATE')}>CREATE GAME</Button>
            <Button variant="secondary" onClick={() => setView('JOIN')}>JOIN GAME</Button>
          </div>
        )}
        {(view === 'JOIN' || view === 'CREATE') && (
          <form onSubmit={view === 'JOIN' ? handleJoin : handleCreate} className="flex flex-col gap-4 bg-slate-900/50 backdrop-blur-xl p-8 rounded-3xl shadow-2xl border border-white/10 animate-fade-in-up">
            <h2 className="text-xl font-bold mb-2 text-white">{view === 'JOIN' ? 'Join Lobby' : 'Create Game'}</h2>
            {renderPhotoUpload()}
            {view === 'JOIN' && <input type="text" placeholder="GAME CODE" className="w-full bg-black/30 border border-white/10 p-4 rounded-xl text-center text-xl font-mono uppercase text-white outline-none" value={joinCode} onChange={e => setJoinCode(e.target.value.toUpperCase())} />}
            <input type="text" placeholder="YOUR NAME" className="w-full bg-black/30 border border-white/10 p-4 rounded-xl text-center text-xl text-white outline-none" value={playerName} onChange={e => setPlayerName(e.target.value)} />
            <div className="flex gap-3 mt-4">
                <Button type="button" variant="secondary" onClick={() => setView('MAIN')} className="flex-1">Back</Button>
                <Button type="submit" className="flex-1" disabled={!playerName || !avatarUrl || (view === 'JOIN' && !joinCode)}>Enter</Button>
            </div>
          </form>
        )}
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { useGame } from '../context/GameContext';
import { Button } from '../components/Button';
import { Avatar } from '../components/Avatar';

export const VotingScreen: React.FC = () => {
  const { state, submitVote, myPlayerId, amIGameHost } = useGame();
  const { players, clues, votes } = state;
  const [selectedSuspect, setSelectedSuspect] = useState<string | null>(null);

  const myVote = myPlayerId ? votes[myPlayerId] : null;
  const humanPlayers = players.filter(p => !p.isBot && !p.isHost);
  const candidates = players.filter(p => !p.isHost);

  if (amIGameHost) {
      const voteCount = humanPlayers.filter(p => votes[p.id]).length;
      return (
          <div className="min-h-screen bg-game-bg flex flex-col items-center justify-center p-6 text-center">
              <h2 className="text-2xl font-black text-white mb-2 uppercase tracking-widest">Voting Progress</h2>
              <p className="text-slate-400 mb-8">Moderating: Waiting for players to decide...</p>
              <div className="w-full max-w-md bg-game-surface p-6 rounded-3xl border border-white/10 shadow-2xl space-y-4">
                  <div className="flex justify-between items-center mb-4">
                      <span className="text-xs font-bold text-slate-500 uppercase">Status</span>
                      <span className="text-xs font-bold text-game-primary uppercase">{voteCount} / {humanPlayers.length} Voted</span>
                  </div>
                  {humanPlayers.map(p => (
                      <div key={p.id} className="flex items-center justify-between bg-slate-900/50 p-3 rounded-xl border border-slate-700">
                          <div className="flex items-center gap-3">
                              <Avatar seed={p.avatarSeed} url={p.avatarUrl} size="sm" />
                              <span className="font-bold">{p.name}</span>
                          </div>
                          {votes[p.id] ? <span className="text-game-success text-xs font-black uppercase">✓ Voted</span> : <span className="text-slate-500 text-xs font-black uppercase animate-pulse">Thinking...</span>}
                      </div>
                  ))}
              </div>
          </div>
      );
  }

  if (myVote) {
      return (
          <div className="min-h-screen bg-game-bg flex flex-col items-center justify-center p-6 text-center">
              <div className="w-20 h-20 bg-game-success/20 rounded-full flex items-center justify-center mb-6 animate-bounce-in">
                  <span className="text-4xl">✓</span>
              </div>
              <h2 className="text-2xl font-black text-white mb-2 uppercase tracking-widest">Vote Cast!</h2>
              <p className="text-slate-400">Waiting for other players to finalize their decisions...</p>
          </div>
      );
  }

  return (
    <div className="min-h-screen bg-game-bg flex flex-col p-4">
      <div className="text-center mb-6">
          <h2 className="text-2xl font-black text-white mb-1 uppercase tracking-widest">CAST YOUR VOTE</h2>
          <p className="text-xs text-game-danger font-bold uppercase tracking-widest">Identify the Imposter</p>
      </div>
      <div className="flex-1 grid grid-cols-3 gap-4">
          {candidates.map(p => {
              const isSelected = selectedSuspect === p.id;
              const isSelf = p.id === myPlayerId;
              return (
                  <button key={p.id} onClick={() => !isSelf && setSelectedSuspect(p.id)} disabled={isSelf} className={`relative flex flex-col items-center p-3 rounded-xl transition-all border-2 ${isSelf ? 'opacity-30' : ''} ${isSelected ? 'bg-game-danger/20 border-game-danger scale-105' : 'border-slate-800'}`}>
                      <Avatar seed={p.avatarSeed} url={p.avatarUrl} size="md" />
                      <span className="mt-2 text-[10px] font-black uppercase truncate w-full text-center">{p.name}</span>
                      {isSelected && <div className="absolute -top-1 -right-1 bg-game-danger text-white rounded-full p-1 shadow-lg z-10"><span className="text-[8px]">✓</span></div>}
                  </button>
              );
          })}
      </div>
      <div className="mt-6 p-4 bg-slate-900/60 rounded-2xl">
          <Button onClick={() => selectedSuspect && myPlayerId && submitVote(myPlayerId, selectedSuspect)} disabled={!selectedSuspect} fullWidth variant="danger">CONFIRM VOTE</Button>
      </div>
    </div>
  );
};

import React, { useEffect, useState } from 'react';
