  const [stage, setStage] = useState(0); 

  useEffect(() => {
    const t1 = setTimeout(() => setStage(1), 3000); 
    const t2 = setTimeout(() => setStage(2), 6000); 
    return () => { clearTimeout(t1); clearTimeout(t2); };
  }, []);

  return (
    <div className="min-h-screen bg-game-bg flex flex-col items-center justify-center p-6 text-center">
      {stage === 0 && (
        <div className="w-full grid grid-cols-3 gap-8 animate-fade-in">
           {players.filter(p => !p.isHost).map(p => (
               <div key={p.id} className="relative flex flex-col items-center">
                   <Avatar seed={p.avatarSeed} url={p.avatarUrl} name={p.name} size="lg" />
                   {p.voteCount > 0 && <div className="absolute -top-2 -right-2 bg-white text-black font-black w-8 h-8 rounded-full flex items-center justify-center shadow-lg">{p.voteCount}</div>}
               </div>
           ))}
        </div>
      )}
      {stage === 1 && <h1 className="text-4xl font-black text-white tracking-widest animate-shake">The Imposter Was...</h1>}
      {stage === 2 && (
        <div className="w-full max-w-lg space-y-8 animate-bounce-in">
             <div className="py-8 border-y border-game-danger/50 bg-game-danger/10">
                 <h2 className="text-game-danger font-black text-3xl uppercase tracking-widest mb-6">IMPOSTERS REVEALED</h2>
                 <div className="flex justify-center gap-6">
                     {players.filter(p => p.isImposter).map(p => (
                         <div key={p.id} className="flex flex-col items-center">
                              <Avatar seed={p.avatarSeed} url={p.avatarUrl} size="xl" className="ring-4 ring-game-danger rounded-full" />
                              <span className="mt-4 font-bold text-white text-xl">{p.name}</span>
                         </div>
                     ))}
                 </div>
             </div>
             {amIGameHost ? (
                <div className="space-y-4">
                    <p className="text-indigo-400 font-bold uppercase text-xs">Moderator Controls</p>
                    <Button onClick={startImposterGuess} fullWidth>PROCEED TO IMPOSTER GUESS &rarr;</Button>
                </div>
             ) : (
                <p className="text-slate-500 animate-pulse uppercase text-sm font-bold">Waiting for Host to continue...</p>
             )}
        </div>
      )}
    </div>
  );
};

import React, { useState } from 'react';
import { useGame } from '../context/GameContext';
import { Button } from '../components/Button';
import { Avatar } from '../components/Avatar';
import { GamePhase } from '../types';

export const ImposterGuessScreen: React.FC = () => {
  const { state, submitImposterGuess, judgeImposterGuess, myPlayerId, amIGameHost } = useGame();
  const { phase, players, clues, imposterGuess, topic } = state;
  const [guessInput, setGuessInput] = useState('');

  const me = players.find(p => p.id === myPlayerId);
  const imposter = players.find(p => p.isImposter);
  const host = players.find(p => p.id === state.currentHostId);

  if (phase === GamePhase.IMPOSTER_GUESS) {
      if (me?.isImposter) {
          return (
              <div className="min-h-screen bg-game-bg flex flex-col p-6">
                  <h2 className="text-2xl font-black text-white text-center mb-6">WHAT WAS THE TOPIC?</h2>
                  <div className="flex-1 bg-slate-800 rounded-2xl p-4 overflow-y-auto mb-6">
                      <p className="text-xs text-slate-500 font-bold uppercase mb-4">Clue History</p>
                      {clues.map((c, i) => <p key={i} className="text-sm italic text-white mb-2">"{c.text}"</p>)}
                  </div>
                  <input type="text" className="w-full bg-slate-900 border-2 border-slate-700 p-4 rounded-xl text-center text-white outline-none mb-4" placeholder="Enter Guess..." value={guessInput} onChange={e => setGuessInput(e.target.value.toUpperCase())} />
                  <Button fullWidth onClick={() => submitImposterGuess(guessInput)} disabled={!guessInput}>SUBMIT GUESS</Button>
              </div>
          );
      }
      return (
          <div className="min-h-screen bg-game-bg flex flex-col items-center justify-center p-6 text-center">
              <Avatar seed={imposter?.avatarSeed || '0'} url={imposter?.avatarUrl} size="xl" className="animate-pulse mb-6" />
              <h2 className="text-2xl font-black text-white mb-2 uppercase tracking-widest">WAITING FOR {imposter?.name}</h2>
              <p className="text-slate-400">The Imposter is guessing the topic...</p>
          </div>
      );
  }

  if (phase === GamePhase.HOST_REVIEW && amIGameHost) {
      return (
          <div className="min-h-screen bg-game-bg flex flex-col items-center justify-center p-6 text-center">
              <h2 className="text-3xl font-black text-white mb-8">JUDGE THE GUESS</h2>
              <div className="bg-slate-800 p-6 rounded-2xl w-full max-w-md mb-8">
                  <p className="text-xs text-slate-500 uppercase font-bold">Secret Topic</p>
                  <p className="text-2xl font-black text-game-success uppercase mb-6">{topic}</p>
                  <p className="text-xs text-slate-500 uppercase font-bold">Imposter Guessed</p>
                  <p className="text-2xl font-black text-white uppercase italic">"{imposterGuess}"</p>
              </div>
              <div className="flex gap-4 w-full max-w-md">
                  <Button variant="danger" className="flex-1" onClick={() => judgeImposterGuess(false)}>WRONG</Button>
                  <Button variant="success" className="flex-1" onClick={() => judgeImposterGuess(true)}>CORRECT</Button>
              </div>
          </div>
      );
  }

  return (
      <div className="min-h-screen bg-game-bg flex flex-col items-center justify-center p-6 text-center">
          <Avatar seed={host?.avatarSeed || '0'} url={host?.avatarUrl} size="lg" className="animate-pulse mb-4" />
          <h2 className="text-2xl font-black text-white uppercase">Waiting for Final Verdict</h2>
          <p className="text-slate-400">The Host is reviewing the Imposter's guess...</p>
      </div>
  );
};

import React, { useState } from 'react';
import { GameProvider, useGame } from './context/GameContext';
import { GamePhase } from './types';
import { HomeScreen } from './screens/HomeScreen';
import { LobbyScreen } from './screens/LobbyScreen';
import { TopicSelectionScreen } from './screens/TopicSelectionScreen';
import { ClueScreen } from './screens/ClueScreen';
import { VotingScreen } from './screens/VotingScreen';
import { RevealScreen } from './screens/RevealScreen';
import { ImposterGuessScreen } from './screens/ImposterGuessScreen';
import { ScoreboardScreen } from './screens/ScoreboardScreen';
import { Avatar } from './components/Avatar';
import { Button } from './components/Button';

const RoleRevealScreen: React.FC = () => {
    const { state, finishRoleReveal, myPlayerId } = useGame();
    const { topic, category, topicImage } = state;
    const [isRevealed, setIsRevealed] = useState(false);
    const me = state.players.find(p => p.id === myPlayerId);

    if (!me) return <div className="text-white text-center mt-20">Reconnecting...</div>;

    if (me.isHost) {
        return (
            <div className="min-h-screen bg-game-bg flex flex-col items-center justify-center p-6 text-center">
                <div className="bg-game-surface p-8 rounded-2xl border border-indigo-500/50 shadow-2xl w-full max-w-md animate-fade-in">
                    <Avatar seed={me.avatarSeed} url={me.avatarUrl} size="lg" className="mb-6 ring-4 ring-indigo-500 rounded-full" />
                    <h2 className="text-3xl font-black text-indigo-400 mb-6">MODERATOR</h2>
                    <div className="bg-slate-900/50 p-4 rounded-xl border border-slate-700 w-full mb-6">
                        <p className="text-xs font-bold text-slate-500 uppercase mb-1">Current Topic</p>
                        <p className="text-xl font-bold text-white uppercase">{topic}</p>
                        <p className="text-xs text-slate-400">Category: {category}</p>
                    </div>
                    <ul className="text-left text-slate-300 text-sm space-y-3 mb-8">
                        <li className="flex gap-2"><span>1.</span><span>You guide the game, you don't play.</span></li>
                        <li className="flex gap-2"><span>2.</span><span>Observe clues, you'll judge at the end.</span></li>
                    </ul>
                    {me.isReady ? (
                        <p className="text-game-success font-bold animate-pulse">Waiting for players to check roles...</p>
                    ) : (
                        <Button onClick={finishRoleReveal} fullWidth>I AM READY TO MODERATE</Button>
                    )}
                </div>
            </div>
        );
    }

    if (me.isReady) {
        return (
            <div className="min-h-screen bg-game-bg flex flex-col items-center justify-center p-6 text-center">
                <h2 className="text-xl font-bold text-white mb-4">Ready! Waiting for others...</h2>
                <div className="flex gap-4 justify-center">
                    {state.players.filter(p => !p.isBot && !p.isHost).map(p => (
                        <div key={p.id} className="opacity-50"><Avatar seed={p.avatarSeed} url={p.avatarUrl} size="sm" /></div>
                    ))}
                </div>
            </div>
        );
    }

    return (
        <div className="min-h-screen bg-game-bg flex flex-col items-center justify-center p-6 text-center">
            <h2 className="text-xl font-bold text-white mb-4">Check Your Role</h2>
            <div className="bg-game-surface p-8 rounded-2xl border border-slate-700 w-full max-w-md relative min-h-[400px] flex flex-col items-center justify-center">
                {!isRevealed ? (
                    <div className="space-y-6 animate-fade-in">
                        <Avatar seed={me.avatarSeed} url={me.avatarUrl} size="lg" />
                        <p className="text-slate-300">A topic has been chosen.<br/>Reveal your destiny.</p>
                        <Button onClick={() => setIsRevealed(true)} fullWidth>REVEAL ROLE</Button>
                    </div>
                ) : (
                    <div className="flex flex-col items-center animate-flip-in">
                         {me.isImposter ? (
                            <>
                                <span className="text-6xl mb-4">🤫</span>
                                <h2 className="text-4xl font-black text-game-danger mb-4">IMPOSTER</h2>
                                <p className="text-slate-400 mb-6">Blend in. You only know the category:</p>
                                <p className="text-2xl font-bold text-yellow-400 uppercase">{category}</p>
                            </>
                         ) : (
                            <>
                                <span className="text-6xl mb-4">😇</span>
                                <h2 className="text-4xl font-black text-game-success mb-4">INNOCENT</h2>
                                <p className="text-slate-400 mb-6">Prove you know the topic:</p>
                                <p className="text-2xl font-bold text-white uppercase">{topic}</p>
                            </>
                         )}
                         <Button onClick={finishRoleReveal} className="mt-8" fullWidth variant={me.isImposter ? 'danger' : 'success'}>I'M READY</Button>
                    </div>
                )}
            </div>
        </div>
    )
}

const GameRouter: React.FC = () => {
  const { state } = useGame();
  switch (state.phase) {
    case GamePhase.HOME: return <HomeScreen />;
    case GamePhase.LOBBY: return <LobbyScreen />;
    case GamePhase.TOPIC_SELECTION: return <TopicSelectionScreen />;
    case GamePhase.ROLE_REVEAL: return <RoleRevealScreen />;
    case GamePhase.ROUND_STARTER:
    case GamePhase.DISCUSSION:
    case GamePhase.CLUES:
    case GamePhase.PASS_DEVICE: return <ClueScreen />;
    case GamePhase.VOTING: return <VotingScreen />;
    case GamePhase.REVEAL: return <RevealScreen />;
    case GamePhase.IMPOSTER_GUESS:
    case GamePhase.HOST_REVIEW: return <ImposterGuessScreen />;
    case GamePhase.SCOREBOARD:
    case GamePhase.WINNER:
    case GamePhase.SETUP: return <ScoreboardScreen />;
    default: return <div className="text-white text-center mt-10">Unknown Game Phase</div>;
  }
};

const App: React.FC = () => (
  <GameProvider>
    <GameRouter />
  </GameProvider>
);
export default App;

export enum GamePhase {
  HOME = 'HOME',
  LOBBY = 'LOBBY',
  SETUP = 'SETUP', 
  TOPIC_SELECTION = 'TOPIC_SELECTION',
  ROLE_REVEAL = 'ROLE_REVEAL', 
  ROUND_STARTER = 'ROUND_STARTER', 
  DISCUSSION = 'DISCUSSION', 
  PASS_DEVICE = 'PASS_DEVICE', 
  CLUES = 'CLUES',
  VOTING = 'VOTING',
  REVEAL = 'REVEAL',
  IMPOSTER_GUESS = 'IMPOSTER_GUESS',
  HOST_REVIEW = 'HOST_REVIEW',
  SCOREBOARD = 'SCOREBOARD',
  WINNER = 'WINNER'
}

export enum PlayerRole {
  HOST = 'HOST',
  PLAYER = 'PLAYER',
  IMPOSTER = 'IMPOSTER'
}

export interface Player {
  id: string;
  name: string;
  avatarSeed: string; 
  avatarUrl?: string; 
  isHost: boolean;
  isImposter: boolean;
  isBot: boolean; 
  score: number;
  voteCount: number;
  isReady: boolean; 
}

export interface Clue {
  playerId: string;
  text: string;
  timestamp: number;
}

export interface GameConfig {
  mode: 'IN_PERSON' | 'PHONE';
  imposterCount: number;
  cycles: number; // Number of times each person hosts
}

export interface GameState {
  gameCode: string;
  phase: GamePhase;
  players: Player[];
  config: GameConfig;

  currentTurnIndex: number;
  clueRound: number; 

  currentHostId: string | null; 
  hostIndex: number; 
  pastHostIds: string[]; 
  currentCycle: number;

  topic: string;
  category: string; 
  topicImage?: string; 

  clues: Clue[];
  votes: Record<string, string>; 
  imposterGuess: string | null;
  imposterGuessCorrect: boolean | null;
  winningPlayerId: string | null;

  nextPlayerTurnId: string | null; 
}

export interface GameContextType {
  state: GameState;
  isHost: boolean; 
  isNetworkHost: boolean; 
  myPlayerId: string | null;
  amIGameHost: boolean; 
  createGame: (name: string, avatarUrl?: string) => void;
  joinGame: (code: string, name: string, avatarUrl?: string) => void;
  reconnectGame: (code: string, playerId: string) => void; 
  updateConfig: (config: Partial<GameConfig>) => void;
  startGame: () => void;
  setTopic: (topic: string, category: string, image?: string, manualImposterIds?: string[]) => void;
  submitClue: (text: string) => void;
  submitVote: (voterId: string, votedForId: string) => void;
  submitImposterGuess: (guess: string) => void;
  judgeImposterGuess: (isCorrect: boolean) => void;
  acknowledgeRoundEnd: (playerId: string) => void;
  resetGame: () => void;
  addBot: () => void;
  confirmPassDevice: () => void;
  finishRoleReveal: () => void;
  startVoting: () => void;
  confirmStarter: () => void;
  startImposterGuess: () => void;
}

import React, { createContext, useContext, useState, useEffect, useRef } from 'react';
import { GamePhase, GameState, Player, GameConfig, GameContextType } from '../types';
import Peer, { DataConnection } from 'peerjs';

type GameAction = 
  | { type: 'SYNC_STATE'; state: GameState }
  | { type: 'JOIN_REQUEST'; player: Player }
  | { type: 'UPDATE_CONFIG'; config: Partial<GameConfig> }
  | { type: 'START_GAME' }
  | { type: 'SET_TOPIC'; topic: string; category: string; image?: string; manualImposterIds?: string[] }
  | { type: 'SUBMIT_CLUE'; text: string }
  | { type: 'SUBMIT_VOTE'; voterId: string; votedForId: string }
  | { type: 'START_VOTING' }
  | { type: 'CONFIRM_STARTER' }
  | { type: 'START_IMPOSTER_GUESS' }
  | { type: 'SUBMIT_GUESS'; guess: string }
  | { type: 'JUDGE_GUESS'; isCorrect: boolean }
  | { type: 'ACK_ROUND_END'; playerId: string }
  | { type: 'RESET_GAME' }
  | { type: 'ADD_BOT' };

const GameContext = createContext<GameContextType | undefined>(undefined);

const INITIAL_STATE: GameState = {
  gameCode: '',
  phase: GamePhase.HOME,
  players: [],
  config: { mode: 'IN_PERSON', imposterCount: 1, cycles: 1 },
  currentTurnIndex: 0,
  clueRound: 1,
  currentHostId: null,
  hostIndex: 0,
  pastHostIds: [],
  currentCycle: 1,
  topic: '',
  category: '',
  clues: [],
  votes: {},
  imposterGuess: null,
  imposterGuessCorrect: null,
  winningPlayerId: null,
  nextPlayerTurnId: null,
};

const PEER_PREFIX = 'imposter-game-v1-';

export const GameProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [state, setState] = useState<GameState>(INITIAL_STATE);
  const [isHost, setIsHost] = useState(false);
  const [myPlayerId, setMyPlayerId] = useState<string | null>(null);

  const peerRef = useRef<Peer | null>(null);
  const connectionsRef = useRef<DataConnection[]>([]);
  const hostConnRef = useRef<DataConnection | null>(null);

  useEffect(() => {
    const storedId = sessionStorage.getItem('imposter_playerId');
    if (storedId) setMyPlayerId(storedId);
  }, []);

  useEffect(() => {
    if (myPlayerId) sessionStorage.setItem('imposter_playerId', myPlayerId);
    if (state.gameCode) sessionStorage.setItem('imposter_gameCode', state.gameCode);
  }, [myPlayerId, state.gameCode]);

  // Bot Host logic for progression
  useEffect(() => {
    if (isHost) {
      const currentHost = state.players.find(p => p.id === state.currentHostId);
      if (currentHost?.isBot) {
        if (state.phase === GamePhase.TOPIC_SELECTION) {
          const timer = setTimeout(() => setTopic('PIZZA', 'Food/Drink'), 2000);
          return () => clearTimeout(timer);
        }
        if (state.phase === GamePhase.ROUND_STARTER) {
          const timer = setTimeout(() => confirmStarter(), 2000);
          return () => clearTimeout(timer);
        }
        if (state.phase === GamePhase.DISCUSSION) {
          const timer = setTimeout(() => startVoting(), 5000); // Give some time for "discussion"
          return () => clearTimeout(timer);
        }
        if (state.phase === GamePhase.REVEAL) {
          const timer = setTimeout(() => startImposterGuess(), 4000);
          return () => clearTimeout(timer);
        }
        if (state.phase === GamePhase.HOST_REVIEW && state.imposterGuess) {
          const timer = setTimeout(() => judgeImposterGuess(Math.random() > 0.5), 3000);
          return () => clearTimeout(timer);
        }
      }
    }
  }, [state.phase, state.currentHostId, isHost, state.imposterGuess]);

  const broadcastState = (newState: GameState) => {
    connectionsRef.current.forEach(conn => {
      if (conn.open) {
        conn.send({ type: 'SYNC_STATE', state: newState });
      }
    });
  };

  const sendActionToHost = (action: GameAction) => {
    if (hostConnRef.current && hostConnRef.current.open) {
      hostConnRef.current.send(action);
    }
  };

  const processAction = (action: GameAction, currentState: GameState): GameState => {
    switch (action.type) {
        case 'JOIN_REQUEST':
            const existingIdx = currentState.players.findIndex(p => p.id === action.player.id);
            if (existingIdx !== -1) {
                const updatedPlayers = [...currentState.players];
                updatedPlayers[existingIdx] = {
                    ...updatedPlayers[existingIdx],
                    name: action.player.name,
                    avatarUrl: action.player.avatarUrl || updatedPlayers[existingIdx].avatarUrl
                };
                return { ...currentState, players: updatedPlayers };
            }
            if (currentState.players.some(p => p.name === action.player.name)) return currentState;
            return { ...currentState, players: [...currentState.players, action.player] };

        case 'UPDATE_CONFIG':
            return { ...currentState, config: { ...currentState.config, ...action.config } };

        case 'ADD_BOT': {
             const names = ["Robo", "Spark", "Gizmo", "Chip", "Bolt", "Data", "Circuit", "Pixel"];
             const botPlayer: Player = {
                id: "BOT-" + Math.random().toString(36).substr(2, 9),
                name: names[Math.floor(Math.random() * names.length)],
                avatarSeed: Math.random().toString(),
                isHost: false,
                isImposter: false,
                isBot: true,
                score: 0,
                voteCount: 0,
                isReady: true
             };
             return { ...currentState, players: [...currentState.players, botPlayer] };
        }

        case 'START_GAME': {
            if (currentState.players.length < 3) return currentState;
            const randHostIdx = Math.floor(Math.random() * currentState.players.length);
            const hostId = currentState.players[randHostIdx].id;
            const newPlayers = currentState.players.map(p => ({
                ...p,
                isHost: p.id === hostId,
                isImposter: false,
                voteCount: 0,
                isReady: false,
                score: 0
            }));
            return {
                ...currentState,
                players: newPlayers,
                currentHostId: hostId,
                pastHostIds: [hostId],
                currentCycle: 1,
                phase: GamePhase.TOPIC_SELECTION,
                clues: [],
                votes: {},
                topic: '',
            };
        }

        case 'SET_TOPIC': {
            const hostId = currentState.currentHostId;
            const manualImposterIds = action.manualImposterIds || [];
            const shuffled = [...currentState.players];
            const imposterIndices = new Set<number>();

            if (manualImposterIds.length > 0) {
                 manualImposterIds.forEach(id => {
                     const idx = shuffled.findIndex(p => p.id === id);
                     if (idx !== -1) imposterIndices.add(idx);
                 });
            } else {
                 while (imposterIndices.size < currentState.config.imposterCount) {
                    const idx = Math.floor(Math.random() * shuffled.length);
                    if (shuffled[idx].id !== hostId && !imposterIndices.has(idx)) {
                        imposterIndices.add(idx);
                    }
                }
            }

            const newPlayers = shuffled.map((p, idx) => ({
                ...p,
                isHost: p.id === hostId,
                isImposter: imposterIndices.has(idx),
                isReady: false
            }));

            const eligibleStarterIndices = newPlayers
                .map((p, idx) => p.isHost ? -1 : idx)
                .filter(idx => idx !== -1);
            const randomStarterIndex = eligibleStarterIndices[Math.floor(Math.random() * eligibleStarterIndices.length)];

            return {
                ...currentState,
                players: newPlayers,
                currentTurnIndex: randomStarterIndex,
                topic: action.topic,
                category: action.category,
                topicImage: action.image,
                phase: GamePhase.ROLE_REVEAL
            };
        }

        case 'CONFIRM_STARTER':
            return { ...currentState, phase: GamePhase.DISCUSSION };

        case 'START_VOTING': {
             return { ...currentState, phase: GamePhase.VOTING };
        }

        case 'SUBMIT_CLUE': {
            const currentPlayer = currentState.players[currentState.currentTurnIndex];
            const newClues = [...currentState.clues, { playerId: currentPlayer.id, text: action.text, timestamp: Date.now() }];
            const activePlayerCount = currentState.players.length - 1;
            const totalCluesNeeded = activePlayerCount * 2;

            let nIdx = (currentState.currentTurnIndex + 1) % currentState.players.length;
            let nRound = currentState.clueRound;
            let nClues = [...newClues];

            while(true) {
                const p = currentState.players[nIdx];
                if (nClues.length >= totalCluesNeeded) break;
                if (p.isHost) {
                    nIdx = (nIdx + 1) % currentState.players.length;
                    continue;
                }
                if (p.isBot) {
                    nClues.push({ playerId: p.id, text: `...`, timestamp: Date.now() });
                    nIdx = (nIdx + 1) % currentState.players.length;
                    continue;
                }
                break;
            }

            if (nClues.length >= totalCluesNeeded) {
                 return { ...currentState, clues: nClues, phase: GamePhase.VOTING };
            }

            if (nClues.length >= activePlayerCount) nRound = 2;

            return {
                ...currentState,
                clues: nClues,
                currentTurnIndex: nIdx,
                clueRound: nRound,
                phase: GamePhase.CLUES
            };
        }

        case 'SUBMIT_VOTE': {
            const newVotes = { ...currentState.votes, [action.voterId]: action.votedForId };
            const votingHumans = currentState.players.filter(p => !p.isBot && !p.isHost);
            const humansWhoVoted = votingHumans.filter(h => newVotes[h.id]);

            if (humansWhoVoted.length === votingHumans.length) {
                // Bots vote automatically when humans finish
                const finalVotes = simulateBotVotes(currentState.players, currentState.config.imposterCount, newVotes);
                const updatedPlayers = currentState.players.map(p => {
                    const votesReceived = Object.values(finalVotes).filter(id => id === p.id).length;
                    return { ...p, voteCount: votesReceived };
                });
                return { ...currentState, players: updatedPlayers, votes: finalVotes, phase: GamePhase.REVEAL };
            }
            return { ...currentState, votes: newVotes };
        }

        case 'START_IMPOSTER_GUESS':
             return { ...currentState, phase: GamePhase.IMPOSTER_GUESS };

        case 'SUBMIT_GUESS':
             return { ...currentState, imposterGuess: action.guess, phase: GamePhase.HOST_REVIEW };

        case 'JUDGE_GUESS': {
            let maxVotes = 0;
            currentState.players.forEach(p => { if(p.voteCount > maxVotes) maxVotes = p.voteCount; });
            const accusedPlayers = currentState.players.filter(p => p.voteCount === maxVotes);

            const newPlayers = currentState.players.map(p => {
                let points = p.score;
                if (p.isHost) return p;
                if (p.isImposter) {
                    const isCaught = accusedPlayers.some(accused => accused.id === p.id);
                    if (!isCaught) points += 100;
                    if (action.isCorrect) points += 200;
                } else {
                    const votedForId = currentState.votes[p.id];
                    const votedForPerson = currentState.players.find(pl => pl.id === votedForId);
                    if (votedForPerson && votedForPerson.isImposter) points += 100;
                }
                return { ...p, score: points, isReady: false };
            });
            return { ...currentState, players: newPlayers, imposterGuessCorrect: action.isCorrect, phase: GamePhase.SCOREBOARD };
        }

        case 'ACK_ROUND_END': {
             const updatedPlayers = currentState.players.map(p => (p.id === action.playerId || p.isBot) ? { ...p, isReady: !p.isReady } : p);
             const readyCount = updatedPlayers.filter(p => p.isReady).length;

             if (readyCount === updatedPlayers.length) {
                if (currentState.phase === GamePhase.ROLE_REVEAL) {
                    return {
                        ...currentState,
                        players: updatedPlayers.map(p => ({ ...p, isReady: false })), 
                        phase: currentState.config.mode === 'IN_PERSON' ? GamePhase.ROUND_STARTER : GamePhase.CLUES
                    };
                }

                // Scoreboard -> Next Round Topic Selection
                let nextPastHosts = [...currentState.pastHostIds];
                let nextCycle = currentState.currentCycle;

                // Cycle logic: pool of available hosts who haven't hosted in current cycle
                let availableHosts = currentState.players.filter(p => !nextPastHosts.includes(p.id));

                if (availableHosts.length === 0) {
                    if (nextCycle < currentState.config.cycles) {
                        nextCycle += 1;
                        nextPastHosts = [];
                        availableHosts = [...currentState.players];
                    } else {
                        // Game ends
                        const sorted = [...updatedPlayers].sort((a,b) => b.score - a.score);
                        return { ...currentState, players: updatedPlayers, winningPlayerId: sorted[0].id, phase: GamePhase.WINNER };
                    }
                }

                const nextHost = availableHosts[Math.floor(Math.random() * availableHosts.length)];
                return {
                    ...currentState,
                    players: updatedPlayers.map(p => ({ ...p, isHost: p.id === nextHost.id, isImposter: false, isReady: false, voteCount: 0 })),
                    currentHostId: nextHost.id,
                    pastHostIds: [...nextPastHosts, nextHost.id],
                    currentCycle: nextCycle,
                    phase: GamePhase.TOPIC_SELECTION,
                    clues: [],
                    votes: {},
                    topic: '',
                    imposterGuess: null,
                    imposterGuessCorrect: null,
                };
             }
             return { ...currentState, players: updatedPlayers };
        }

        case 'RESET_GAME':
             return { ...INITIAL_STATE, gameCode: currentState.gameCode, phase: GamePhase.LOBBY, players: [] };

        default:
            return currentState;
    }
  };

  const simulateBotVotes = (allPlayers: Player[], imposterCount: number, existingVotes: Record<string,string>): Record<string, string> => {
    const votes: Record<string, string> = { ...existingVotes };
    const candidates = allPlayers.filter(p => !p.isHost);
    allPlayers.filter(p => p.isBot && !p.isHost).forEach(bot => {
        const otherCandidates = candidates.filter(c => c.id !== bot.id);
        const target = otherCandidates[Math.floor(Math.random() * otherCandidates.length)];
        if (target) votes[bot.id] = target.id;
    });
    return votes;
  };

  const dispatch = (action: GameAction) => {
    if (isHost) {
        const newState = processAction(action, state);
        setState(newState);
        broadcastState(newState);
    } else {
        sendActionToHost(action);
    }
  };

  const createGame = (name: string, avatarUrl?: string) => {
    const code = Math.random().toString(36).substring(2, 7).toUpperCase();
    const playerId = Math.random().toString(36).substr(2, 9);
    const creatorPlayer: Player = {
        id: playerId, name, avatarSeed: Math.random().toString(), avatarUrl,
        isHost: false, isImposter: false, isBot: false, score: 0, voteCount: 0, isReady: false
    };
    const newState = { ...INITIAL_STATE, gameCode: code, phase: GamePhase.LOBBY, players: [creatorPlayer] };
    const peer = new Peer(PEER_PREFIX + code);
    peer.on('open', (id) => {
        setIsHost(true);
        setMyPlayerId(playerId);
        setState(newState);
    });
    peer.on('connection', (conn) => {
        connectionsRef.current.push(conn);
        conn.on('data', (data: any) => {
            setState(current => {
                const updated = processAction(data as GameAction, current);
                connectionsRef.current.forEach(c => { if (c.open) c.send({ type: 'SYNC_STATE', state: updated }); });
                return updated;
            });
        });
        setState(current => { conn.send({ type: 'SYNC_STATE', state: current }); return current; });
    });
    peerRef.current = peer;
  };

  const connectToPeer = (code: string, playerId: string, playerData?: Partial<Player>) => {
    const peer = new Peer(); 
    peer.on('open', () => {
        const conn = peer.connect(PEER_PREFIX + code);
        conn.on('open', () => {
            hostConnRef.current = conn;
            setIsHost(false);
            setMyPlayerId(playerId);
            const player: Player = {
                id: playerId, name: playerData?.name || "Player", avatarSeed: playerData?.avatarSeed || Math.random().toString(),
                avatarUrl: playerData?.avatarUrl, isHost: false, isImposter: false, isBot: false, score: 0, voteCount: 0, isReady: false
            };
            conn.send({ type: 'JOIN_REQUEST', player });
        });
        conn.on('data', (data: any) => { if (data.type === 'SYNC_STATE') setState(data.state); });
    });
    peerRef.current = peer;
  };

  const joinGame = (code: string, name: string, avatarUrl?: string) => {
      const storedId = sessionStorage.getItem('imposter_playerId');
      const playerId = storedId || Math.random().toString(36).substr(2, 9);
      connectToPeer(code, playerId, { name, avatarUrl });
  };

  const reconnectGame = (code: string, playerId: string) => connectToPeer(code, playerId);
  const updateConfig = (config: Partial<GameConfig>) => dispatch({ type: 'UPDATE_CONFIG', config });
  const startGame = () => dispatch({ type: 'START_GAME' });
  const addBot = () => dispatch({ type: 'ADD_BOT' });
  const setTopic = (topic: string, category: string, image?: string, manualImposterIds?: string[]) => dispatch({ type: 'SET_TOPIC', topic, category, image, manualImposterIds });
  const finishRoleReveal = () => myPlayerId && dispatch({ type: 'ACK_ROUND_END', playerId: myPlayerId });
  const confirmStarter = () => dispatch({ type: 'CONFIRM_STARTER' });
  const startVoting = () => dispatch({ type: 'START_VOTING' });
  const confirmPassDevice = () => { };
  const startImposterGuess = () => dispatch({ type: 'START_IMPOSTER_GUESS' });
  const submitClue = (text: string) => dispatch({ type: 'SUBMIT_CLUE', text });
  const submitVote = (voterId: string, votedForId: string) => dispatch({ type: 'SUBMIT_VOTE', voterId, votedForId });
  const submitImposterGuess = (guess: string) => dispatch({ type: 'SUBMIT_GUESS', guess });
  const judgeImposterGuess = (isCorrect: boolean) => dispatch({ type: 'JUDGE_GUESS', isCorrect });
  const acknowledgeRoundEnd = (playerId: string) => dispatch({ type: 'ACK_ROUND_END', playerId });
  const resetGame = () => dispatch({ type: 'RESET_GAME' });

  const amIGameHost = !!state.currentHostId && state.currentHostId === myPlayerId;

  return (
    <GameContext.Provider value={{
      state, isHost, isNetworkHost: isHost, myPlayerId, amIGameHost, createGame, joinGame, reconnectGame, updateConfig, startGame, setTopic, submitClue, submitVote, submitImposterGuess, judgeImposterGuess, acknowledgeRoundEnd, resetGame, addBot, confirmPassDevice,
      finishRoleReveal, startVoting, confirmStarter, startImposterGuess
    }}>
      {children}
    </GameContext.Provider>
  );
};

export const useGame = () => {
  const context = useContext(GameContext);
  if (!context) throw new Error("useGame must be used within a GameProvider");
  return context;
};

import React from 'react';
import { useGame } from '../context/GameContext';
import { Button } from '../components/Button';
import { Avatar } from '../components/Avatar';
import { GameConfig } from '../types';

export const LobbyScreen: React.FC = () => {
  const { state, updateConfig, startGame, addBot, isNetworkHost } = useGame();
  const { players, config, gameCode } = state;

  const handleConfigChange = (updates: Partial<GameConfig>) => {
    if (!isNetworkHost) return;
    updateConfig(updates);
  };

  const handleShare = async () => {
      const currentUrl = new URL(window.location.href);
      currentUrl.searchParams.set('code', gameCode);
      const shareUrl = currentUrl.toString();
      try {
          if (navigator.share) {
              await navigator.share({ title: 'Join Imposter', url: shareUrl });
          } else {
              await navigator.clipboard.writeText(shareUrl);
              alert(`Link copied!`);
          }
      } catch (err) {
          await navigator.clipboard.writeText(shareUrl);
          alert(`Link copied!`);
      }
  };

  return (
    <div className="min-h-screen flex flex-col p-6">
      <div className="flex justify-between items-center mb-6 bg-slate-900/40 p-4 rounded-2xl backdrop-blur-md border border-white/10">
        <div>
          <span className="text-slate-400 text-xs font-bold tracking-widest uppercase">Code</span>
          <h2 className="text-4xl font-mono font-black text-white">{gameCode}</h2>
        </div>
        <Button variant="secondary" className="!py-2 !px-4 text-xs font-bold" onClick={handleShare}>SHARE</Button>
      </div>

      <div className="flex-1 overflow-y-auto mb-6">
        <div className="flex justify-between items-end mb-4">
             <h3 className="text-indigo-200 font-bold uppercase text-sm">Players ({players.length})</h3>
             {isNetworkHost && (
                 <button onClick={addBot} className="text-xs bg-indigo-500/20 text-indigo-300 px-3 py-1 rounded-full border border-indigo-500/30">+ Bot</button>
             )}
        </div>
        <div className="grid grid-cols-4 gap-4">
          {players.map(p => <Avatar key={p.id} seed={p.avatarSeed} url={p.avatarUrl} name={p.name} size="sm" />)}
        </div>
      </div>

      <div className="bg-slate-900/60 p-6 rounded-3xl border border-white/10 space-y-6 shadow-2xl">
        <div className="space-y-3">
            <label className="text-xs font-bold text-slate-400 uppercase tracking-widest">Game Style</label>
            <div className={`flex gap-3 ${!isNetworkHost ? 'opacity-60 pointer-events-none' : ''}`}>
                {(['IN_PERSON', 'PHONE'] as const).map(mode => (
                    <button 
                        key={mode}
                        onClick={() => handleConfigChange({ mode })}
                        className={`flex-1 p-3 rounded-xl font-bold border ${config.mode === mode ? 'border-indigo-500 bg-indigo-500/20 text-indigo-300' : 'border-slate-700 bg-slate-800/50 text-slate-500'}`}
                    >
                        {mode === 'IN_PERSON' ? 'Party' : 'Remote'}
                    </button>
                ))}
            </div>
        </div>

        <div className="space-y-3">
            <label className="text-xs font-bold text-slate-400 uppercase tracking-widest">Cycles (Hosting Turns)</label>
            <div className={`flex gap-3 ${!isNetworkHost ? 'opacity-60 pointer-events-none' : ''}`}>
                {[1, 2, 3].map(num => (
                    <button 
                        key={num}
                        onClick={() => handleConfigChange({ cycles: num })}
                        className={`flex-1 p-3 rounded-xl font-bold border ${config.cycles === num ? 'border-game-accent bg-game-accent/20 text-game-accent' : 'border-slate-700 bg-slate-800/50 text-slate-500'}`}
                    >
                        {num}
                    </button>
                ))}
            </div>
        </div>

        {isNetworkHost ? (
            <Button fullWidth disabled={players.length < 3} onClick={startGame}>
                {players.length < 3 ? "NEED 3+ PLAYERS" : "START GAME"}
            </Button>
        ) : (
            <div className="text-center p-4 text-slate-400 font-bold bg-slate-800/50 rounded-xl border border-slate-700 animate-pulse">Waiting for Host...</div>
        )}
      </div>
    </div>
  );
};

