export const ScoreboardScreen: React.FC = () => {
  const { state, acknowledgeRoundEnd, resetGame, myPlayerId } = useGame();
  const { players, winningPlayerId, phase, currentCycle } = state;

  const sortedPlayers = [...players].sort((a, b) => b.score - a.score);
  const me = players.find(p => p.id === myPlayerId);

  if (phase === 'WINNER') {
      const winner = players.find(p => p.id === winningPlayerId);
      return (
        <div className="min-h-screen bg-game-bg flex flex-col items-center justify-center p-6 text-center">
             <h1 className="text-5xl font-black text-yellow-400 mb-6">CHAMPION!</h1>
             <Avatar seed={winner?.avatarSeed || '0'} url={winner?.avatarUrl} size="xl" className="mx-auto ring-4 ring-yellow-400 mb-8" />
             <h2 className="text-3xl font-bold text-white mb-8">{winner?.name}</h2>
             <div className="flex gap-4">
                 <Button onClick={resetGame}>PLAY AGAIN</Button>
                 <Button variant="secondary" onClick={() => window.location.reload()}>EXIT</Button>
             </div>
        </div>
      );
  }

  return (
    <div className="min-h-screen bg-game-bg flex flex-col p-6">
      <div className="text-center mb-6">
          <h2 className="text-3xl font-black text-white uppercase tracking-widest">Scoreboard</h2>
          <p className="text-indigo-400 font-bold text-xs">Cycle {currentCycle} of {state.config.cycles}</p>
      </div>

      <div className="flex-1 space-y-3 overflow-y-auto mb-6">
          {sortedPlayers.map((p, idx) => (
              <div key={p.id} className={`flex items-center justify-between bg-slate-800 p-3 rounded-xl border ${p.isReady ? 'border-game-success shadow-lg' : 'border-slate-700 opacity-80'}`}>
                  <div className="flex items-center gap-3">
                      <span className="font-mono text-slate-500 font-bold">#{idx + 1}</span>
                      <Avatar seed={p.avatarSeed} url={p.avatarUrl} size="sm" />
                      <div className="flex flex-col">
                          <span className="font-bold text-white">{p.name}</span>
                          {p.isReady ? (
                              <span className="text-[10px] text-game-success font-black uppercase">READY</span>
                          ) : (
                              <span className="text-[10px] text-slate-500 font-black uppercase">WAITING...</span>
                          )}
                      </div>
                  </div>
                  <span className="font-mono font-black text-xl text-game-primary">{p.score}</span>
              </div>
          ))}
      </div>

      <div className="bg-slate-900/80 p-6 rounded-3xl border border-white/10 shadow-2xl">
          <Button 
            fullWidth 
            variant={me?.isReady ? 'success' : 'primary'}
            onClick={() => myPlayerId && acknowledgeRoundEnd(myPlayerId)}
          >
              {me?.isReady ? "✓ READY" : "I AM READY"}
          </Button>
          <div className="mt-4 flex justify-center gap-2">
               {players.map(p => (
                   <div key={p.id} className={`w-3 h-3 rounded-full transition-all ${p.isReady ? 'bg-game-success scale-110 shadow-[0_0_10px_#22c55e]' : 'bg-slate-700'}`}></div>
               ))}
          </div>
      </div>
    </div>
  );
};

import React, { createContext, useContext, useState, useEffect, useRef } from 'react';
import { GamePhase, GameState, Player, GameConfig, GameContextType } from '../types';
import Peer, { DataConnection } from 'peerjs';

type GameAction = 
  | { type: 'SYNC_STATE'; state: GameState }
  | { type: 'JOIN_REQUEST'; player: Player }
  | { type: 'UPDATE_CONFIG'; config: Partial<GameConfig> }
  | { type: 'START_GAME' }
  | { type: 'SET_TOPIC'; topic: string; category: string; image?: string; manualImposterIds?: string[] }
  | { type: 'SUBMIT_CLUE'; text: string }
  | { type: 'SUBMIT_VOTE'; voterId: string; votedForId: string }
  | { type: 'START_VOTING' }
  | { type: 'CONFIRM_STARTER' }
  | { type: 'START_IMPOSTER_GUESS' }
  | { type: 'SUBMIT_GUESS'; guess: string }
  | { type: 'JUDGE_GUESS'; isCorrect: boolean }
  | { type: 'ACK_ROUND_END'; playerId: string }
  | { type: 'RESET_GAME' }
  | { type: 'ADD_BOT' };

const GameContext = createContext<GameContextType | undefined>(undefined);

const INITIAL_STATE: GameState = {
  gameCode: '',
  phase: GamePhase.HOME,
  players: [],
  config: { mode: 'IN_PERSON', imposterCount: 1, cycles: 1 },
  currentTurnIndex: 0,
  clueRound: 1,
  currentHostId: null,
  hostIndex: 0,
  pastHostIds: [],
  currentCycle: 1,
  topic: '',
  category: '',
  clues: [],
  votes: {},
  imposterGuess: null,
  imposterGuessCorrect: null,
  winningPlayerId: null,
  nextPlayerTurnId: null,
};

const PEER_PREFIX = 'imposter-game-v1-';

export const GameProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [state, setState] = useState<GameState>(INITIAL_STATE);
  const [isHost, setIsHost] = useState(false);
  const [myPlayerId, setMyPlayerId] = useState<string | null>(null);

  const peerRef = useRef<Peer | null>(null);
  const connectionsRef = useRef<DataConnection[]>([]);
  const hostConnRef = useRef<DataConnection | null>(null);

  useEffect(() => {
    const storedId = sessionStorage.getItem('imposter_playerId');
    if (storedId) setMyPlayerId(storedId);
  }, []);

  useEffect(() => {
    if (myPlayerId) sessionStorage.setItem('imposter_playerId', myPlayerId);
    if (state.gameCode) sessionStorage.setItem('imposter_gameCode', state.gameCode);
  }, [myPlayerId, state.gameCode]);

  // Logic for Bot Host progression and Bot Imposter guessing
  useEffect(() => {
    if (isHost) {
      const currentHost = state.players.find(p => p.id === state.currentHostId);
      const imposter = state.players.find(p => p.isImposter);

      // 1. Bot Host progression
      if (currentHost?.isBot) {
        if (state.phase === GamePhase.TOPIC_SELECTION) {
          const timer = setTimeout(() => setTopic('PIZZA', 'Food/Drink'), 2000);
          return () => clearTimeout(timer);
        }
        if (state.phase === GamePhase.ROUND_STARTER) {
          const timer = setTimeout(() => confirmStarter(), 2000);
          return () => clearTimeout(timer);
        }
        if (state.phase === GamePhase.DISCUSSION) {
          const timer = setTimeout(() => startVoting(), 6000);
          return () => clearTimeout(timer);
        }
        if (state.phase === GamePhase.REVEAL) {
          const timer = setTimeout(() => startImposterGuess(), 5000);
          return () => clearTimeout(timer);
        }
        if (state.phase === GamePhase.HOST_REVIEW && state.imposterGuess) {
          const timer = setTimeout(() => judgeImposterGuess(Math.random() > 0.4), 3000);
          return () => clearTimeout(timer);
        }
      }

      // 2. Bot Imposter Guessing
      if (state.phase === GamePhase.IMPOSTER_GUESS && imposter?.isBot) {
        const timer = setTimeout(() => {
          submitImposterGuess("PIZZA?"); // Bots are simple, they always guess pizza or similar
        }, 3000);
        return () => clearTimeout(timer);
      }
    }
  }, [state.phase, state.currentHostId, isHost, state.imposterGuess, state.players]);

  const broadcastState = (newState: GameState) => {
    connectionsRef.current.forEach(conn => {
      if (conn.open) {
        conn.send({ type: 'SYNC_STATE', state: newState });
      }
    });
  };

  const sendActionToHost = (action: GameAction) => {
    if (hostConnRef.current && hostConnRef.current.open) {
      hostConnRef.current.send(action);
    }
  };

  const processAction = (action: GameAction, currentState: GameState): GameState => {
    switch (action.type) {
        case 'JOIN_REQUEST':
            const existingIdx = currentState.players.findIndex(p => p.id === action.player.id);
            if (existingIdx !== -1) {
                const updatedPlayers = [...currentState.players];
                updatedPlayers[existingIdx] = {
                    ...updatedPlayers[existingIdx],
                    name: action.player.name,
                    avatarUrl: action.player.avatarUrl || updatedPlayers[existingIdx].avatarUrl
                };
                return { ...currentState, players: updatedPlayers };
            }
            if (currentState.players.some(p => p.name === action.player.name)) return currentState;
            return { ...currentState, players: [...currentState.players, action.player] };

        case 'UPDATE_CONFIG':
            return { ...currentState, config: { ...currentState.config, ...action.config } };

        case 'ADD_BOT': {
             const names = ["Robo", "Spark", "Gizmo", "Chip", "Bolt", "Data", "Circuit", "Pixel", "Unit-01", "Vector"];
             const botPlayer: Player = {
                id: "BOT-" + Math.random().toString(36).substr(2, 9),
                name: names[Math.floor(Math.random() * names.length)],
                avatarSeed: Math.random().toString(),
                isHost: false,
                isImposter: false,
                isBot: true,
                score: 0,
                voteCount: 0,
                isReady: true
             };
             return { ...currentState, players: [...currentState.players, botPlayer] };
        }

        case 'START_GAME': {
            if (currentState.players.length < 3) return currentState;
            const randHostIdx = Math.floor(Math.random() * currentState.players.length);
            const hostId = currentState.players[randHostIdx].id;
            const newPlayers = currentState.players.map(p => ({
                ...p,
                isHost: p.id === hostId,
                isImposter: false,
                voteCount: 0,
                isReady: false,
                score: 0
            }));
            return {
                ...currentState,
                players: newPlayers,
                currentHostId: hostId,
                pastHostIds: [hostId],
                currentCycle: 1,
                phase: GamePhase.TOPIC_SELECTION,
                clues: [],
                votes: {},
                topic: '',
            };
        }

        case 'SET_TOPIC': {
            const hostId = currentState.currentHostId;
            const manualImposterIds = action.manualImposterIds || [];
            const shuffled = [...currentState.players];
            const imposterIndices = new Set<number>();

            if (manualImposterIds.length > 0) {
                 manualImposterIds.forEach(id => {
                     const idx = shuffled.findIndex(p => p.id === id);
                     if (idx !== -1) imposterIndices.add(idx);
                 });
            } else {
                 while (imposterIndices.size < currentState.config.imposterCount) {
                    const idx = Math.floor(Math.random() * shuffled.length);
                    if (shuffled[idx].id !== hostId && !imposterIndices.has(idx)) {
                        imposterIndices.add(idx);
                    }
                }
            }

            const newPlayers = shuffled.map((p, idx) => ({
                ...p,
                isHost: p.id === hostId,
                isImposter: imposterIndices.has(idx),
                isReady: false
            }));

            const eligibleStarterIndices = newPlayers
                .map((p, idx) => p.isHost ? -1 : idx)
                .filter(idx => idx !== -1);
            const randomStarterIndex = eligibleStarterIndices[Math.floor(Math.random() * eligibleStarterIndices.length)];

            return {
                ...currentState,
                players: newPlayers,
                currentTurnIndex: randomStarterIndex,
                topic: action.topic,
                category: action.category,
                topicImage: action.image,
                phase: GamePhase.ROLE_REVEAL
            };
        }

        case 'CONFIRM_STARTER':
            return { ...currentState, phase: GamePhase.DISCUSSION };

        case 'START_VOTING': {
             return { ...currentState, phase: GamePhase.VOTING };
        }

        case 'SUBMIT_CLUE': {
            const currentPlayer = currentState.players[currentState.currentTurnIndex];
            const newClues = [...currentState.clues, { playerId: currentPlayer.id, text: action.text, timestamp: Date.now() }];
            const activePlayerCount = currentState.players.length - 1;
            const totalCluesNeeded = activePlayerCount * 2;

            let nIdx = (currentState.currentTurnIndex + 1) % currentState.players.length;
            let nRound = currentState.clueRound;
            let nClues = [...newClues];

            while(true) {
                const p = currentState.players[nIdx];
                if (nClues.length >= totalCluesNeeded) break;
                if (p.isHost) {
                    nIdx = (nIdx + 1) % currentState.players.length;
                    continue;
                }
                if (p.isBot) {
                    nClues.push({ playerId: p.id, text: `...`, timestamp: Date.now() });
                    nIdx = (nIdx + 1) % currentState.players.length;
                    continue;
                }
                break;
            }

            if (nClues.length >= totalCluesNeeded) {
                 return { ...currentState, clues: nClues, phase: GamePhase.VOTING };
            }

            if (nClues.length >= activePlayerCount) nRound = 2;

            return {
                ...currentState,
                clues: nClues,
                currentTurnIndex: nIdx,
                clueRound: nRound,
                phase: GamePhase.CLUES
            };
        }

        case 'SUBMIT_VOTE': {
            const newVotes = { ...currentState.votes, [action.voterId]: action.votedForId };
            const votingHumans = currentState.players.filter(p => !p.isBot && !p.isHost);
            const humansWhoVoted = votingHumans.filter(h => newVotes[h.id]);

            if (humansWhoVoted.length === votingHumans.length) {
                // All humans voted. Bots vote automatically.
                const finalVotes = simulateBotVotes(currentState.players, currentState.config.imposterCount, newVotes);
                const updatedPlayers = currentState.players.map(p => {
                    const votesReceived = Object.values(finalVotes).filter(id => id === p.id).length;
                    return { ...p, voteCount: votesReceived };
                });
                return { ...currentState, players: updatedPlayers, votes: finalVotes, phase: GamePhase.REVEAL };
            }
            return { ...currentState, votes: newVotes };
        }

        case 'START_IMPOSTER_GUESS':
             return { ...currentState, phase: GamePhase.IMPOSTER_GUESS };

        case 'SUBMIT_GUESS':
             return { ...currentState, imposterGuess: action.guess, phase: GamePhase.HOST_REVIEW };

        case 'JUDGE_GUESS': {
            let maxVotes = 0;
            currentState.players.forEach(p => { if(p.voteCount > maxVotes) maxVotes = p.voteCount; });
            const accusedPlayers = currentState.players.filter(p => p.voteCount === maxVotes);

            const newPlayers = currentState.players.map(p => {
                let points = p.score;
                if (p.isHost) return p;
                if (p.isImposter) {
                    const isCaught = accusedPlayers.some(accused => accused.id === p.id);
                    if (!isCaught) points += 100;
                    if (action.isCorrect) points += 200;
                } else {
                    const votedForId = currentState.votes[p.id];
                    const votedForPerson = currentState.players.find(pl => pl.id === votedForId);
                    if (votedForPerson && votedForPerson.isImposter) points += 100;
                }
                return { ...p, score: points, isReady: false };
            });
            return { ...currentState, players: newPlayers, imposterGuessCorrect: action.isCorrect, phase: GamePhase.SCOREBOARD };
        }

        case 'ACK_ROUND_END': {
             // Toggle isReady for the player who clicked
             const updatedPlayers = currentState.players.map(p => (p.id === action.playerId) ? { ...p, isReady: !p.isReady } : p);
             const activePlayers = updatedPlayers;
             const readyCount = activePlayers.filter(p => p.isReady || p.isBot).length;

             if (readyCount === activePlayers.length) {
                if (currentState.phase === GamePhase.ROLE_REVEAL) {
                    return {
                        ...currentState,
                        players: updatedPlayers.map(p => ({ ...p, isReady: false })), 
                        phase: currentState.config.mode === 'IN_PERSON' ? GamePhase.ROUND_STARTER : GamePhase.CLUES
                    };
                }

                // Proceed to next round topic selection
                let nextPastHosts = [...currentState.pastHostIds];
                let nextCycle = currentState.currentCycle;

                let availableHosts = currentState.players.filter(p => !nextPastHosts.includes(p.id));

                if (availableHosts.length === 0) {
                    if (nextCycle < currentState.config.cycles) {
                        nextCycle += 1;
                        nextPastHosts = [];
                        availableHosts = [...currentState.players];
                    } else {
                        // All cycles done, end game
                        const sorted = [...updatedPlayers].sort((a,b) => b.score - a.score);
                        return { ...currentState, players: updatedPlayers, winningPlayerId: sorted[0].id, phase: GamePhase.WINNER };
                    }
                }

                const nextHost = availableHosts[Math.floor(Math.random() * availableHosts.length)];
                return {
                    ...currentState,
                    players: updatedPlayers.map(p => ({ ...p, isHost: p.id === nextHost.id, isImposter: false, isReady: false, voteCount: 0 })),
                    currentHostId: nextHost.id,
                    pastHostIds: [...nextPastHosts, nextHost.id],
                    currentCycle: nextCycle,
                    phase: GamePhase.TOPIC_SELECTION,
                    clues: [],
                    votes: {},
                    topic: '',
                    imposterGuess: null,
                    imposterGuessCorrect: null,
                };
             }
             return { ...currentState, players: updatedPlayers };
        }

        case 'RESET_GAME':
             return { ...INITIAL_STATE, gameCode: currentState.gameCode, phase: GamePhase.LOBBY, players: [] };

        default:
            return currentState;
    }
  };

  const simulateBotVotes = (allPlayers: Player[], imposterCount: number, existingVotes: Record<string,string>): Record<string, string> => {
    const votes: Record<string, string> = { ...existingVotes };
    const candidates = allPlayers.filter(p => !p.isHost);
    allPlayers.filter(p => p.isBot && !p.isHost).forEach(bot => {
        if (votes[bot.id]) return; // Already voted?
        const otherCandidates = candidates.filter(c => c.id !== bot.id);
        const target = otherCandidates[Math.floor(Math.random() * otherCandidates.length)];
        if (target) votes[bot.id] = target.id;
    });
    return votes;
  };

  const dispatch = (action: GameAction) => {
    if (isHost) {
        const newState = processAction(action, state);
        setState(newState);
        broadcastState(newState);
    } else {
        sendActionToHost(action);
    }
  };

  const createGame = (name: string, avatarUrl?: string) => {
    const code = Math.random().toString(36).substring(2, 7).toUpperCase();
    const playerId = Math.random().toString(36).substr(2, 9);
    const creatorPlayer: Player = {
        id: playerId, name, avatarSeed: Math.random().toString(), avatarUrl,
        isHost: false, isImposter: false, isBot: false, score: 0, voteCount: 0, isReady: false
    };
    const newState = { ...INITIAL_STATE, gameCode: code, phase: GamePhase.LOBBY, players: [creatorPlayer] };
    const peer = new Peer(PEER_PREFIX + code);
    peer.on('open', (id) => {
        setIsHost(true);
        setMyPlayerId(playerId);
        setState(newState);
    });
    peer.on('connection', (conn) => {
        connectionsRef.current.push(conn);
        conn.on('data', (data: any) => {
            setState(current => {
                const updated = processAction(data as GameAction, current);
                connectionsRef.current.forEach(c => { if (c.open) c.send({ type: 'SYNC_STATE', state: updated }); });
                return updated;
            });
        });
        setState(current => { conn.send({ type: 'SYNC_STATE', state: current }); return current; });
    });
    peerRef.current = peer;
  };

  const connectToPeer = (code: string, playerId: string, playerData?: Partial<Player>) => {
    const peer = new Peer(); 
    peer.on('open', () => {
        const conn = peer.connect(PEER_PREFIX + code);
        conn.on('open', () => {
            hostConnRef.current = conn;
            setIsHost(false);
            setMyPlayerId(playerId);
            const player: Player = {
                id: playerId, name: playerData?.name || "Player", avatarSeed: playerData?.avatarSeed || Math.random().toString(),
                avatarUrl: playerData?.avatarUrl, isHost: false, isImposter: false, isBot: false, score: 0, voteCount: 0, isReady: false
            };
            conn.send({ type: 'JOIN_REQUEST', player });
        });
        conn.on('data', (data: any) => { if (data.type === 'SYNC_STATE') setState(data.state); });
    });
    peerRef.current = peer;
  };

  const joinGame = (code: string, name: string, avatarUrl?: string) => {
      const storedId = sessionStorage.getItem('imposter_playerId');
      const playerId = storedId || Math.random().toString(36).substr(2, 9);
      connectToPeer(code, playerId, { name, avatarUrl });
  };

  const reconnectGame = (code: string, playerId: string) => connectToPeer(code, playerId);
  const updateConfig = (config: Partial<GameConfig>) => dispatch({ type: 'UPDATE_CONFIG', config });
  const startGame = () => dispatch({ type: 'START_GAME' });
  const addBot = () => dispatch({ type: 'ADD_BOT' });
  const setTopic = (topic: string, category: string, image?: string, manualImposterIds?: string[]) => dispatch({ type: 'SET_TOPIC', topic, category, image, manualImposterIds });
  const finishRoleReveal = () => myPlayerId && dispatch({ type: 'ACK_ROUND_END', playerId: myPlayerId });
  const confirmStarter = () => dispatch({ type: 'CONFIRM_STARTER' });
  const startVoting = () => dispatch({ type: 'START_VOTING' });
  const confirmPassDevice = () => { };
  const startImposterGuess = () => dispatch({ type: 'START_IMPOSTER_GUESS' });
  const submitClue = (text: string) => dispatch({ type: 'SUBMIT_CLUE', text });
  const submitVote = (voterId: string, votedForId: string) => dispatch({ type: 'SUBMIT_VOTE', voterId, votedForId });
  const submitImposterGuess = (guess: string) => dispatch({ type: 'SUBMIT_GUESS', guess });
  const judgeImposterGuess = (isCorrect: boolean) => dispatch({ type: 'JUDGE_GUESS', isCorrect });
  const acknowledgeRoundEnd = (playerId: string) => dispatch({ type: 'ACK_ROUND_END', playerId });
  const resetGame = () => dispatch({ type: 'RESET_GAME' });

  const amIGameHost = !!state.currentHostId && state.currentHostId === myPlayerId;

  return (
    <GameContext.Provider value={{
      state, isHost, isNetworkHost: isHost, myPlayerId, amIGameHost, createGame, joinGame, reconnectGame, updateConfig, startGame, setTopic, submitClue, submitVote, submitImposterGuess, judgeImposterGuess, acknowledgeRoundEnd, resetGame, addBot, confirmPassDevice,
      finishRoleReveal, startVoting, confirmStarter, startImposterGuess
    }}>
      {children}
    </GameContext.Provider>
  );
};

export const useGame = () => {
  const context = useContext(GameContext);
  if (!context) throw new Error("useGame must be used within a GameProvider");
  return context;
};

import React, { useEffect, useState } from 'react';
import { useGame } from '../context/GameContext';
import { Avatar } from '../components/Avatar';
import { Button } from '../components/Button';

export const RevealScreen: React.FC = () => {
  const { state, startImposterGuess, amIGameHost } = useGame();
  const { players } = state;
  const [stage, setStage] = useState(0); 

  useEffect(() => {
    const t1 = setTimeout(() => setStage(1), 3000); 
    const t2 = setTimeout(() => setStage(2), 6000); 
    return () => { clearTimeout(t1); clearTimeout(t2); };
  }, []);

  return (
    <div className={`min-h-screen transition-colors duration-1000 flex flex-col items-center justify-center p-6 text-center ${stage >= 2 ? 'bg-black' : 'bg-game-bg'}`}>

      {stage === 0 && (
        <div className="w-full space-y-8 animate-fade-in">
           <h2 className="text-2xl font-black text-white uppercase tracking-[0.3em]">Tallying Votes...</h2>
           <div className="grid grid-cols-3 gap-8">
              {players.filter(p => !p.isHost).map(p => (
                  <div key={p.id} className="relative flex flex-col items-center">
                      <Avatar seed={p.avatarSeed} url={p.avatarUrl} name={p.name} size="lg" />
                      {p.voteCount > 0 && (
                          <div className="absolute -top-2 -right-2 bg-white text-black font-black w-8 h-8 rounded-full flex items-center justify-center shadow-[0_0_15px_rgba(255,255,255,0.5)] transform scale-125 z-10">
                              {p.voteCount}
                          </div>
                      )}
                  </div>
              ))}
           </div>
        </div>
      )}

      {stage === 1 && (
        <div className="animate-shake">
            <h1 className="text-5xl font-black text-white tracking-[0.2em] mb-4 uppercase drop-shadow-[0_0_10px_rgba(255,255,255,0.3)]">THE DECEIVER WAS...</h1>
            <div className="w-16 h-16 border-4 border-white border-t-transparent rounded-full animate-spin mx-auto mt-8"></div>
        </div>
      )}

      {stage === 2 && (
        <div className="w-full max-w-lg space-y-12 animate-bounce-in">
             <div className="relative py-12 border-y-4 border-red-600 bg-red-950/20 overflow-hidden shadow-[0_0_50px_rgba(220,38,38,0.2)]">
                 {/* Glitch Overlay */}
                 <div className="absolute inset-0 bg-red-500/5 animate-pulse"></div>

                 <h2 className="text-red-600 font-black text-4xl uppercase tracking-[0.4em] mb-10 relative z-10 animate-pulse">EXPOSED</h2>

                 <div className="flex justify-center gap-10 relative z-10">
                     {players.filter(p => p.isImposter).map(p => (
                         <div key={p.id} className="flex flex-col items-center group">
                              <div className="relative">
                                  <Avatar seed={p.avatarSeed} url={p.avatarUrl} size="xl" className="ring-4 ring-red-600 rounded-full grayscale hover:grayscale-0 transition-all duration-700" />
                                  <div className="absolute inset-0 bg-red-600/20 rounded-full animate-ping pointer-events-none"></div>
                              </div>
                              <span className="mt-6 font-black text-white text-2xl tracking-widest">{p.name.toUpperCase()}</span>
                              <span className="text-red-500 font-bold text-xs mt-1 tracking-tighter">IMPOSTER</span>
                         </div>
                     ))}
                 </div>
             </div>

             <div className="space-y-6">
                 {amIGameHost ? (
                     <div className="flex flex-col items-center gap-4">
                        <p className="text-red-500 font-black uppercase text-xs tracking-[0.3em]">Master of Shadows</p>
                        <Button 
                            onClick={startImposterGuess} 
                            variant="danger"
                            className="w-full max-w-xs animate-pulse ring-2 ring-red-500 ring-offset-4 ring-offset-black"
                        >
                            PROCEED TO JUDGEMENT &rarr;
                        </Button>
                     </div>
                 ) : (
                     <div className="space-y-2">
                        <p className="text-red-900 animate-pulse uppercase text-sm font-black tracking-widest">
                            Waiting for the Host's verdict...
                        </p>
                        <div className="flex justify-center gap-1">
                            <div className="w-1 h-1 bg-red-600 animate-bounce"></div>
                            <div className="w-1 h-1 bg-red-600 animate-bounce delay-100"></div>
                            <div className="w-1 h-1 bg-red-600 animate-bounce delay-200"></div>
                        </div>
                     </div>
                 )}
             </div>
        </div>
      )}
    </div>
  );
};

import React, { createContext, useContext, useState, useEffect, useRef } from 'react';
import { GamePhase, GameState, Player, GameConfig, GameContextType } from '../types';
import Peer, { DataConnection } from 'peerjs';

type GameAction = 
  | { type: 'SYNC_STATE'; state: GameState }
  | { type: 'JOIN_REQUEST'; player: Player }
  | { type: 'UPDATE_CONFIG'; config: Partial<GameConfig> }
  | { type: 'START_GAME' }
  | { type: 'SET_TOPIC'; topic: string; category: string; image?: string; manualImposterIds?: string[] }
  | { type: 'SUBMIT_CLUE'; text: string }
  | { type: 'SUBMIT_VOTE'; voterId: string; votedForId: string }
  | { type: 'START_VOTING' }
  | { type: 'CONFIRM_STARTER' }
  | { type: 'START_IMPOSTER_GUESS' }
  | { type: 'SUBMIT_GUESS'; guess: string }
  | { type: 'JUDGE_GUESS'; isCorrect: boolean }
  | { type: 'ACK_ROUND_END'; playerId: string }
  | { type: 'RESET_GAME' }
  | { type: 'ADD_BOT' };

const GameContext = createContext<GameContextType | undefined>(undefined);

const INITIAL_STATE: GameState = {
  gameCode: '',
  phase: GamePhase.HOME,
  players: [],
  config: { mode: 'IN_PERSON', imposterCount: 1, cycles: 1 },
  currentTurnIndex: 0,
  clueRound: 1,
  currentHostId: null,
  hostIndex: 0,
  pastHostIds: [],
  currentCycle: 1,
  topic: '',
  category: '',
  clues: [],
  votes: {},
  imposterGuess: null,
  imposterGuessCorrect: null,
  winningPlayerId: null,
  nextPlayerTurnId: null,
};

const PEER_PREFIX = 'imposter-game-v1-';

export const GameProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [state, setState] = useState<GameState>(INITIAL_STATE);
  const [isHost, setIsHost] = useState(false);
  const [myPlayerId, setMyPlayerId] = useState<string | null>(null);

  const peerRef = useRef<Peer | null>(null);
  const connectionsRef = useRef<DataConnection[]>([]);
  const hostConnRef = useRef<DataConnection | null>(null);

  useEffect(() => {
    const storedId = sessionStorage.getItem('imposter_playerId');
    if (storedId) setMyPlayerId(storedId);
  }, []);

  useEffect(() => {
    if (myPlayerId) sessionStorage.setItem('imposter_playerId', myPlayerId);
    if (state.gameCode) sessionStorage.setItem('imposter_gameCode', state.gameCode);
  }, [myPlayerId, state.gameCode]);

  // AI progression logic
  useEffect(() => {
    if (isHost) {
      const currentHost = state.players.find(p => p.id === state.currentHostId);
      const imposter = state.players.find(p => p.isImposter);

      // Bot Host progression
      if (currentHost?.isBot) {
        if (state.phase === GamePhase.TOPIC_SELECTION) {
          const timer = setTimeout(() => setTopic('PIZZA', 'Food/Drink'), 2000);
          return () => clearTimeout(timer);
        }
        if (state.phase === GamePhase.ROUND_STARTER) {
          const timer = setTimeout(() => confirmStarter(), 2000);
          return () => clearTimeout(timer);
        }
        if (state.phase === GamePhase.DISCUSSION) {
          const timer = setTimeout(() => startVoting(), 6000);
          return () => clearTimeout(timer);
        }
        if (state.phase === GamePhase.REVEAL) {
          const timer = setTimeout(() => startImposterGuess(), 5000);
          return () => clearTimeout(timer);
        }
        if (state.phase === GamePhase.HOST_REVIEW && state.imposterGuess) {
          const timer = setTimeout(() => judgeImposterGuess(Math.random() > 0.4), 3000);
          return () => clearTimeout(timer);
        }
      }

      // Bot Imposter Guessing logic
      if (state.phase === GamePhase.IMPOSTER_GUESS && imposter?.isBot) {
        const timer = setTimeout(() => {
          submitImposterGuess("PIZZA"); 
        }, 3000);
        return () => clearTimeout(timer);
      }
    }
  }, [state.phase, state.currentHostId, isHost, state.imposterGuess, state.players]);

  const broadcastState = (newState: GameState) => {
    connectionsRef.current.forEach(conn => {
      if (conn.open) {
        conn.send({ type: 'SYNC_STATE', state: newState });
      }
    });
  };

  const sendActionToHost = (action: GameAction) => {
    if (hostConnRef.current && hostConnRef.current.open) {
      hostConnRef.current.send(action);
    }
  };

  const processAction = (action: GameAction, currentState: GameState): GameState => {
    switch (action.type) {
        case 'JOIN_REQUEST':
            const existingIdx = currentState.players.findIndex(p => p.id === action.player.id);
            if (existingIdx !== -1) {
                const updatedPlayers = [...currentState.players];
                updatedPlayers[existingIdx] = {
                    ...updatedPlayers[existingIdx],
                    name: action.player.name,
                    avatarUrl: action.player.avatarUrl || updatedPlayers[existingIdx].avatarUrl
                };
                return { ...currentState, players: updatedPlayers };
            }
            if (currentState.players.some(p => p.name === action.player.name)) return currentState;
            return { ...currentState, players: [...currentState.players, action.player] };

        case 'UPDATE_CONFIG':
            return { ...currentState, config: { ...currentState.config, ...action.config } };

        case 'ADD_BOT': {
             const names = ["Unit-X", "Spark", "Gizmo", "Chip", "Bolt", "Nexus", "Circuit", "Pixel", "Droid", "Robo"];
             const botPlayer: Player = {
                id: "BOT-" + Math.random().toString(36).substr(2, 9),
                name: names[Math.floor(Math.random() * names.length)],
                avatarSeed: Math.random().toString(),
                isHost: false,
                isImposter: false,
                isBot: true,
                score: 0,
                voteCount: 0,
                isReady: true
             };
             return { ...currentState, players: [...currentState.players, botPlayer] };
        }

        case 'START_GAME': {
            if (currentState.players.length < 3) return currentState;
            const randHostIdx = Math.floor(Math.random() * currentState.players.length);
            const hostId = currentState.players[randHostIdx].id;
            return {
                ...currentState,
                players: currentState.players.map(p => ({
                    ...p, isHost: p.id === hostId, isImposter: false, voteCount: 0, isReady: false, score: 0
                })),
                currentHostId: hostId,
                pastHostIds: [hostId],
                currentCycle: 1,
                phase: GamePhase.TOPIC_SELECTION,
                clues: [],
                votes: {},
                topic: '',
            };
        }

        case 'SET_TOPIC': {
            const hostId = currentState.currentHostId;
            const manualImposterIds = action.manualImposterIds || [];
            const players = [...currentState.players];
            const imposterIndices = new Set<number>();

            if (manualImposterIds.length > 0) {
                 manualImposterIds.forEach(id => {
                     const idx = players.findIndex(p => p.id === id);
                     if (idx !== -1) imposterIndices.add(idx);
                 });
            } else {
                 while (imposterIndices.size < currentState.config.imposterCount) {
                    const idx = Math.floor(Math.random() * players.length);
                    if (players[idx].id !== hostId && !imposterIndices.has(idx)) {
                        imposterIndices.add(idx);
                    }
                }
            }

            const newPlayers = players.map((p, idx) => ({
                ...p,
                isHost: p.id === hostId,
                isImposter: imposterIndices.has(idx),
                isReady: false
            }));

            const eligibleStarterIndices = newPlayers
                .map((p, idx) => p.isHost ? -1 : idx)
                .filter(idx => idx !== -1);
            const randomStarterIndex = eligibleStarterIndices[Math.floor(Math.random() * eligibleStarterIndices.length)];

            return {
                ...currentState,
                players: newPlayers,
                currentTurnIndex: randomStarterIndex,
                topic: action.topic,
                category: action.category,
                topicImage: action.image,
                phase: GamePhase.ROLE_REVEAL,
                imposterGuess: null,
                imposterGuessCorrect: null,
            };
        }

        case 'CONFIRM_STARTER':
            return { ...currentState, phase: GamePhase.DISCUSSION };

        case 'START_VOTING':
             return { ...currentState, phase: GamePhase.VOTING };

        case 'SUBMIT_CLUE': {
            const currentPlayer = currentState.players[currentState.currentTurnIndex];
            const newClues = [...currentState.clues, { playerId: currentPlayer.id, text: action.text, timestamp: Date.now() }];
            const activePlayerCount = currentState.players.length - 1;
            const totalCluesNeeded = activePlayerCount * 2;

            let nIdx = (currentState.currentTurnIndex + 1) % currentState.players.length;
            let nRound = currentState.clueRound;
            let nClues = [...newClues];

            while(true) {
                const p = currentState.players[nIdx];
                if (nClues.length >= totalCluesNeeded) break;
                if (p.isHost) {
                    nIdx = (nIdx + 1) % currentState.players.length;
                    continue;
                }
                if (p.isBot) {
                    nClues.push({ playerId: p.id, text: `...`, timestamp: Date.now() });
                    nIdx = (nIdx + 1) % currentState.players.length;
                    continue;
                }
                break;
            }

            if (nClues.length >= totalCluesNeeded) {
                 return { ...currentState, clues: nClues, phase: GamePhase.VOTING };
            }

            if (nClues.length >= activePlayerCount) nRound = 2;

            return {
                ...currentState,
                clues: nClues,
                currentTurnIndex: nIdx,
                clueRound: nRound,
                phase: GamePhase.CLUES
            };
        }

        case 'SUBMIT_VOTE': {
            const newVotes = { ...currentState.votes, [action.voterId]: action.votedForId };
            const votingHumans = currentState.players.filter(p => !p.isBot && !p.isHost);
            const humansWhoVoted = votingHumans.filter(h => newVotes[h.id]);

            if (humansWhoVoted.length === votingHumans.length) {
                const finalVotes = simulateBotVotes(currentState.players, currentState.config.imposterCount, newVotes);
                const updatedPlayers = currentState.players.map(p => {
                    const votesReceived = Object.values(finalVotes).filter(id => id === p.id).length;
                    return { ...p, voteCount: votesReceived };
                });
                return { ...currentState, players: updatedPlayers, votes: finalVotes, phase: GamePhase.REVEAL };
            }
            return { ...currentState, votes: newVotes };
        }

        case 'START_IMPOSTER_GUESS':
             return { ...currentState, phase: GamePhase.IMPOSTER_GUESS };

        case 'SUBMIT_GUESS':
             return { ...currentState, imposterGuess: action.guess, phase: GamePhase.HOST_REVIEW };

        case 'JUDGE_GUESS': {
            const imposter = currentState.players.find(p => p.isImposter);
            if (!imposter) return currentState;

            // Majority Logic: Most voted player(s)
            let maxVotes = 0;
            currentState.players.forEach(p => { if(p.voteCount > maxVotes) maxVotes = p.voteCount; });
            const accusedPlayers = currentState.players.filter(p => p.voteCount === maxVotes);

            // Majority did NOT vote for imposter if the imposter is NOT among the most voted
            const majorityVotedForImposter = accusedPlayers.some(p => p.id === imposter.id);

            const newPlayers = currentState.players.map(p => {
                let roundPoints = 0;

                if (p.isHost) return p;

                if (p.isImposter) {
                    // Imposter points: 2 for blending in, 1 for correct guess
                    if (!majorityVotedForImposter) roundPoints += 2;
                    if (action.isCorrect) roundPoints += 1;
                } else {
                    // Innocent points: 1 if they individually voted for the imposter
                    const theirVote = currentState.votes[p.id];
                    if (theirVote === imposter.id) roundPoints += 1;
                }

                return { ...p, score: p.score + roundPoints, isReady: false };
            });

            return { ...currentState, players: newPlayers, imposterGuessCorrect: action.isCorrect, phase: GamePhase.SCOREBOARD };
        }

        case 'ACK_ROUND_END': {
             const updatedPlayers = currentState.players.map(p => (p.id === action.playerId) ? { ...p, isReady: !p.isReady } : p);
             const readyCount = updatedPlayers.filter(p => p.isReady || p.isBot).length;

             if (readyCount === updatedPlayers.length) {
                if (currentState.phase === GamePhase.ROLE_REVEAL) {
                    return {
                        ...currentState,
                        players: updatedPlayers.map(p => ({ ...p, isReady: false })), 
                        phase: currentState.config.mode === 'IN_PERSON' ? GamePhase.ROUND_STARTER : GamePhase.CLUES
                    };
                }

                let nextPastHosts = [...currentState.pastHostIds];
                let nextCycle = currentState.currentCycle;
                let availableHosts = currentState.players.filter(p => !nextPastHosts.includes(p.id));

                if (availableHosts.length === 0) {
                    if (nextCycle < currentState.config.cycles) {
                        nextCycle += 1;
                        nextPastHosts = [];
                        availableHosts = [...currentState.players];
                    } else {
                        const sorted = [...updatedPlayers].sort((a,b) => b.score - a.score);
                        return { ...currentState, players: updatedPlayers, winningPlayerId: sorted[0].id, phase: GamePhase.WINNER };
                    }
                }

                const nextHost = availableHosts[Math.floor(Math.random() * availableHosts.length)];
                return {
                    ...currentState,
                    players: updatedPlayers.map(p => ({ ...p, isHost: p.id === nextHost.id, isImposter: false, isReady: false, voteCount: 0 })),
                    currentHostId: nextHost.id,
                    pastHostIds: [...nextPastHosts, nextHost.id],
                    currentCycle: nextCycle,
                    phase: GamePhase.TOPIC_SELECTION,
                    clues: [],
                    votes: {},
                    topic: '',
                    imposterGuess: null,
                    imposterGuessCorrect: null,
                };
             }
             return { ...currentState, players: updatedPlayers };
        }

        case 'RESET_GAME':
             return { ...INITIAL_STATE, gameCode: currentState.gameCode, phase: GamePhase.LOBBY, players: [] };

        default:
            return currentState;
    }
  };

  const simulateBotVotes = (allPlayers: Player[], imposterCount: number, existingVotes: Record<string,string>): Record<string, string> => {
    const votes: Record<string, string> = { ...existingVotes };
    const candidates = allPlayers.filter(p => !p.isHost);
    allPlayers.filter(p => p.isBot && !p.isHost).forEach(bot => {
        if (votes[bot.id]) return;
        const otherCandidates = candidates.filter(c => c.id !== bot.id);
        const target = otherCandidates[Math.floor(Math.random() * otherCandidates.length)];
        if (target) votes[bot.id] = target.id;
    });
    return votes;
  };

  const dispatch = (action: GameAction) => {
    if (isHost) {
        const newState = processAction(action, state);
        setState(newState);
        broadcastState(newState);
    } else {
        sendActionToHost(action);
    }
  };

  const createGame = (name: string, avatarUrl?: string) => {
    const code = Math.random().toString(36).substring(2, 7).toUpperCase();
    const playerId = Math.random().toString(36).substr(2, 9);
    const creatorPlayer: Player = {
        id: playerId, name, avatarSeed: Math.random().toString(), avatarUrl,
        isHost: false, isImposter: false, isBot: false, score: 0, voteCount: 0, isReady: false
    };
    const newState = { ...INITIAL_STATE, gameCode: code, phase: GamePhase.LOBBY, players: [creatorPlayer] };
    const peer = new Peer(PEER_PREFIX + code);
    peer.on('open', () => { setIsHost(true); setMyPlayerId(playerId); setState(newState); });
    peer.on('connection', (conn) => {
        connectionsRef.current.push(conn);
        conn.on('data', (data: any) => {
            setState(current => {
                const updated = processAction(data as GameAction, current);
                connectionsRef.current.forEach(c => { if (c.open) c.send({ type: 'SYNC_STATE', state: updated }); });
                return updated;
            });
        });
        setState(current => { conn.send({ type: 'SYNC_STATE', state: current }); return current; });
    });
    peerRef.current = peer;
  };

  const connectToPeer = (code: string, playerId: string, playerData?: Partial<Player>) => {
    const peer = new Peer(); 
    peer.on('open', () => {
        const conn = peer.connect(PEER_PREFIX + code);
        conn.on('open', () => {
            hostConnRef.current = conn;
            setIsHost(false);
            setMyPlayerId(playerId);
            const player: Player = {
                id: playerId, name: playerData?.name || "Player", avatarSeed: playerData?.avatarSeed || Math.random().toString(),
                avatarUrl: playerData?.avatarUrl, isHost: false, isImposter: false, isBot: false, score: 0, voteCount: 0, isReady: false
            };
            conn.send({ type: 'JOIN_REQUEST', player });
        });
        conn.on('data', (data: any) => { if (data.type === 'SYNC_STATE') setState(data.state); });
    });
    peerRef.current = peer;
  };

  const joinGame = (code: string, name: string, avatarUrl?: string) => {
      const storedId = sessionStorage.getItem('imposter_playerId');
      const playerId = storedId || Math.random().toString(36).substr(2, 9);
      connectToPeer(code, playerId, { name, avatarUrl });
  };

  const reconnectGame = (code: string, playerId: string) => connectToPeer(code, playerId);
  const updateConfig = (config: Partial<GameConfig>) => dispatch({ type: 'UPDATE_CONFIG', config });
  const startGame = () => dispatch({ type: 'START_GAME' });
  const addBot = () => dispatch({ type: 'ADD_BOT' });
  const setTopic = (topic: string, category: string, image?: string, manualImposterIds?: string[]) => dispatch({ type: 'SET_TOPIC', topic, category, image, manualImposterIds });
  const finishRoleReveal = () => myPlayerId && dispatch({ type: 'ACK_ROUND_END', playerId: myPlayerId });
  const confirmStarter = () => dispatch({ type: 'CONFIRM_STARTER' });
  const startVoting = () => dispatch({ type: 'START_VOTING' });
  const confirmPassDevice = () => { };
  const startImposterGuess = () => dispatch({ type: 'START_IMPOSTER_GUESS' });
  const submitClue = (text: string) => dispatch({ type: 'SUBMIT_CLUE', text });
  const submitVote = (voterId: string, votedForId: string) => dispatch({ type: 'SUBMIT_VOTE', voterId, votedForId });
  const submitImposterGuess = (guess: string) => dispatch({ type: 'SUBMIT_GUESS', guess });
  const judgeImposterGuess = (isCorrect: boolean) => dispatch({ type: 'JUDGE_GUESS', isCorrect });
  const acknowledgeRoundEnd = (playerId: string) => dispatch({ type: 'ACK_ROUND_END', playerId });
  const resetGame = () => dispatch({ type: 'RESET_GAME' });

  const amIGameHost = !!state.currentHostId && state.currentHostId === myPlayerId;

  return (
    <GameContext.Provider value={{
      state, isHost, isNetworkHost: isHost, myPlayerId, amIGameHost, createGame, joinGame, reconnectGame, updateConfig, startGame, setTopic, submitClue, submitVote, submitImposterGuess, judgeImposterGuess, acknowledgeRoundEnd, resetGame, addBot, confirmPassDevice,
      finishRoleReveal, startVoting, confirmStarter, startImposterGuess
    }}>
      {children}
    </GameContext.Provider>
  );
};

export const useGame = () => {
  const context = useContext(GameContext);
  if (!context) throw new Error("useGame must be used within a GameProvider");
  return context;
};

import React, { useState } from 'react';
import { useGame } from '../context/GameContext';
import { Button } from '../components/Button';
import { Avatar } from '../components/Avatar';
import { GamePhase } from '../types';

export const ImposterGuessScreen: React.FC = () => {
  const { state, submitImposterGuess, judgeImposterGuess, myPlayerId, amIGameHost } = useGame();
  const { phase, players, clues, imposterGuess, topic } = state;
  const [guessInput, setGuessInput] = useState('');

  const me = players.find(p => p.id === myPlayerId);
  const imposter = players.find(p => p.isImposter);
  const host = players.find(p => p.id === state.currentHostId);

  // 1. Guessing Phase
  if (phase === GamePhase.IMPOSTER_GUESS) {
      if (me?.isImposter) {
          return (
              <div className="min-h-screen bg-game-bg flex flex-col p-6 animate-fade-in">
                  <h2 className="text-2xl font-black text-white text-center mb-6 uppercase tracking-widest">Identify the Topic</h2>
                  <div className="flex-1 bg-slate-800/50 rounded-2xl p-4 overflow-y-auto mb-6 border border-white/5">
                      <p className="text-[10px] text-slate-500 font-bold uppercase mb-4 tracking-[0.2em]">Clue History</p>
                      {clues.map((c, i) => {
                          const author = players.find(p => p.id === c.playerId);
                          return (
                              <div key={i} className="flex items-center gap-2 mb-2">
                                  <Avatar seed={author?.avatarSeed || '0'} url={author?.avatarUrl} size="sm" />
                                  <p className="text-sm italic text-white">"{c.text}"</p>
                              </div>
                          )
                      })}
                  </div>
                  <div className="space-y-4">
                      <input 
                        type="text" 
                        className="w-full bg-slate-900 border-2 border-slate-700 p-4 rounded-xl text-center text-white outline-none focus:border-game-primary transition-all uppercase font-bold" 
                        placeholder="ENTER YOUR GUESS..." 
                        value={guessInput} 
                        onChange={e => setGuessInput(e.target.value.toUpperCase())} 
                      />
                      <Button fullWidth onClick={() => submitImposterGuess(guessInput)} disabled={!guessInput.trim()}>
                          SUBMIT FINAL GUESS
                      </Button>
                  </div>
              </div>
          );
      }
      return (
          <div className="min-h-screen bg-game-bg flex flex-col items-center justify-center p-6 text-center">
              <div className="relative mb-8">
                  <Avatar seed={imposter?.avatarSeed || '0'} url={imposter?.avatarUrl} size="xl" className="animate-pulse" />
                  <div className="absolute inset-0 ring-4 ring-red-600 rounded-full animate-ping opacity-20"></div>
              </div>
              <h2 className="text-2xl font-black text-white mb-2 uppercase tracking-widest">IMPOSTER IS GUESSING</h2>
              <p className="text-slate-400">Waiting for {imposter?.name} to identify the secret topic...</p>
          </div>
      );
  }

  // 2. Review Phase (Visible to EVERYONE)
  if (phase === GamePhase.HOST_REVIEW) {
      return (
          <div className="min-h-screen bg-black flex flex-col items-center justify-center p-6 text-center animate-fade-in">
              <div className="mb-10">
                  <h2 className="text-4xl font-black text-white mb-2 tracking-tighter">THE VERDICT</h2>
                  <p className="text-red-600 font-bold uppercase text-xs tracking-[0.3em]">Host is Judging the Guess</p>
              </div>

              <div className="bg-slate-900/50 p-8 rounded-3xl border border-red-900/30 w-full max-w-md mb-10 space-y-8 shadow-[0_0_50px_rgba(220,38,38,0.1)]">
                  <div>
                      <p className="text-[10px] text-slate-500 uppercase font-black tracking-widest mb-2">The Real Topic Was</p>
                      <p className="text-3xl font-black text-game-success uppercase tracking-tight">{topic}</p>
                  </div>

                  <div className="h-px bg-slate-800 w-full"></div>

                  <div>
                      <p className="text-[10px] text-slate-500 uppercase font-black tracking-widest mb-2">{imposter?.name} Guessed</p>
                      <p className="text-3xl font-black text-white uppercase italic tracking-tight">"{imposterGuess}"</p>
                  </div>
              </div>

              {amIGameHost ? (
                  <div className="flex gap-4 w-full max-w-md">
                      <Button variant="danger" className="flex-1 !py-6 font-black" onClick={() => judgeImposterGuess(false)}>WRONG</Button>
                      <Button variant="success" className="flex-1 !py-6 font-black" onClick={() => judgeImposterGuess(true)}>CORRECT</Button>
                  </div>
              ) : (
                  <div className="flex flex-col items-center gap-4">
                      <Avatar seed={host?.avatarSeed || '0'} url={host?.avatarUrl} size="md" className="ring-2 ring-indigo-500 rounded-full mb-2" />
                      <p className="text-indigo-400 font-bold animate-pulse text-sm uppercase tracking-widest">Host verdict pending...</p>
                  </div>
              )}
          </div>
      );
  }

  return null;
};

