class AudioService {
  private music: HTMLAudioElement | null = null;
  private ctx: AudioContext | null = null;
  private isMuted: boolean = false;
  private musicUrl: string = 'https://assets.mixkit.co/music/preview/mixkit-mysterious-bass-and-synth-loop-2486.mp3';

  constructor() {
    this.isMuted = localStorage.getItem('game_muted') === 'true';
  }

  private initContext() {
    if (!this.ctx) {
      this.ctx = new (window.AudioContext || (window as any).webkitAudioContext)();
    }
  }

  toggleMute(): boolean {
    this.isMuted = !this.isMuted;
    localStorage.setItem('game_muted', String(this.isMuted));
    if (this.music) {
      this.music.muted = this.isMuted;
    }
    return this.isMuted;
  }

  getMuted(): boolean {
    return this.isMuted;
  }

  playMusic() {
    if (this.music) return;

    this.music = new Audio(this.musicUrl);
    this.music.loop = true;
    this.music.volume = 0.4;
    this.music.muted = this.isMuted;

    // Play on interaction
    const startPlay = () => {
      this.music?.play().catch(e => console.debug("Autoplay blocked", e));
      window.removeEventListener('click', startPlay);
      window.removeEventListener('touchstart', startPlay);
    };
    window.addEventListener('click', startPlay);
    window.addEventListener('touchstart', startPlay);
  }

  playSfx(type: 'click' | 'success' | 'danger' | 'pop') {
    if (this.isMuted) return;
    this.initContext();
    if (!this.ctx) return;

    const osc = this.ctx.createOscillator();
    const gain = this.ctx.createGain();

    osc.connect(gain);
    gain.connect(this.ctx.destination);

    const now = this.ctx.currentTime;

    if (type === 'click') {
      osc.type = 'sine';
      osc.frequency.setValueAtTime(800, now);
      osc.frequency.exponentialRampToValueAtTime(400, now + 0.1);
      gain.gain.setValueAtTime(0.1, now);
      gain.gain.exponentialRampToValueAtTime(0.01, now + 0.1);
      osc.start(now);
      osc.stop(now + 0.1);
    } else if (type === 'pop') {
      osc.type = 'triangle';
      osc.frequency.setValueAtTime(400, now);
      osc.frequency.exponentialRampToValueAtTime(600, now + 0.05);
      gain.gain.setValueAtTime(0.2, now);
      gain.gain.exponentialRampToValueAtTime(0.01, now + 0.1);
      osc.start(now);
      osc.stop(now + 0.1);
    } else if (type === 'success') {
      osc.type = 'sine';
      osc.frequency.setValueAtTime(523.25, now); // C5
      osc.frequency.exponentialRampToValueAtTime(659.25, now + 0.1); // E5
      gain.gain.setValueAtTime(0.1, now);
      gain.gain.exponentialRampToValueAtTime(0.01, now + 0.3);
      osc.start(now);
      osc.stop(now + 0.3);
    } else if (type === 'danger') {
      osc.type = 'sawtooth';
      osc.frequency.setValueAtTime(150, now);
      osc.frequency.linearRampToValueAtTime(100, now + 0.2);
      gain.gain.setValueAtTime(0.1, now);
      gain.gain.linearRampToValueAtTime(0.01, now + 0.2);
      osc.start(now);
      osc.stop(now + 0.2);
    }
  }
}

