class AudioService {
  private music: HTMLAudioElement | null = null;
  private ctx: AudioContext | null = null;
  private isMuted: boolean = false;
  // High-energy mysterious trap theme similar to the requested style
  private musicUrl: string = 'https://cdn.pixabay.com/audio/2022/01/18/audio_276943f650.mp3';

  constructor() {
    this.isMuted = localStorage.getItem('game_muted') === 'true';
  }

  private async initContext() {
    if (!this.ctx) {
      this.ctx = new (window.AudioContext || (window as any).webkitAudioContext)();
    }
    if (this.ctx.state === 'suspended') {
      await this.ctx.resume();
    }
  }

  toggleMute(): boolean {
    this.isMuted = !this.isMuted;
    localStorage.setItem('game_muted', String(this.isMuted));
    if (this.music) {
      this.music.muted = this.isMuted;
    }
    return this.isMuted;
  }

  getMuted(): boolean {
    return this.isMuted;
  }

  async playMusic() {
    if (this.music) {
      if (this.music.paused) {
        this.music.play().catch(() => {});
      }
      return;
    }

    this.music = new Audio(this.musicUrl);
    this.music.loop = true;
    this.music.volume = 0.3; // Slightly louder for the trap vibe
    this.music.muted = this.isMuted;

    const startPlay = async () => {
      await this.initContext();
      this.music?.play().catch(e => console.debug("Autoplay blocked", e));
      // Keep trying until successful or just let it trigger on interaction
    };

    // Multiple listeners to ensure we catch the first interaction
    window.addEventListener('click', startPlay, { once: true });
    window.addEventListener('touchstart', startPlay, { once: true });
    window.addEventListener('keydown', startPlay, { once: true });
  }

  async playSfx(type: 'click' | 'success' | 'danger' | 'pop' | 'reveal' | 'vote') {
    if (this.isMuted) return;
    await this.initContext();
    if (!this.ctx) return;

    const osc = this.ctx.createOscillator();
    const gain = this.ctx.createGain();

    osc.connect(gain);
    gain.connect(this.ctx.destination);

    const now = this.ctx.currentTime;

    switch(type) {
      case 'click':
        // Sharper, higher quality tactile "tick" sound
        osc.type = 'sine';
        osc.frequency.setValueAtTime(1200, now);
        osc.frequency.exponentialRampToValueAtTime(100, now + 0.05);
        gain.gain.setValueAtTime(0.15, now);
        gain.gain.exponentialRampToValueAtTime(0.01, now + 0.05);
        osc.start(now);
        osc.stop(now + 0.05);
        break;
      case 'pop':
        osc.type = 'triangle';
        osc.frequency.setValueAtTime(400, now);
        osc.frequency.exponentialRampToValueAtTime(800, now + 0.08);
        gain.gain.setValueAtTime(0.2, now);
        gain.gain.exponentialRampToValueAtTime(0.01, now + 0.1);
        osc.start(now);
        osc.stop(now + 0.1);
        break;
      case 'vote':
        osc.type = 'sine';
        osc.frequency.setValueAtTime(350, now);
        osc.frequency.exponentialRampToValueAtTime(150, now + 0.15);
        gain.gain.setValueAtTime(0.2, now);
        gain.gain.exponentialRampToValueAtTime(0.01, now + 0.2);
        osc.start(now);
        osc.stop(now + 0.2);
        break;
      case 'reveal':
        // Dramatic low frequency rumble
        const noise = this.ctx.createOscillator();
        noise.type = 'sawtooth';
        noise.frequency.setValueAtTime(80, now);
        noise.frequency.exponentialRampToValueAtTime(30, now + 1.2);
        const noiseGain = this.ctx.createGain();
        noise.connect(noiseGain);
        noiseGain.connect(this.ctx.destination);
        noiseGain.gain.setValueAtTime(0.3, now);
        noiseGain.gain.linearRampToValueAtTime(0, now + 1.2);
        noise.start(now);
        noise.stop(now + 1.2);
        break;
      case 'success':
        // Upward arpeggio
        osc.type = 'sine';
        osc.frequency.setValueAtTime(523, now);
        osc.frequency.setValueAtTime(659, now + 0.1);
        osc.frequency.setValueAtTime(783, now + 0.2);
        osc.frequency.exponentialRampToValueAtTime(1046, now + 0.4);
        gain.gain.setValueAtTime(0.15, now);
        gain.gain.exponentialRampToValueAtTime(0.01, now + 0.5);
        osc.start(now);
        osc.stop(now + 0.5);
        break;
      case 'danger':
        // Low discordant buzz
        osc.type = 'sawtooth';
        osc.frequency.setValueAtTime(120, now);
        osc.frequency.setValueAtTime(115, now + 0.1);
        gain.gain.setValueAtTime(0.15, now);
        gain.gain.linearRampToValueAtTime(0, now + 0.4);
        osc.start(now);
        osc.stop(now + 0.4);
        break;
    }
  }
}

