            <div className={`flex gap-3 ${!isNetworkHost ? 'opacity-60 pointer-events-none' : ''}`}>
                {(['IN_PERSON', 'PHONE'] as const).map(mode => (
                    <button 
                        key={mode}
                        onClick={() => handleConfigChange({ mode })}
                        className={`flex-1 p-3 rounded-xl font-bold border transition-all ${config.mode === mode ? 'border-indigo-500 bg-indigo-500/20 text-indigo-300 shadow-[0_0_15px_rgba(99,102,241,0.2)]' : 'border-slate-700 bg-slate-800/50 text-slate-500 hover:border-slate-600'}`}
                    >
                        {mode === 'IN_PERSON' ? 'Party' : 'Remote'}
                    </button>
                ))}
            </div>
        </div>

        <div className="space-y-3">
            <label className="text-xs font-bold text-slate-400 uppercase tracking-widest">Cycles (Rounds)</label>
            <div className={`flex gap-3 ${!isNetworkHost ? 'opacity-60 pointer-events-none' : ''}`}>
                {[1, 2, 3].map(num => (
                    <button 
                        key={num}
                        onClick={() => handleConfigChange({ cycles: num })}
                        className={`flex-1 p-3 rounded-xl font-bold border transition-all ${config.cycles === num ? 'border-game-accent bg-game-accent/20 text-game-accent shadow-[0_0_15px_rgba(139,92,246,0.2)]' : 'border-slate-700 bg-slate-800/50 text-slate-500 hover:border-slate-600'}`}
                    >
                        {num}
                    </button>
                ))}
            </div>
        </div>

        {isNetworkHost ? (
            <Button fullWidth disabled={players.length < 3} onClick={startGame} className="ring-offset-2 ring-offset-slate-900 focus:ring-2 ring-game-primary">
                {players.length < 3 ? `NEED ${3 - players.length} MORE` : "START GAME"}
            </Button>
        ) : (
            <div className="text-center p-5 text-slate-400 font-bold bg-slate-800/30 rounded-2xl border border-slate-700/50 animate-pulse uppercase tracking-widest text-xs">
              Waiting for host to launch...
            </div>
        )}
      </div>
    </div>
  );
};

import React, { createContext, useContext, useState, useEffect, useRef } from 'react';
import { GamePhase, GameState, Player, GameConfig, GameContextType } from '../types';
import Peer, { DataConnection } from 'peerjs';
import { audioService } from '../services/audioService';

type GameAction = 
  | { type: 'SYNC_STATE'; state: GameState }
  | { type: 'JOIN_REQUEST'; player: Player }
  | { type: 'UPDATE_CONFIG'; config: Partial<GameConfig> }
  | { type: 'START_GAME' }
  | { type: 'SET_TOPIC'; topic: string; category: string; image?: string; manualImposterIds?: string[] }
  | { type: 'SUBMIT_CLUE'; text: string }
  | { type: 'SUBMIT_VOTE'; voterId: string; votedForId: string }
  | { type: 'START_VOTING' }
  | { type: 'CONFIRM_STARTER' }
  | { type: 'START_IMPOSTER_GUESS' }
  | { type: 'SUBMIT_GUESS'; guess: string }
  | { type: 'JUDGE_GUESS'; isCorrect: boolean }
  | { type: 'ACK_ROUND_END'; playerId: string }
  | { type: 'RESET_GAME' }
  | { type: 'ADD_BOT' };

const GameContext = createContext<GameContextType | undefined>(undefined);

const INITIAL_STATE: GameState = {
  gameCode: '',
  phase: GamePhase.HOME,
  players: [],
  config: { mode: 'IN_PERSON', imposterCount: 1, cycles: 1 },
  currentTurnIndex: 0,
  clueRound: 1,
  currentHostId: null,
  hostIndex: 0,
  pastHostIds: [],
  currentCycle: 1,
  topic: '',
  category: '',
  clues: [],
  votes: {},
  imposterGuess: null,
  imposterGuessCorrect: null,
  winningPlayerId: null,
  nextPlayerTurnId: null,
};

// Using a more unique prefix to avoid signaling collisions with other users/games
const PEER_PREFIX = 'imposter-deduction-v2-prod-';

export const GameProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [state, setState] = useState<GameState>(INITIAL_STATE);
  const [isHost, setIsHost] = useState(false);
  const [myPlayerId, setMyPlayerId] = useState<string | null>(null);

  const peerRef = useRef<Peer | null>(null);
  const connectionsRef = useRef<DataConnection[]>([]);
  const hostConnRef = useRef<DataConnection | null>(null);

  useEffect(() => {
    const storedId = sessionStorage.getItem('imposter_playerId');
    if (storedId) setMyPlayerId(storedId);
  }, []);

  useEffect(() => {
    if (myPlayerId) sessionStorage.setItem('imposter_playerId', myPlayerId);
    if (state.gameCode) sessionStorage.setItem('imposter_gameCode', state.gameCode);
  }, [myPlayerId, state.gameCode]);

  useEffect(() => {
    if (state.phase !== GamePhase.HOME) {
        audioService.playMusic();
    }
  }, [state.phase]);

  const broadcastState = (newState: GameState) => {
    connectionsRef.current.forEach(conn => {
      if (conn.open) {
        conn.send({ type: 'SYNC_STATE', state: newState });
      }
    });
  };

  const processAction = (action: GameAction, currentState: GameState): GameState => {
    switch (action.type) {
        case 'JOIN_REQUEST':
            const existingIdx = currentState.players.findIndex(p => p.id === action.player.id);
            if (existingIdx !== -1) {
                const updatedPlayers = [...currentState.players];
                updatedPlayers[existingIdx] = {
                    ...updatedPlayers[existingIdx],
                    name: action.player.name || updatedPlayers[existingIdx].name,
                    avatarUrl: action.player.avatarUrl || updatedPlayers[existingIdx].avatarUrl
                };
                return { ...currentState, players: updatedPlayers };
            }
            return { ...currentState, players: [...currentState.players, action.player] };

        case 'UPDATE_CONFIG':
            return { ...currentState, config: { ...currentState.config, ...action.config } };

        case 'ADD_BOT': {
             audioService.playSfx('pop');
             const names = ["Unit-X", "Spark", "Gizmo", "Chip", "Bolt", "Nexus", "Circuit", "Pixel", "Droid", "Robo"];
             const botPlayer: Player = {
                id: "BOT-" + Math.random().toString(36).substr(2, 9),
                name: names[Math.floor(Math.random() * names.length)],
                avatarSeed: Math.random().toString(),
                isHost: false,
                isImposter: false,
                isBot: true,
                score: 0,
                voteCount: 0,
                isReady: true
             };
             return { ...currentState, players: [...currentState.players, botPlayer] };
        }

        case 'START_GAME': {
            audioService.playSfx('success');
            if (currentState.players.length < 3) return currentState;
            const randHostIdx = Math.floor(Math.random() * currentState.players.length);
            const hostId = currentState.players[randHostIdx].id;
            return {
                ...currentState,
                players: currentState.players.map(p => ({
                    ...p, isHost: p.id === hostId, isImposter: false, voteCount: 0, isReady: false, score: 0
                })),
                currentHostId: hostId,
                pastHostIds: [hostId],
                currentCycle: 1,
                phase: GamePhase.TOPIC_SELECTION,
                clues: [],
                votes: {},
                topic: '',
            };
        }

        case 'SET_TOPIC': {
            audioService.playSfx('pop');
            const hostId = currentState.currentHostId;
            const manualImposterIds = action.manualImposterIds || [];
            const players = [...currentState.players];
            const imposterIndices = new Set<number>();

            if (manualImposterIds.length > 0) {
                 manualImposterIds.forEach(id => {
                     const idx = players.findIndex(p => p.id === id);
                     if (idx !== -1) imposterIndices.add(idx);
                 });
            } else {
                 while (imposterIndices.size < currentState.config.imposterCount) {
                    const idx = Math.floor(Math.random() * players.length);
                    if (players[idx].id !== hostId && !imposterIndices.has(idx)) {
                        imposterIndices.add(idx);
                    }
                }
            }

            const newPlayers = players.map((p, idx) => ({
                ...p,
                isHost: p.id === hostId,
                isImposter: imposterIndices.has(idx),
                isReady: false
            }));

            // Implementation of weighted random selection for the starter
            // Give innocents a weight of 4 and imposters a weight of 1
            const eligibleStarters = newPlayers
                .map((p, idx) => ({ p, idx }))
                .filter(item => !item.p.isHost);

            const tickets: number[] = [];
            eligibleStarters.forEach(({ p, idx }) => {
                const count = p.isImposter ? 1 : 4; 
                for (let i = 0; i < count; i++) {
                    tickets.push(idx);
                }
            });

            const randomStarterIndex = tickets[Math.floor(Math.random() * tickets.length)];

            return {
                ...currentState,
                players: newPlayers,
                currentTurnIndex: randomStarterIndex,
                topic: action.topic,
                category: action.category,
                topicImage: action.image,
                phase: GamePhase.ROLE_REVEAL,
                imposterGuess: null,
                imposterGuessCorrect: null,
            };
        }

        case 'CONFIRM_STARTER':
            return { ...currentState, phase: GamePhase.DISCUSSION };

        case 'START_VOTING':
             audioService.playSfx('danger');
             return { ...currentState, phase: GamePhase.VOTING };

        case 'SUBMIT_CLUE': {
            audioService.playSfx('pop');
            const currentPlayer = currentState.players[currentState.currentTurnIndex];
            const newClues = [...currentState.clues, { playerId: currentPlayer.id, text: action.text, timestamp: Date.now() }];
            const activePlayerCount = currentState.players.length - 1;
            const totalCluesNeeded = activePlayerCount * 2;

            let nIdx = (currentState.currentTurnIndex + 1) % currentState.players.length;
            let nRound = currentState.clueRound;
            let nClues = [...newClues];

            while(true) {
                const p = currentState.players[nIdx];
                if (nClues.length >= totalCluesNeeded) break;
                if (p.isHost) {
                    nIdx = (nIdx + 1) % currentState.players.length;
                    continue;
                }
                if (p.isBot) {
                    nClues.push({ playerId: p.id, text: `...`, timestamp: Date.now() });
                    nIdx = (nIdx + 1) % currentState.players.length;
                    continue;
                }
                break;
            }

            if (nClues.length >= totalCluesNeeded) {
                 return { ...currentState, clues: nClues, phase: GamePhase.VOTING };
            }

            if (nClues.length >= activePlayerCount) nRound = 2;

            return {
                ...currentState,
                clues: nClues,
                currentTurnIndex: nIdx,
                clueRound: nRound,
                phase: GamePhase.CLUES
            };
        }

        case 'SUBMIT_VOTE': {
            audioService.playSfx('vote');
            const newVotes = { ...currentState.votes, [action.voterId]: action.votedForId };
            const votingHumans = currentState.players.filter(p => !p.isBot && !p.isHost);
            const humansWhoVoted = votingHumans.filter(h => newVotes[h.id]);

            if (humansWhoVoted.length === votingHumans.length) {
                const finalVotes = simulateBotVotes(currentState.players, currentState.config.imposterCount, newVotes);
                const updatedPlayers = currentState.players.map(p => {
                    const votesReceived = Object.values(finalVotes).filter(id => id === p.id).length;
                    return { ...p, voteCount: votesReceived };
                });
                return { ...currentState, players: updatedPlayers, votes: finalVotes, phase: GamePhase.REVEAL };
            }
            return { ...currentState, votes: newVotes };
        }

        case 'START_IMPOSTER_GUESS':
             return { ...currentState, phase: GamePhase.IMPOSTER_GUESS };

        case 'SUBMIT_GUESS':
             audioService.playSfx('pop');
             return { ...currentState, imposterGuess: action.guess, phase: GamePhase.HOST_REVIEW };

        case 'JUDGE_GUESS': {
            if (action.isCorrect) audioService.playSfx('success');
            else audioService.playSfx('danger');

            const imposter = currentState.players.find(p => p.isImposter);
            if (!imposter) return currentState;

            let maxVotes = 0;
            currentState.players.forEach(p => { if(p.voteCount > maxVotes) maxVotes = p.voteCount; });
            const accusedPlayers = currentState.players.filter(p => p.voteCount === maxVotes);
            const majorityVotedForImposter = accusedPlayers.some(p => p.id === imposter.id);

            const newPlayers = currentState.players.map(p => {
                let roundPoints = 0;
                if (p.isHost) return p;
                if (p.isImposter) {
                    if (!majorityVotedForImposter) roundPoints += 2;
                    if (action.isCorrect) roundPoints += 1;
                } else {
                    const theirVote = currentState.votes[p.id];
                    if (theirVote === imposter.id) roundPoints += 1;
                }
                return { ...p, score: p.score + roundPoints, isReady: false };
            });

            return { ...currentState, players: newPlayers, imposterGuessCorrect: action.isCorrect, phase: GamePhase.SCOREBOARD };
        }

        case 'ACK_ROUND_END': {
             audioService.playSfx('click');
             const updatedPlayers = currentState.players.map(p => (p.id === action.playerId) ? { ...p, isReady: !p.isReady } : p);
             const readyCount = updatedPlayers.filter(p => p.isReady || p.isBot).length;

             if (readyCount === updatedPlayers.length) {
                if (currentState.phase === GamePhase.ROLE_REVEAL) {
                    return {
                        ...currentState,
                        players: updatedPlayers.map(p => ({ ...p, isReady: false })), 
                        phase: currentState.config.mode === 'IN_PERSON' ? GamePhase.ROUND_STARTER : GamePhase.CLUES
                    };
                }

                let nextPastHosts = [...currentState.pastHostIds];
                let nextCycle = currentState.currentCycle;
                let availableHosts = currentState.players.filter(p => !nextPastHosts.includes(p.id));

                if (availableHosts.length === 0) {
                    if (nextCycle < currentState.config.cycles) {
                        nextCycle += 1;
                        nextPastHosts = [];
                        availableHosts = [...currentState.players];
                    } else {
                        const sorted = [...updatedPlayers].sort((a,b) => b.score - a.score);
                        return { ...currentState, players: updatedPlayers, winningPlayerId: sorted[0].id, phase: GamePhase.WINNER };
                    }
                }

                const nextHost = availableHosts[Math.floor(Math.random() * availableHosts.length)];
                return {
                    ...currentState,
                    players: updatedPlayers.map(p => ({ ...p, isHost: p.id === nextHost.id, isImposter: false, isReady: false, voteCount: 0 })),
                    currentHostId: nextHost.id,
                    pastHostIds: [...nextPastHosts, nextHost.id],
                    currentCycle: nextCycle,
                    phase: GamePhase.TOPIC_SELECTION,
                    clues: [],
                    votes: {},
                    topic: '',
                    imposterGuess: null,
                    imposterGuessCorrect: null,
                };
             }
             return { ...currentState, players: updatedPlayers };
        }

        case 'RESET_GAME':
             return { ...INITIAL_STATE, gameCode: currentState.gameCode, phase: GamePhase.LOBBY, players: [] };

        default:
            return currentState;
    }
  };

  const simulateBotVotes = (allPlayers: Player[], imposterCount: number, existingVotes: Record<string,string>): Record<string, string> => {
    const votes: Record<string, string> = { ...existingVotes };
    const candidates = allPlayers.filter(p => !p.isHost);
    allPlayers.filter(p => p.isBot && !p.isHost).forEach(bot => {
        if (votes[bot.id]) return;
        const otherCandidates = candidates.filter(c => c.id !== bot.id);
        const target = otherCandidates[Math.floor(Math.random() * otherCandidates.length)];
        if (target) votes[bot.id] = target.id;
    });
    return votes;
  };

  const dispatch = (action: GameAction) => {
    if (isHost) {
        const newState = processAction(action, state);
        setState(newState);
        broadcastState(newState);
    } else if (hostConnRef.current && hostConnRef.current.open) {
        hostConnRef.current.send(action);
    }
  };

  const createGame = (name: string, avatarUrl?: string) => {
    return new Promise<void>((resolve, reject) => {
        if (peerRef.current) peerRef.current.destroy();

        const code = Math.random().toString(36).substring(2, 7).toUpperCase();
        const playerId = Math.random().toString(36).substr(2, 9);
        const peer = new Peer(PEER_PREFIX + code);

        peer.on('open', () => {
            setIsHost(true);
            setMyPlayerId(playerId);
            const creatorPlayer: Player = {
                id: playerId, name, avatarSeed: Math.random().toString(), avatarUrl,
                isHost: false, isImposter: false, isBot: false, score: 0, voteCount: 0, isReady: false
            };
            setState({ ...INITIAL_STATE, gameCode: code, phase: GamePhase.LOBBY, players: [creatorPlayer] });
            peerRef.current = peer;
            resolve();
        });

        peer.on('error', (err) => {
            reject(new Error("Code already in use or network error. Try again."));
        });

        peer.on('connection', (conn) => {
            connectionsRef.current.push(conn);
            conn.on('data', (data: any) => {
                setState(current => {
                    const updated = processAction(data as GameAction, current);
                    connectionsRef.current.forEach(c => { if (c.open) c.send({ type: 'SYNC_STATE', state: updated }); });
                    return updated;
                });
            });
            setState(current => {
                conn.send({ type: 'SYNC_STATE', state: current });
                return current;
            });
        });
    });
  };

  const joinGame = (code: string, name: string, avatarUrl?: string) => {
    return new Promise<void>((resolve, reject) => {
        if (peerRef.current) peerRef.current.destroy();

        const playerId = sessionStorage.getItem('imposter_playerId') || Math.random().toString(36).substr(2, 9);
        const peer = new Peer(); 

        const timeout = setTimeout(() => {
            peer.destroy();
            reject(new Error("Connection timed out. Game host might be offline."));
        }, 12000);

        peer.on('open', () => {
            const conn = peer.connect(PEER_PREFIX + code.toUpperCase(), {
              reliable: true
            });

            conn.on('open', () => {
                clearTimeout(timeout);
                hostConnRef.current = conn;
                setIsHost(false);
                setMyPlayerId(playerId);
                peerRef.current = peer;

                const player: Player = {
                    id: playerId, name, avatarSeed: Math.random().toString(),
                    avatarUrl: avatarUrl, isHost: false, isImposter: false, isBot: false, score: 0, voteCount: 0, isReady: false
                };
                conn.send({ type: 'JOIN_REQUEST', player });
                resolve();
            });

            conn.on('data', (data: any) => { 
                if (data.type === 'SYNC_STATE') setState(data.state); 
            });

            conn.on('error', () => {
                clearTimeout(timeout);
                reject(new Error("Network connection lost."));
            });
        });

        peer.on('error', (err) => {
            clearTimeout(timeout);
            reject(new Error("Network error occurred: " + err.type));
        });
    });
  };

  const reconnectGame = (code: string, playerId: string) => {
      if (peerRef.current) peerRef.current.destroy();
      const peer = new Peer();
      peer.on('open', () => {
          const conn = peer.connect(PEER_PREFIX + code.toUpperCase(), {
            reliable: true
          });
          conn.on('open', () => {
              hostConnRef.current = conn;
              setIsHost(false);
              setMyPlayerId(playerId);
              peerRef.current = peer;
              conn.on('data', (data: any) => { if (data.type === 'SYNC_STATE') setState(data.state); });
          });
      });
  };

  const updateConfig = (config: Partial<GameConfig>) => dispatch({ type: 'UPDATE_CONFIG', config });
  const startGame = () => dispatch({ type: 'START_GAME' });
  const addBot = () => dispatch({ type: 'ADD_BOT' });
  const setTopic = (topic: string, category: string, image?: string, manualImposterIds?: string[]) => dispatch({ type: 'SET_TOPIC', topic, category, image, manualImposterIds });
  const finishRoleReveal = () => myPlayerId && dispatch({ type: 'ACK_ROUND_END', playerId: myPlayerId });
  const confirmStarter = () => dispatch({ type: 'CONFIRM_STARTER' });
  const startVoting = () => dispatch({ type: 'START_VOTING' });
  const confirmPassDevice = () => { };
  const startImposterGuess = () => dispatch({ type: 'START_IMPOSTER_GUESS' });
  const submitClue = (text: string) => dispatch({ type: 'SUBMIT_CLUE', text });
  const submitVote = (voterId: string, votedForId: string) => dispatch({ type: 'SUBMIT_VOTE', voterId, votedForId });
  const submitImposterGuess = (guess: string) => dispatch({ type: 'SUBMIT_GUESS', guess });
  const judgeImposterGuess = (isCorrect: boolean) => dispatch({ type: 'JUDGE_GUESS', isCorrect });
  const acknowledgeRoundEnd = (playerId: string) => dispatch({ type: 'ACK_ROUND_END', playerId });
  const resetGame = () => dispatch({ type: 'RESET_GAME' });

  const amIGameHost = !!state.currentHostId && state.currentHostId === myPlayerId;

  return (
    <GameContext.Provider value={{
      state, isHost, isNetworkHost: isHost, myPlayerId, amIGameHost, createGame, joinGame, reconnectGame, updateConfig, startGame, setTopic, submitClue, submitVote, submitImposterGuess, judgeImposterGuess, acknowledgeRoundEnd, resetGame, addBot, confirmPassDevice,
      finishRoleReveal, startVoting, confirmStarter, startImposterGuess
    }}>
      {children}
    </GameContext.Provider>
  );
};

export const useGame = () => {
  const context = useContext(GameContext);
  if (!context) throw new Error("useGame must be used within a GameProvider");
  return context;
};

import React from 'react';
import { useGame } from '../context/GameContext';
import { Button } from '../components/Button';
import { Avatar } from '../components/Avatar';
import { GameConfig } from '../types';

export const LobbyScreen: React.FC = () => {
  const { state, updateConfig, startGame, addBot, isNetworkHost } = useGame();
  const { players, config, gameCode } = state;

  const handleConfigChange = (updates: Partial<GameConfig>) => {
    if (!isNetworkHost) return;
    updateConfig(updates);
  };

  const handleShare = async () => {
      const currentUrl = new URL(window.location.href);
      currentUrl.searchParams.set('code', gameCode);
      const shareUrl = currentUrl.toString();
      try {
          if (navigator.share) {
              await navigator.share({ title: 'Join Imposter', url: shareUrl });
          } else {
              await navigator.clipboard.writeText(shareUrl);
              alert(`Link copied!`);
          }
      } catch (err) {
          await navigator.clipboard.writeText(shareUrl);
          alert(`Link copied!`);
      }
  };

  return (
    <div className="min-h-screen flex flex-col p-6 max-w-2xl mx-auto">
      <div className="flex justify-between items-center mb-6 bg-slate-900/40 p-4 rounded-2xl backdrop-blur-md border border-white/10">
        <div>
          <span className="text-slate-400 text-xs font-bold tracking-widest uppercase">Room Code</span>
          <h2 className="text-4xl font-mono font-black text-white">{gameCode}</h2>
        </div>
        <Button variant="secondary" className="!py-2 !px-4 text-xs font-bold" onClick={handleShare}>SHARE LINK</Button>
      </div>

      <div className="flex-1 overflow-y-auto mb-6">
        <div className="flex justify-between items-end mb-6">
             <h3 className="text-indigo-200 font-bold uppercase text-sm tracking-widest">Crew ({players.length})</h3>
             {isNetworkHost && (
                 <button 
                  onClick={addBot} 
                  className="text-xs bg-indigo-500/20 text-indigo-300 px-4 py-2 rounded-full border border-indigo-500/30 hover:bg-indigo-500/30 transition-colors font-bold uppercase"
                 >
                  + Add Bot
                 </button>
             )}
        </div>
        <div className="grid grid-cols-3 gap-y-8 gap-x-4 pb-8">
          {players.map(p => (
            <div key={p.id} className="animate-bounce-in">
              <Avatar 
                seed={p.avatarSeed} 
                url={p.avatarUrl} 
                name={p.name} 
                size="md" 
                className="transform hover:scale-110 transition-transform cursor-default"
              />
            </div>
          ))}
        </div>
      </div>

      <div className="bg-slate-900/60 p-6 rounded-3xl border border-white/10 space-y-6 shadow-2xl backdrop-blur-xl">
        <div className="space-y-3">
            <label className="text-xs font-bold text-slate-400 uppercase tracking-widest">Game Style</label>
            <div className={`flex gap-3 ${!isNetworkHost ? 'opacity-60 pointer-events-none' : ''}`}>
                {(['IN_PERSON', 'PHONE'] as const).map(mode => (
                    <button 
                        key={mode}
                        onClick={() => handleConfigChange({ mode })}
                        className={`flex-1 p-3 rounded-xl font-bold border transition-all ${config.mode === mode ? 'border-indigo-500 bg-indigo-500/20 text-indigo-300 shadow-[0_0_15px_rgba(99,102,241,0.2)]' : 'border-slate-700 bg-slate-800/50 text-slate-500 hover:border-slate-600'}`}
                    >
                        {mode === 'IN_PERSON' ? 'Party' : 'Remote'}
                    </button>
                ))}
            </div>
        </div>

        <div className="space-y-3">
            <label className="text-xs font-bold text-slate-400 uppercase tracking-widest">Cycles (Rounds)</label>
            <div className={`flex gap-3 ${!isNetworkHost ? 'opacity-60 pointer-events-none' : ''}`}>
                {[1, 2, 3].map(num => (
                    <button 
                        key={num}
                        onClick={() => handleConfigChange({ cycles: num })}
                        className={`flex-1 p-3 rounded-xl font-bold border transition-all ${config.cycles === num ? 'border-game-accent bg-game-accent/20 text-game-accent shadow-[0_0_15px_rgba(139,92,246,0.2)]' : 'border-slate-700 bg-slate-800/50 text-slate-500 hover:border-slate-600'}`}
                    >
                        {num}
                    </button>
                ))}
            </div>
        </div>

        {isNetworkHost ? (
            <Button fullWidth disabled={players.length < 3} onClick={startGame} className="ring-offset-2 ring-offset-slate-900 focus:ring-2 ring-game-primary">
                {players.length < 3 ? `NEED ${3 - players.length} MORE` : "START GAME"}
            </Button>
        ) : (
            <div className="text-center p-5 text-slate-400 font-bold bg-slate-800/30 rounded-2xl border border-slate-700/50 animate-pulse uppercase tracking-widest text-xs">
              Waiting for host to launch...
            </div>
        )}
      </div>
    </div>
  );
};

import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });

export const generateGameTopic = async (): Promise<string> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: "Generate a single, interesting, specific noun or short phrase suitable for a game of 'Imposter'. Examples: 'The Eiffel Tower', 'Sushi', 'Mars Landing'. Return ONLY the phrase, no quotes.",
      config: {
        maxOutputTokens: 20,
        temperature: 1.0,
      }
    });

    return response.text.trim();
  } catch (error) {
    console.error("Failed to generate topic", error);
    return "The Ocean"; // Fallback
  }
};

export const generateClue = async (role: 'INNOCENT' | 'IMPOSTER', topic: string, category: string): Promise<string> => {
    try {
        const prompt = role === 'INNOCENT' 
            ? `You are playing a game called 'Imposter'. The secret topic is '${topic}' in the category '${category}'. Give a one-word or very short phrase clue that proves you know the topic without being TOO obvious. Do not use the word '${topic}' itself.`
            : `You are playing 'Imposter'. You DON'T know the secret topic, only that the category is '${category}'. Give a vague but confident one-word or short phrase clue related to '${category}' to try and blend in.`;

        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
            config: {
                maxOutputTokens: 15,
                temperature: 0.8,
            }
        });

        return response.text.trim().replace(/['"().]/g, '');
    } catch (error) {
        console.error("Failed to generate bot clue", error);
        return "Interesting...";
    }
};

import React, { createContext, useContext, useState, useEffect, useRef } from 'react';
import { GamePhase, GameState, Player, GameConfig, GameContextType } from '../types';
import Peer, { DataConnection } from 'peerjs';
import { audioService } from '../services/audioService';
import { generateClue } from '../services/geminiService';

type GameAction = 
  | { type: 'SYNC_STATE'; state: GameState }
  | { type: 'JOIN_REQUEST'; player: Player }
  | { type: 'UPDATE_CONFIG'; config: Partial<GameConfig> }
  | { type: 'START_GAME' }
  | { type: 'SET_TOPIC'; topic: string; category: string; image?: string; manualImposterIds?: string[] }
  | { type: 'SUBMIT_CLUE'; text: string }
  | { type: 'SUBMIT_VOTE'; voterId: string; votedForId: string }
  | { type: 'START_VOTING' }
  | { type: 'CONFIRM_STARTER' }
  | { type: 'START_IMPOSTER_GUESS' }
  | { type: 'SUBMIT_GUESS'; guess: string }
  | { type: 'JUDGE_GUESS'; isCorrect: boolean }
  | { type: 'ACK_ROUND_END'; playerId: string }
  | { type: 'RESET_GAME' }
  | { type: 'ADD_BOT' };

const GameContext = createContext<GameContextType | undefined>(undefined);

const INITIAL_STATE: GameState = {
  gameCode: '',
  phase: GamePhase.HOME,
  players: [],
  config: { mode: 'IN_PERSON', imposterCount: 1, cycles: 1 },
  currentTurnIndex: 0,
  clueRound: 1,
  currentHostId: null,
  hostIndex: 0,
  pastHostIds: [],
  currentCycle: 1,
  topic: '',
  category: '',
  clues: [],
  votes: {},
  imposterGuess: null,
  imposterGuessCorrect: null,
  winningPlayerId: null,
  nextPlayerTurnId: null,
};

const PEER_PREFIX = 'imposter-deduction-v2-prod-';

export const GameProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [state, setState] = useState<GameState>(INITIAL_STATE);
  const [isHost, setIsHost] = useState(false);
  const [myPlayerId, setMyPlayerId] = useState<string | null>(null);

  const peerRef = useRef<Peer | null>(null);
  const connectionsRef = useRef<DataConnection[]>([]);
  const hostConnRef = useRef<DataConnection | null>(null);

  // Bot Auto-Action Logic (Only the network host handles this)
  useEffect(() => {
    if (!isHost) return;

    // Phase: Role Reveal - Bots are always ready
    if (state.phase === GamePhase.ROLE_REVEAL) {
        const botsToReady = state.players.filter(p => p.isBot && !p.isReady);
        if (botsToReady.length > 0) {
            // Give humans a moment to read
            const timer = setTimeout(() => {
                botsToReady.forEach(bot => dispatch({ type: 'ACK_ROUND_END', playerId: bot.id }));
            }, 2000);
            return () => clearTimeout(timer);
        }
    }

    // Phase: Clues - Bots think and speak
    if (state.phase === GamePhase.CLUES) {
        const currentPlayer = state.players[state.currentTurnIndex];
        if (currentPlayer && currentPlayer.isBot) {
            const timer = setTimeout(async () => {
                const role = currentPlayer.isImposter ? 'IMPOSTER' : 'INNOCENT';
                const clueText = await generateClue(role, state.topic, state.category);
                dispatch({ type: 'SUBMIT_CLUE', text: clueText });
            }, 3000); // 3 second "thinking" time
            return () => clearTimeout(timer);
        }
    }

    // Phase: Scoreboard - Bots ready up
    if (state.phase === GamePhase.SCOREBOARD) {
        const botsToReady = state.players.filter(p => p.isBot && !p.isReady);
        if (botsToReady.length > 0) {
            const timer = setTimeout(() => {
                botsToReady.forEach(bot => dispatch({ type: 'ACK_ROUND_END', playerId: bot.id }));
            }, 1500);
            return () => clearTimeout(timer);
        }
    }
  }, [state.phase, state.currentTurnIndex, isHost, state.players]);

  useEffect(() => {
    const storedId = sessionStorage.getItem('imposter_playerId');
    if (storedId) setMyPlayerId(storedId);
  }, []);

  useEffect(() => {
    if (myPlayerId) sessionStorage.setItem('imposter_playerId', myPlayerId);
    if (state.gameCode) sessionStorage.setItem('imposter_gameCode', state.gameCode);
  }, [myPlayerId, state.gameCode]);

  useEffect(() => {
    if (state.phase !== GamePhase.HOME) {
        audioService.playMusic();
    }
  }, [state.phase]);

  const broadcastState = (newState: GameState) => {
    connectionsRef.current.forEach(conn => {
      if (conn.open) {
        conn.send({ type: 'SYNC_STATE', state: newState });
      }
    });
  };

  const processAction = (action: GameAction, currentState: GameState): GameState => {
    switch (action.type) {
        case 'JOIN_REQUEST':
            const existingIdx = currentState.players.findIndex(p => p.id === action.player.id);
            if (existingIdx !== -1) {
                const updatedPlayers = [...currentState.players];
                updatedPlayers[existingIdx] = {
                    ...updatedPlayers[existingIdx],
                    name: action.player.name || updatedPlayers[existingIdx].name,
                    avatarUrl: action.player.avatarUrl || updatedPlayers[existingIdx].avatarUrl
                };
                return { ...currentState, players: updatedPlayers };
            }
            return { ...currentState, players: [...currentState.players, action.player] };

        case 'UPDATE_CONFIG':
            return { ...currentState, config: { ...currentState.config, ...action.config } };

        case 'ADD_BOT': {
             audioService.playSfx('pop');
             const names = ["Unit-X", "Spark", "Gizmo", "Chip", "Bolt", "Nexus", "Circuit", "Pixel", "Droid", "Robo"];
             const botPlayer: Player = {
                id: "BOT-" + Math.random().toString(36).substr(2, 9),
                name: names[Math.floor(Math.random() * names.length)],
                avatarSeed: Math.random().toString(),
                isHost: false,
                isImposter: false,
                isBot: true,
                score: 0,
                voteCount: 0,
                isReady: false // Start unready for the reveal phase logic
             };
             return { ...currentState, players: [...currentState.players, botPlayer] };
        }

        case 'START_GAME': {
            audioService.playSfx('success');
            if (currentState.players.length < 3) return currentState;
            const randHostIdx = Math.floor(Math.random() * currentState.players.length);
            const hostId = currentState.players[randHostIdx].id;
            return {
                ...currentState,
                players: currentState.players.map(p => ({
                    ...p, isHost: p.id === hostId, isImposter: false, voteCount: 0, isReady: false, score: 0
                })),
                currentHostId: hostId,
                pastHostIds: [hostId],
                currentCycle: 1,
                phase: GamePhase.TOPIC_SELECTION,
                clues: [],
                votes: {},
                topic: '',
            };
        }

        case 'SET_TOPIC': {
            audioService.playSfx('pop');
            const hostId = currentState.currentHostId;
            const manualImposterIds = action.manualImposterIds || [];
            const players = [...currentState.players];
            const imposterIndices = new Set<number>();

            if (manualImposterIds.length > 0) {
                 manualImposterIds.forEach(id => {
                     const idx = players.findIndex(p => p.id === id);
                     if (idx !== -1) imposterIndices.add(idx);
                 });
            } else {
                 while (imposterIndices.size < currentState.config.imposterCount) {
                    const idx = Math.floor(Math.random() * players.length);
                    if (players[idx].id !== hostId && !imposterIndices.has(idx)) {
                        imposterIndices.add(idx);
                    }
                }
            }

            const newPlayers = players.map((p, idx) => ({
                ...p,
                isHost: p.id === hostId,
                isImposter: imposterIndices.has(idx),
                isReady: false
            }));

            const eligibleStarters = newPlayers
                .map((p, idx) => ({ p, idx }))
                .filter(item => !item.p.isHost);

            const tickets: number[] = [];
            eligibleStarters.forEach(({ p, idx }) => {
                const count = p.isImposter ? 1 : 4; 
                for (let i = 0; i < count; i++) {
                    tickets.push(idx);
                }
            });

            const randomStarterIndex = tickets[Math.floor(Math.random() * tickets.length)];

            return {
                ...currentState,
                players: newPlayers,
                currentTurnIndex: randomStarterIndex,
                topic: action.topic,
                category: action.category,
                topicImage: action.image,
                phase: GamePhase.ROLE_REVEAL,
                imposterGuess: null,
                imposterGuessCorrect: null,
            };
        }

        case 'CONFIRM_STARTER':
            return { ...currentState, phase: GamePhase.DISCUSSION };

        case 'START_VOTING':
             audioService.playSfx('danger');
             return { ...currentState, phase: GamePhase.VOTING };

        case 'SUBMIT_CLUE': {
            audioService.playSfx('pop');
            const currentPlayer = currentState.players[currentState.currentTurnIndex];
            const newClues = [...currentState.clues, { playerId: currentPlayer.id, text: action.text, timestamp: Date.now() }];
            const activePlayerCount = currentState.players.length - 1;
            const totalCluesNeeded = activePlayerCount * 2;

            let nIdx = (currentState.currentTurnIndex + 1) % currentState.players.length;
            let nRound = currentState.clueRound;

            // Skip the host
            if (currentState.players[nIdx].isHost) {
                nIdx = (nIdx + 1) % currentState.players.length;
            }

            if (newClues.length >= totalCluesNeeded) {
                 return { ...currentState, clues: newClues, phase: GamePhase.VOTING };
            }

            if (newClues.length >= activePlayerCount) nRound = 2;

            return {
                ...currentState,
                clues: newClues,
                currentTurnIndex: nIdx,
                clueRound: nRound,
                phase: GamePhase.CLUES
            };
        }

        case 'SUBMIT_VOTE': {
            audioService.playSfx('vote');
            const newVotes = { ...currentState.votes, [action.voterId]: action.votedForId };
            const votingHumans = currentState.players.filter(p => !p.isBot && !p.isHost);
            const humansWhoVoted = votingHumans.filter(h => newVotes[h.id]);

            if (humansWhoVoted.length === votingHumans.length) {
                const finalVotes = simulateBotVotes(currentState.players, currentState.config.imposterCount, newVotes);
                const updatedPlayers = currentState.players.map(p => {
                    const votesReceived = Object.values(finalVotes).filter(id => id === p.id).length;
                    return { ...p, voteCount: votesReceived };
                });
                return { ...currentState, players: updatedPlayers, votes: finalVotes, phase: GamePhase.REVEAL };
            }
            return { ...currentState, votes: newVotes };
        }

        case 'START_IMPOSTER_GUESS':
             return { ...currentState, phase: GamePhase.IMPOSTER_GUESS };

        case 'SUBMIT_GUESS':
             audioService.playSfx('pop');
             return { ...currentState, imposterGuess: action.guess, phase: GamePhase.HOST_REVIEW };

        case 'JUDGE_GUESS': {
            if (action.isCorrect) audioService.playSfx('success');
            else audioService.playSfx('danger');

            const imposter = currentState.players.find(p => p.isImposter);
            if (!imposter) return currentState;

            let maxVotes = 0;
            currentState.players.forEach(p => { if(p.voteCount > maxVotes) maxVotes = p.voteCount; });
            const accusedPlayers = currentState.players.filter(p => p.voteCount === maxVotes);
            const majorityVotedForImposter = accusedPlayers.some(p => p.id === imposter.id);

            const newPlayers = currentState.players.map(p => {
                let roundPoints = 0;
                if (p.isHost) return p;
                if (p.isImposter) {
                    if (!majorityVotedForImposter) roundPoints += 2;
                    if (action.isCorrect) roundPoints += 1;
                } else {
                    const theirVote = currentState.votes[p.id];
                    if (theirVote === imposter.id) roundPoints += 1;
                }
                return { ...p, score: p.score + roundPoints, isReady: false };
            });

            return { ...currentState, players: newPlayers, imposterGuessCorrect: action.isCorrect, phase: GamePhase.SCOREBOARD };
        }

        case 'ACK_ROUND_END': {
             audioService.playSfx('click');
             const updatedPlayers = currentState.players.map(p => (p.id === action.playerId) ? { ...p, isReady: !p.isReady } : p);
             const readyCount = updatedPlayers.filter(p => p.isReady).length;

             if (readyCount === updatedPlayers.length) {
                if (currentState.phase === GamePhase.ROLE_REVEAL) {
                    return {
                        ...currentState,
                        players: updatedPlayers.map(p => ({ ...p, isReady: false })), 
                        phase: currentState.config.mode === 'IN_PERSON' ? GamePhase.ROUND_STARTER : GamePhase.CLUES
                    };
                }

                let nextPastHosts = [...currentState.pastHostIds];
                let nextCycle = currentState.currentCycle;
                let availableHosts = currentState.players.filter(p => !nextPastHosts.includes(p.id));

                if (availableHosts.length === 0) {
                    if (nextCycle < currentState.config.cycles) {
                        nextCycle += 1;
                        nextPastHosts = [];
                        availableHosts = [...currentState.players];
                    } else {
                        const sorted = [...updatedPlayers].sort((a,b) => b.score - a.score);
                        return { ...currentState, players: updatedPlayers, winningPlayerId: sorted[0].id, phase: GamePhase.WINNER };
                    }
                }

                const nextHost = availableHosts[Math.floor(Math.random() * availableHosts.length)];
                return {
                    ...currentState,
                    players: updatedPlayers.map(p => ({ ...p, isHost: p.id === nextHost.id, isImposter: false, isReady: false, voteCount: 0 })),
                    currentHostId: nextHost.id,
                    pastHostIds: [...nextPastHosts, nextHost.id],
                    currentCycle: nextCycle,
                    phase: GamePhase.TOPIC_SELECTION,
                    clues: [],
                    votes: {},
                    topic: '',
                    imposterGuess: null,
                    imposterGuessCorrect: null,
                };
             }
             return { ...currentState, players: updatedPlayers };
        }

        case 'RESET_GAME':
             return { ...INITIAL_STATE, gameCode: currentState.gameCode, phase: GamePhase.LOBBY, players: [] };

        default:
            return currentState;
    }
  };

  const simulateBotVotes = (allPlayers: Player[], imposterCount: number, existingVotes: Record<string,string>): Record<string, string> => {
    const votes: Record<string, string> = { ...existingVotes };
    const candidates = allPlayers.filter(p => !p.isHost);
    allPlayers.filter(p => p.isBot && !p.isHost).forEach(bot => {
        if (votes[bot.id]) return;
        const otherCandidates = candidates.filter(c => c.id !== bot.id);
        const target = otherCandidates[Math.floor(Math.random() * otherCandidates.length)];
        if (target) votes[bot.id] = target.id;
    });
    return votes;
  };

  const dispatch = (action: GameAction) => {
    if (isHost) {
        const newState = processAction(action, state);
        setState(newState);
        broadcastState(newState);
    } else if (hostConnRef.current && hostConnRef.current.open) {
        hostConnRef.current.send(action);
    }
  };

  const createGame = (name: string, avatarUrl?: string) => {
    return new Promise<void>((resolve, reject) => {
        if (peerRef.current) peerRef.current.destroy();

        const code = Math.random().toString(36).substring(2, 7).toUpperCase();
        const playerId = Math.random().toString(36).substr(2, 9);
        const peer = new Peer(PEER_PREFIX + code);

        peer.on('open', () => {
            setIsHost(true);
            setMyPlayerId(playerId);
            const creatorPlayer: Player = {
                id: playerId, name, avatarSeed: Math.random().toString(), avatarUrl,
                isHost: false, isImposter: false, isBot: false, score: 0, voteCount: 0, isReady: false
            };
            setState({ ...INITIAL_STATE, gameCode: code, phase: GamePhase.LOBBY, players: [creatorPlayer] });
            peerRef.current = peer;
            resolve();
        });

        peer.on('error', (err) => {
            reject(new Error("Code already in use or network error. Try again."));
        });

        peer.on('connection', (conn) => {
            connectionsRef.current.push(conn);
            conn.on('data', (data: any) => {
                setState(current => {
                    const updated = processAction(data as GameAction, current);
                    connectionsRef.current.forEach(c => { if (c.open) c.send({ type: 'SYNC_STATE', state: updated }); });
                    return updated;
                });
            });
            setState(current => {
                conn.send({ type: 'SYNC_STATE', state: current });
                return current;
            });
        });
    });
  };

  const joinGame = (code: string, name: string, avatarUrl?: string) => {
    return new Promise<void>((resolve, reject) => {
        if (peerRef.current) peerRef.current.destroy();

        const playerId = sessionStorage.getItem('imposter_playerId') || Math.random().toString(36).substr(2, 9);
        const peer = new Peer(); 

        const timeout = setTimeout(() => {
            peer.destroy();
            reject(new Error("Connection timed out. Game host might be offline."));
        }, 12000);

        peer.on('open', () => {
            const conn = peer.connect(PEER_PREFIX + code.toUpperCase(), {
              reliable: true
            });

            conn.on('open', () => {
                clearTimeout(timeout);
                hostConnRef.current = conn;
                setIsHost(false);
                setMyPlayerId(playerId);
                peerRef.current = peer;

                const player: Player = {
                    id: playerId, name, avatarSeed: Math.random().toString(),
                    avatarUrl: avatarUrl, isHost: false, isImposter: false, isBot: false, score: 0, voteCount: 0, isReady: false
                };
                conn.send({ type: 'JOIN_REQUEST', player });
                resolve();
            });

            conn.on('data', (data: any) => { 
                if (data.type === 'SYNC_STATE') setState(data.state); 
            });

            conn.on('error', () => {
                clearTimeout(timeout);
                reject(new Error("Network connection lost."));
            });
        });

        peer.on('error', (err) => {
            clearTimeout(timeout);
            reject(new Error("Network error occurred: " + err.type));
        });
    });
  };

  const reconnectGame = (code: string, playerId: string) => {
      if (peerRef.current) peerRef.current.destroy();
      const peer = new Peer();
      peer.on('open', () => {
          const conn = peer.connect(PEER_PREFIX + code.toUpperCase(), {
            reliable: true
          });
          conn.on('open', () => {
              hostConnRef.current = conn;
              setIsHost(false);
              setMyPlayerId(playerId);
              peerRef.current = peer;
              conn.on('data', (data: any) => { if (data.type === 'SYNC_STATE') setState(data.state); });
          });
      });
  };

  const updateConfig = (config: Partial<GameConfig>) => dispatch({ type: 'UPDATE_CONFIG', config });
  const startGame = () => dispatch({ type: 'START_GAME' });
  const addBot = () => dispatch({ type: 'ADD_BOT' });
  const setTopic = (topic: string, category: string, image?: string, manualImposterIds?: string[]) => dispatch({ type: 'SET_TOPIC', topic, category, image, manualImposterIds });
  const finishRoleReveal = () => myPlayerId && dispatch({ type: 'ACK_ROUND_END', playerId: myPlayerId });
  const confirmStarter = () => dispatch({ type: 'CONFIRM_STARTER' });
  const startVoting = () => dispatch({ type: 'START_VOTING' });
  const confirmPassDevice = () => { };
  const startImposterGuess = () => dispatch({ type: 'START_IMPOSTER_GUESS' });
  const submitClue = (text: string) => dispatch({ type: 'SUBMIT_CLUE', text });
  const submitVote = (voterId: string, votedForId: string) => dispatch({ type: 'SUBMIT_VOTE', voterId, votedForId });
  const submitImposterGuess = (guess: string) => dispatch({ type: 'SUBMIT_GUESS', guess });
  const judgeImposterGuess = (isCorrect: boolean) => dispatch({ type: 'JUDGE_GUESS', isCorrect });
  const acknowledgeRoundEnd = (playerId: string) => dispatch({ type: 'ACK_ROUND_END', playerId });
  const resetGame = () => dispatch({ type: 'RESET_GAME' });

  const amIGameHost = !!state.currentHostId && state.currentHostId === myPlayerId;

  return (
    <GameContext.Provider value={{
      state, isHost, isNetworkHost: isHost, myPlayerId, amIGameHost, createGame, joinGame, reconnectGame, updateConfig, startGame, setTopic, submitClue, submitVote, submitImposterGuess, judgeImposterGuess, acknowledgeRoundEnd, resetGame, addBot, confirmPassDevice,
      finishRoleReveal, startVoting, confirmStarter, startImposterGuess
    }}>
      {children}
    </GameContext.Provider>
  );
};

export const useGame = () => {
  const context = useContext(GameContext);
  if (!context) throw new Error("useGame must be used within a GameProvider");
  return context;
};

import React, { createContext, useContext, useState, useEffect, useRef } from 'react';
import { GamePhase, GameState, Player, GameConfig, GameContextType } from '../types';
import Peer, { DataConnection } from 'peerjs';
import { audioService } from '../services/audioService';
import { generateClue } from '../services/geminiService';

type GameAction = 
  | { type: 'SYNC_STATE'; state: GameState }
  | { type: 'JOIN_REQUEST'; player: Player }
  | { type: 'UPDATE_CONFIG'; config: Partial<GameConfig> }
  | { type: 'START_GAME' }
  | { type: 'SET_TOPIC'; topic: string; category: string; image?: string; manualImposterIds?: string[] }
  | { type: 'SUBMIT_CLUE'; text: string }
  | { type: 'SUBMIT_VOTE'; voterId: string; votedForId: string }
  | { type: 'START_VOTING' }
  | { type: 'CONFIRM_STARTER' }
  | { type: 'START_IMPOSTER_GUESS' }
  | { type: 'SUBMIT_GUESS'; guess: string }
  | { type: 'JUDGE_GUESS'; isCorrect: boolean }
  | { type: 'ACK_ROUND_END'; playerId: string }
  | { type: 'RESET_GAME' }
  | { type: 'ADD_BOT' };

const GameContext = createContext<GameContextType | undefined>(undefined);

const INITIAL_STATE: GameState = {
  gameCode: '',
  phase: GamePhase.HOME,
  players: [],
  config: { mode: 'IN_PERSON', imposterCount: 1, cycles: 1 },
  currentTurnIndex: 0,
  clueRound: 1,
  currentHostId: null,
  hostIndex: 0,
  pastHostIds: [],
  currentCycle: 1,
  topic: '',
  category: '',
  clues: [],
  votes: {},
  imposterGuess: null,
  imposterGuessCorrect: null,
  winningPlayerId: null,
  nextPlayerTurnId: null,
};

// V3 prefix for better isolation
const PEER_PREFIX = 'imposter-deduction-v3-stable-';

export const GameProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [state, setState] = useState<GameState>(INITIAL_STATE);
  const [isHost, setIsHost] = useState(false);
  const [myPlayerId, setMyPlayerId] = useState<string | null>(null);

  const peerRef = useRef<Peer | null>(null);
  const connectionsRef = useRef<DataConnection[]>([]);
  const hostConnRef = useRef<DataConnection | null>(null);

  // Bot Auto-Action Logic
  useEffect(() => {
    if (!isHost) return;

    if (state.phase === GamePhase.ROLE_REVEAL) {
        const botsToReady = state.players.filter(p => p.isBot && !p.isReady);
        if (botsToReady.length > 0) {
            const timer = setTimeout(() => {
                botsToReady.forEach(bot => dispatch({ type: 'ACK_ROUND_END', playerId: bot.id }));
            }, 2000);
            return () => clearTimeout(timer);
        }
    }

    if (state.phase === GamePhase.CLUES) {
        const currentPlayer = state.players[state.currentTurnIndex];
        if (currentPlayer && currentPlayer.isBot) {
            const timer = setTimeout(async () => {
                const role = currentPlayer.isImposter ? 'IMPOSTER' : 'INNOCENT';
                const clueText = await generateClue(role, state.topic, state.category);
                dispatch({ type: 'SUBMIT_CLUE', text: clueText });
            }, 3000);
            return () => clearTimeout(timer);
        }
    }

    if (state.phase === GamePhase.SCOREBOARD) {
        const botsToReady = state.players.filter(p => p.isBot && !p.isReady);
        if (botsToReady.length > 0) {
            const timer = setTimeout(() => {
                botsToReady.forEach(bot => dispatch({ type: 'ACK_ROUND_END', playerId: bot.id }));
            }, 1500);
            return () => clearTimeout(timer);
        }
    }
  }, [state.phase, state.currentTurnIndex, isHost, state.players]);

  useEffect(() => {
    const storedId = sessionStorage.getItem('imposter_playerId');
    if (storedId) setMyPlayerId(storedId);
  }, []);

  useEffect(() => {
    if (myPlayerId) sessionStorage.setItem('imposter_playerId', myPlayerId);
    if (state.gameCode) sessionStorage.setItem('imposter_gameCode', state.gameCode);
  }, [myPlayerId, state.gameCode]);

  useEffect(() => {
    if (state.phase !== GamePhase.HOME) {
        audioService.playMusic();
    }
  }, [state.phase]);

  const broadcastState = (newState: GameState) => {
    connectionsRef.current.forEach(conn => {
      if (conn.open) {
        conn.send({ type: 'SYNC_STATE', state: newState });
      }
    });
  };

  const processAction = (action: GameAction, currentState: GameState): GameState => {
    switch (action.type) {
        case 'JOIN_REQUEST':
            const existingIdx = currentState.players.findIndex(p => p.id === action.player.id);
            if (existingIdx !== -1) {
                const updatedPlayers = [...currentState.players];
                updatedPlayers[existingIdx] = {
                    ...updatedPlayers[existingIdx],
                    name: action.player.name || updatedPlayers[existingIdx].name,
                    avatarUrl: action.player.avatarUrl || updatedPlayers[existingIdx].avatarUrl
                };
                return { ...currentState, players: updatedPlayers };
            }
            return { ...currentState, players: [...currentState.players, action.player] };

        case 'UPDATE_CONFIG':
            return { ...currentState, config: { ...currentState.config, ...action.config } };

        case 'ADD_BOT': {
             audioService.playSfx('pop');
             const names = ["Unit-X", "Spark", "Gizmo", "Chip", "Bolt", "Nexus", "Circuit", "Pixel", "Droid", "Robo"];
             const botPlayer: Player = {
                id: "BOT-" + Math.random().toString(36).substr(2, 9),
                name: names[Math.floor(Math.random() * names.length)],
                avatarSeed: Math.random().toString(),
                isHost: false,
                isImposter: false,
                isBot: true,
                score: 0,
                voteCount: 0,
                isReady: false
             };
             return { ...currentState, players: [...currentState.players, botPlayer] };
        }

        case 'START_GAME': {
            audioService.playSfx('success');
            if (currentState.players.length < 3) return currentState;
            const randHostIdx = Math.floor(Math.random() * currentState.players.length);
            const hostId = currentState.players[randHostIdx].id;
            return {
                ...currentState,
                players: currentState.players.map(p => ({
                    ...p, isHost: p.id === hostId, isImposter: false, voteCount: 0, isReady: false, score: 0
                })),
                currentHostId: hostId,
                pastHostIds: [hostId],
                currentCycle: 1,
                phase: GamePhase.TOPIC_SELECTION,
                clues: [],
                votes: {},
                topic: '',
            };
        }

        case 'SET_TOPIC': {
            audioService.playSfx('pop');
            const hostId = currentState.currentHostId;
            const manualImposterIds = action.manualImposterIds || [];
            const players = [...currentState.players];
            const imposterIndices = new Set<number>();

            if (manualImposterIds.length > 0) {
                 manualImposterIds.forEach(id => {
                     const idx = players.findIndex(p => p.id === id);
                     if (idx !== -1) imposterIndices.add(idx);
                 });
            } else {
                 while (imposterIndices.size < currentState.config.imposterCount) {
                    const idx = Math.floor(Math.random() * players.length);
                    if (players[idx].id !== hostId && !imposterIndices.has(idx)) {
                        imposterIndices.add(idx);
                    }
                }
            }

            const newPlayers = players.map((p, idx) => ({
                ...p,
                isHost: p.id === hostId,
                isImposter: imposterIndices.has(idx),
                isReady: false
            }));

            const eligibleStarters = newPlayers
                .map((p, idx) => ({ p, idx }))
                .filter(item => !item.p.isHost);

            const tickets: number[] = [];
            eligibleStarters.forEach(({ p, idx }) => {
                const count = p.isImposter ? 1 : 4; 
                for (let i = 0; i < count; i++) {
                    tickets.push(idx);
                }
            });

            const randomStarterIndex = tickets[Math.floor(Math.random() * tickets.length)];

            return {
                ...currentState,
                players: newPlayers,
                currentTurnIndex: randomStarterIndex,
                topic: action.topic,
                category: action.category,
                topicImage: action.image,
                phase: GamePhase.ROLE_REVEAL,
                imposterGuess: null,
                imposterGuessCorrect: null,
            };
        }

        case 'CONFIRM_STARTER':
            return { ...currentState, phase: GamePhase.DISCUSSION };

        case 'START_VOTING':
             audioService.playSfx('danger');
             return { ...currentState, phase: GamePhase.VOTING };

        case 'SUBMIT_CLUE': {
            audioService.playSfx('pop');
            const currentPlayer = currentState.players[currentState.currentTurnIndex];
            const newClues = [...currentState.clues, { playerId: currentPlayer.id, text: action.text, timestamp: Date.now() }];
            const activePlayerCount = currentState.players.length - 1;
            const totalCluesNeeded = activePlayerCount * 2;

            let nIdx = (currentState.currentTurnIndex + 1) % currentState.players.length;
            let nRound = currentState.clueRound;

            if (currentState.players[nIdx].isHost) {
                nIdx = (nIdx + 1) % currentState.players.length;
            }

            if (newClues.length >= totalCluesNeeded) {
                 return { ...currentState, clues: newClues, phase: GamePhase.VOTING };
            }

            if (newClues.length >= activePlayerCount) nRound = 2;

            return {
                ...currentState,
                clues: newClues,
                currentTurnIndex: nIdx,
                clueRound: nRound,
                phase: GamePhase.CLUES
            };
        }

        case 'SUBMIT_VOTE': {
            audioService.playSfx('vote');
            const newVotes = { ...currentState.votes, [action.voterId]: action.votedForId };
            const votingHumans = currentState.players.filter(p => !p.isBot && !p.isHost);
            const humansWhoVoted = votingHumans.filter(h => newVotes[h.id]);

            if (humansWhoVoted.length === votingHumans.length) {
                const finalVotes = simulateBotVotes(currentState.players, currentState.config.imposterCount, newVotes);
                const updatedPlayers = currentState.players.map(p => {
                    const votesReceived = Object.values(finalVotes).filter(id => id === p.id).length;
                    return { ...p, voteCount: votesReceived };
                });
                return { ...currentState, players: updatedPlayers, votes: finalVotes, phase: GamePhase.REVEAL };
            }
            return { ...currentState, votes: newVotes };
        }

        case 'START_IMPOSTER_GUESS':
             return { ...currentState, phase: GamePhase.IMPOSTER_GUESS };

        case 'SUBMIT_GUESS':
             audioService.playSfx('pop');
             return { ...currentState, imposterGuess: action.guess, phase: GamePhase.HOST_REVIEW };

        case 'JUDGE_GUESS': {
            if (action.isCorrect) audioService.playSfx('success');
            else audioService.playSfx('danger');

            const imposter = currentState.players.find(p => p.isImposter);
            if (!imposter) return currentState;

            let maxVotes = 0;
            currentState.players.forEach(p => { if(p.voteCount > maxVotes) maxVotes = p.voteCount; });
            const accusedPlayers = currentState.players.filter(p => p.voteCount === maxVotes);
            const majorityVotedForImposter = accusedPlayers.some(p => p.id === imposter.id);

            const newPlayers = currentState.players.map(p => {
                let roundPoints = 0;
                if (p.isHost) return p;
                if (p.isImposter) {
                    if (!majorityVotedForImposter) roundPoints += 2;
                    if (action.isCorrect) roundPoints += 1;
                } else {
                    const theirVote = currentState.votes[p.id];
                    if (theirVote === imposter.id) roundPoints += 1;
                }
                return { ...p, score: p.score + roundPoints, isReady: false };
            });

            return { ...currentState, players: newPlayers, imposterGuessCorrect: action.isCorrect, phase: GamePhase.SCOREBOARD };
        }

        case 'ACK_ROUND_END': {
             audioService.playSfx('click');
             const updatedPlayers = currentState.players.map(p => (p.id === action.playerId) ? { ...p, isReady: !p.isReady } : p);
             const readyCount = updatedPlayers.filter(p => p.isReady).length;

             if (readyCount === updatedPlayers.length) {
                if (currentState.phase === GamePhase.ROLE_REVEAL) {
                    return {
                        ...currentState,
                        players: updatedPlayers.map(p => ({ ...p, isReady: false })), 
                        phase: currentState.config.mode === 'IN_PERSON' ? GamePhase.ROUND_STARTER : GamePhase.CLUES
                    };
                }

                let nextPastHosts = [...currentState.pastHostIds];
                let nextCycle = currentState.currentCycle;
                let availableHosts = currentState.players.filter(p => !nextPastHosts.includes(p.id));

                if (availableHosts.length === 0) {
                    if (nextCycle < currentState.config.cycles) {
                        nextCycle += 1;
                        nextPastHosts = [];
                        availableHosts = [...currentState.players];
                    } else {
                        const sorted = [...updatedPlayers].sort((a,b) => b.score - a.score);
                        return { ...currentState, players: updatedPlayers, winningPlayerId: sorted[0].id, phase: GamePhase.WINNER };
                    }
                }

                const nextHost = availableHosts[Math.floor(Math.random() * availableHosts.length)];
                return {
                    ...currentState,
                    players: updatedPlayers.map(p => ({ ...p, isHost: p.id === nextHost.id, isImposter: false, isReady: false, voteCount: 0 })),
                    currentHostId: nextHost.id,
                    pastHostIds: [...nextPastHosts, nextHost.id],
                    currentCycle: nextCycle,
                    phase: GamePhase.TOPIC_SELECTION,
                    clues: [],
                    votes: {},
                    topic: '',
                    imposterGuess: null,
                    imposterGuessCorrect: null,
                };
             }
             return { ...currentState, players: updatedPlayers };
        }

        case 'RESET_GAME':
             return { ...INITIAL_STATE, gameCode: currentState.gameCode, phase: GamePhase.LOBBY, players: [] };

        default:
            return currentState;
    }
  };

  const simulateBotVotes = (allPlayers: Player[], imposterCount: number, existingVotes: Record<string,string>): Record<string, string> => {
    const votes: Record<string, string> = { ...existingVotes };
    const candidates = allPlayers.filter(p => !p.isHost);
    allPlayers.filter(p => p.isBot && !p.isHost).forEach(bot => {
        if (votes[bot.id]) return;
        const otherCandidates = candidates.filter(c => c.id !== bot.id);
        const target = otherCandidates[Math.floor(Math.random() * otherCandidates.length)];
        if (target) votes[bot.id] = target.id;
    });
    return votes;
  };

  const dispatch = (action: GameAction) => {
    if (isHost) {
        const newState = processAction(action, state);
        setState(newState);
        broadcastState(newState);
    } else if (hostConnRef.current && hostConnRef.current.open) {
        hostConnRef.current.send(action);
    }
  };

  const createGame = (name: string, avatarUrl?: string) => {
    return new Promise<void>((resolve, reject) => {
        if (peerRef.current) peerRef.current.destroy();

        const code = Math.random().toString(36).substring(2, 7).toUpperCase();
        const playerId = Math.random().toString(36).substr(2, 9);
        const peer = new Peer(PEER_PREFIX + code, {
            debug: 1,
            config: { iceServers: [{ urls: 'stun:stun.l.google.com:19302' }] }
        });

        peer.on('open', () => {
            setIsHost(true);
            setMyPlayerId(playerId);
            const creatorPlayer: Player = {
                id: playerId, name, avatarSeed: Math.random().toString(), avatarUrl,
                isHost: false, isImposter: false, isBot: false, score: 0, voteCount: 0, isReady: false
            };
            setState({ ...INITIAL_STATE, gameCode: code, phase: GamePhase.LOBBY, players: [creatorPlayer] });
            peerRef.current = peer;
            resolve();
        });

        peer.on('error', (err) => {
            if (err.type === 'unavailable-id') {
                reject(new Error("Room code busy. Try again."));
            } else {
                reject(new Error("Network server error. Please retry."));
            }
        });

        peer.on('connection', (conn) => {
            connectionsRef.current.push(conn);
            conn.on('open', () => {
                 conn.send({ type: 'SYNC_STATE', state: state });
            });
            conn.on('data', (data: any) => {
                setState(current => {
                    const updated = processAction(data as GameAction, current);
                    connectionsRef.current.forEach(c => { if (c.open) c.send({ type: 'SYNC_STATE', state: updated }); });
                    return updated;
                });
            });
            // Auto-cleanup on disconnect
            conn.on('close', () => {
                connectionsRef.current = connectionsRef.current.filter(c => c !== conn);
            });
        });
    });
  };

  const joinGame = (code: string, name: string, avatarUrl?: string) => {
    return new Promise<void>((resolve, reject) => {
        if (peerRef.current) peerRef.current.destroy();

        const playerId = sessionStorage.getItem('imposter_playerId') || Math.random().toString(36).substr(2, 9);
        const peer = new Peer({
            debug: 1,
            config: { iceServers: [{ urls: 'stun:stun.l.google.com:19302' }] }
        }); 

        // Increased timeout for slow connections
        const timeout = setTimeout(() => {
            peer.destroy();
            reject(new Error("Game not found. The host might be offline or starting up."));
        }, 25000);

        peer.on('open', () => {
            const conn = peer.connect(PEER_PREFIX + code.toUpperCase(), {
              reliable: true
            });

            conn.on('open', () => {
                clearTimeout(timeout);
                hostConnRef.current = conn;
                setIsHost(false);
                setMyPlayerId(playerId);
                peerRef.current = peer;

                const player: Player = {
                    id: playerId, name, avatarSeed: Math.random().toString(),
                    avatarUrl: avatarUrl, isHost: false, isImposter: false, isBot: false, score: 0, voteCount: 0, isReady: false
                };
                conn.send({ type: 'JOIN_REQUEST', player });
                resolve();
            });

            conn.on('data', (data: any) => { 
                if (data.type === 'SYNC_STATE') setState(data.state); 
            });

            conn.on('error', (err) => {
                clearTimeout(timeout);
                console.error("Join Connection Error:", err);
                reject(new Error("Connection failed. Try a different room code."));
            });

            conn.on('close', () => {
                // Potential silent reconnection logic could go here
                console.warn("Lost connection to host.");
            });
        });

        peer.on('error', (err) => {
            clearTimeout(timeout);
            if (err.type === 'peer-unavailable') {
                reject(new Error("Room " + code + " not found."));
            } else {
                reject(new Error("Network error: " + err.type));
            }
        });
    });
  };

  const reconnectGame = (code: string, playerId: string) => {
      if (peerRef.current) peerRef.current.destroy();
      const peer = new Peer({
          debug: 1,
          config: { iceServers: [{ urls: 'stun:stun.l.google.com:19302' }] }
      });
      peer.on('open', () => {
          const conn = peer.connect(PEER_PREFIX + code.toUpperCase(), {
            reliable: true
          });
          conn.on('open', () => {
              hostConnRef.current = conn;
              setIsHost(false);
              setMyPlayerId(playerId);
              peerRef.current = peer;
              conn.on('data', (data: any) => { if (data.type === 'SYNC_STATE') setState(data.state); });
          });
          conn.on('error', () => {
               console.warn("Silent reconnection failed.");
          });
      });
  };

  const updateConfig = (config: Partial<GameConfig>) => dispatch({ type: 'UPDATE_CONFIG', config });
  const startGame = () => dispatch({ type: 'START_GAME' });
  const addBot = () => dispatch({ type: 'ADD_BOT' });
  const setTopic = (topic: string, category: string, image?: string, manualImposterIds?: string[]) => dispatch({ type: 'SET_TOPIC', topic, category, image, manualImposterIds });
  const finishRoleReveal = () => myPlayerId && dispatch({ type: 'ACK_ROUND_END', playerId: myPlayerId });
  const confirmStarter = () => dispatch({ type: 'CONFIRM_STARTER' });
  const startVoting = () => dispatch({ type: 'START_VOTING' });
  const confirmPassDevice = () => { };
  const startImposterGuess = () => dispatch({ type: 'START_IMPOSTER_GUESS' });
  const submitClue = (text: string) => dispatch({ type: 'SUBMIT_CLUE', text });
  const submitVote = (voterId: string, votedForId: string) => dispatch({ type: 'SUBMIT_VOTE', voterId, votedForId });
  const submitImposterGuess = (guess: string) => dispatch({ type: 'SUBMIT_GUESS', guess });
  const judgeImposterGuess = (isCorrect: boolean) => dispatch({ type: 'JUDGE_GUESS', isCorrect });
  const acknowledgeRoundEnd = (playerId: string) => dispatch({ type: 'ACK_ROUND_END', playerId });
  const resetGame = () => dispatch({ type: 'RESET_GAME' });

  const amIGameHost = !!state.currentHostId && state.currentHostId === myPlayerId;

  return (
    <GameContext.Provider value={{
      state, isHost, isNetworkHost: isHost, myPlayerId, amIGameHost, createGame, joinGame, reconnectGame, updateConfig, startGame, setTopic, submitClue, submitVote, submitImposterGuess, judgeImposterGuess, acknowledgeRoundEnd, resetGame, addBot, confirmPassDevice,
      finishRoleReveal, startVoting, confirmStarter, startImposterGuess
    }}>
      {children}
    </GameContext.Provider>
  );
};

export const useGame = () => {
  const context = useContext(GameContext);
  if (!context) throw new Error("useGame must be used within a GameProvider");
  return context;
};

import React, { createContext, useContext, useState, useEffect, useRef } from 'react';
import { GamePhase, GameState, Player, GameConfig, GameContextType } from '../types';
import Peer, { DataConnection } from 'peerjs';
import { audioService } from '../services/audioService';
import { generateClue } from '../services/geminiService';

type GameAction = 
  | { type: 'SYNC_STATE'; state: GameState }
  | { type: 'JOIN_REQUEST'; player: Player }
  | { type: 'UPDATE_CONFIG'; config: Partial<GameConfig> }
  | { type: 'START_GAME' }
  | { type: 'SET_TOPIC'; topic: string; category: string; image?: string; manualImposterIds?: string[] }
  | { type: 'SUBMIT_CLUE'; text: string }
  | { type: 'SUBMIT_VOTE'; voterId: string; votedForId: string }
  | { type: 'START_VOTING' }
  | { type: 'CONFIRM_STARTER' }
  | { type: 'START_IMPOSTER_GUESS' }
  | { type: 'SUBMIT_GUESS'; guess: string }
  | { type: 'JUDGE_GUESS'; isCorrect: boolean }
  | { type: 'ACK_ROUND_END'; playerId: string }
  | { type: 'RESET_GAME' }
  | { type: 'ADD_BOT' };

const GameContext = createContext<GameContextType | undefined>(undefined);

const INITIAL_STATE: GameState = {
  gameCode: '',
  phase: GamePhase.HOME,
  players: [],
  config: { mode: 'IN_PERSON', imposterCount: 1, cycles: 1 },
  currentTurnIndex: 0,
  clueRound: 1,
  currentHostId: null,
  hostIndex: 0,
  pastHostIds: [],
  currentCycle: 1,
  topic: '',
  category: '',
  clues: [],
  votes: {},
  imposterGuess: null,
  imposterGuessCorrect: null,
  winningPlayerId: null,
  nextPlayerTurnId: null,
};

// V3 prefix for better isolation
const PEER_PREFIX = 'imposter-deduction-v3-stable-';

export const GameProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [state, setState] = useState<GameState>(INITIAL_STATE);
  const [isHost, setIsHost] = useState(false);
  const [myPlayerId, setMyPlayerId] = useState<string | null>(null);

  const peerRef = useRef<Peer | null>(null);
  const connectionsRef = useRef<DataConnection[]>([]);
  const hostConnRef = useRef<DataConnection | null>(null);

  // Bot Auto-Action Logic
  useEffect(() => {
    if (!isHost) return;

    if (state.phase === GamePhase.ROLE_REVEAL) {
        const botsToReady = state.players.filter(p => p.isBot && !p.isReady);
        if (botsToReady.length > 0) {
            const timer = setTimeout(() => {
                botsToReady.forEach(bot => dispatch({ type: 'ACK_ROUND_END', playerId: bot.id }));
            }, 2000);
            return () => clearTimeout(timer);
        }
    }

    if (state.phase === GamePhase.CLUES) {
        const currentPlayer = state.players[state.currentTurnIndex];
        if (currentPlayer && currentPlayer.isBot) {
            const timer = setTimeout(async () => {
                const role = currentPlayer.isImposter ? 'IMPOSTER' : 'INNOCENT';
                const clueText = await generateClue(role, state.topic, state.category);
                dispatch({ type: 'SUBMIT_CLUE', text: clueText });
            }, 3000);
            return () => clearTimeout(timer);
        }
    }

    if (state.phase === GamePhase.SCOREBOARD) {
        const botsToReady = state.players.filter(p => p.isBot && !p.isReady);
        if (botsToReady.length > 0) {
            const timer = setTimeout(() => {
                botsToReady.forEach(bot => dispatch({ type: 'ACK_ROUND_END', playerId: bot.id }));
            }, 1500);
            return () => clearTimeout(timer);
        }
    }
  }, [state.phase, state.currentTurnIndex, isHost, state.players]);

  useEffect(() => {
    const storedId = sessionStorage.getItem('imposter_playerId');
    if (storedId) setMyPlayerId(storedId);
  }, []);

  useEffect(() => {
    if (myPlayerId) sessionStorage.setItem('imposter_playerId', myPlayerId);
    if (state.gameCode) sessionStorage.setItem('imposter_gameCode', state.gameCode);
  }, [myPlayerId, state.gameCode]);

  useEffect(() => {
    if (state.phase !== GamePhase.HOME) {
        audioService.playMusic();
    }
  }, [state.phase]);

  const broadcastState = (newState: GameState) => {
    connectionsRef.current.forEach(conn => {
      if (conn.open) {
        conn.send({ type: 'SYNC_STATE', state: newState });
      }
    });
  };

  const processAction = (action: GameAction, currentState: GameState): GameState => {
    switch (action.type) {
        case 'JOIN_REQUEST':
            const existingIdx = currentState.players.findIndex(p => p.id === action.player.id);
            if (existingIdx !== -1) {
                const updatedPlayers = [...currentState.players];
                updatedPlayers[existingIdx] = {
                    ...updatedPlayers[existingIdx],
                    name: action.player.name || updatedPlayers[existingIdx].name,
                    avatarUrl: action.player.avatarUrl || updatedPlayers[existingIdx].avatarUrl
                };
                return { ...currentState, players: updatedPlayers };
            }
            return { ...currentState, players: [...currentState.players, action.player] };

        case 'UPDATE_CONFIG':
            return { ...currentState, config: { ...currentState.config, ...action.config } };

        case 'ADD_BOT': {
             audioService.playSfx('pop');
             const names = ["Unit-X", "Spark", "Gizmo", "Chip", "Bolt", "Nexus", "Circuit", "Pixel", "Droid", "Robo"];
             const botPlayer: Player = {
                id: "BOT-" + Math.random().toString(36).substr(2, 9),
                name: names[Math.floor(Math.random() * names.length)],
                avatarSeed: Math.random().toString(),
                isHost: false,
                isImposter: false,
                isBot: true,
                score: 0,
                voteCount: 0,
                isReady: false
             };
             return { ...currentState, players: [...currentState.players, botPlayer] };
        }

        case 'START_GAME': {
            audioService.playSfx('success');
            if (currentState.players.length < 3) return currentState;
            const randHostIdx = Math.floor(Math.random() * currentState.players.length);
            const hostId = currentState.players[randHostIdx].id;
            return {
                ...currentState,
                players: currentState.players.map(p => ({
                    ...p, isHost: p.id === hostId, isImposter: false, voteCount: 0, isReady: false, score: 0
                })),
                currentHostId: hostId,
                pastHostIds: [hostId],
                currentCycle: 1,
                phase: GamePhase.TOPIC_SELECTION,
                clues: [],
                votes: {},
                topic: '',
            };
        }

        case 'SET_TOPIC': {
            audioService.playSfx('pop');
            const hostId = currentState.currentHostId;
            const manualImposterIds = action.manualImposterIds || [];
            const players = [...currentState.players];
            const imposterIndices = new Set<number>();

            if (manualImposterIds.length > 0) {
                 manualImposterIds.forEach(id => {
                     const idx = players.findIndex(p => p.id === id);
                     if (idx !== -1) imposterIndices.add(idx);
                 });
            } else {
                 while (imposterIndices.size < currentState.config.imposterCount) {
                    const idx = Math.floor(Math.random() * players.length);
                    if (players[idx].id !== hostId && !imposterIndices.has(idx)) {
                        imposterIndices.add(idx);
                    }
                }
            }

            const newPlayers = players.map((p, idx) => ({
                ...p,
                isHost: p.id === hostId,
                isImposter: imposterIndices.has(idx),
                isReady: false
            }));

            const eligibleStarters = newPlayers
                .map((p, idx) => ({ p, idx }))
                .filter(item => !item.p.isHost);

            const tickets: number[] = [];
            eligibleStarters.forEach(({ p, idx }) => {
                const count = p.isImposter ? 1 : 4; 
                for (let i = 0; i < count; i++) {
                    tickets.push(idx);
                }
            });

            const randomStarterIndex = tickets[Math.floor(Math.random() * tickets.length)];

            return {
                ...currentState,
                players: newPlayers,
                currentTurnIndex: randomStarterIndex,
                topic: action.topic,
                category: action.category,
                topicImage: action.image,
                phase: GamePhase.ROLE_REVEAL,
                imposterGuess: null,
                imposterGuessCorrect: null,
            };
        }

        case 'CONFIRM_STARTER':
            return { ...currentState, phase: GamePhase.DISCUSSION };

        case 'START_VOTING':
             audioService.playSfx('danger');
             return { ...currentState, phase: GamePhase.VOTING };

        case 'SUBMIT_CLUE': {
            audioService.playSfx('pop');
            const currentPlayer = currentState.players[currentState.currentTurnIndex];
            const newClues = [...currentState.clues, { playerId: currentPlayer.id, text: action.text, timestamp: Date.now() }];
            const activePlayerCount = currentState.players.length - 1;
            const totalCluesNeeded = activePlayerCount * 2;

            let nIdx = (currentState.currentTurnIndex + 1) % currentState.players.length;
            let nRound = currentState.clueRound;

            if (currentState.players[nIdx].isHost) {
                nIdx = (nIdx + 1) % currentState.players.length;
            }

            if (newClues.length >= totalCluesNeeded) {
                 return { ...currentState, clues: newClues, phase: GamePhase.VOTING };
            }

            if (newClues.length >= activePlayerCount) nRound = 2;

            return {
                ...currentState,
                clues: newClues,
                currentTurnIndex: nIdx,
                clueRound: nRound,
                phase: GamePhase.CLUES
            };
        }

        case 'SUBMIT_VOTE': {
            audioService.playSfx('vote');
            const newVotes = { ...currentState.votes, [action.voterId]: action.votedForId };
            const votingHumans = currentState.players.filter(p => !p.isBot && !p.isHost);
            const humansWhoVoted = votingHumans.filter(h => newVotes[h.id]);

            if (humansWhoVoted.length === votingHumans.length) {
                const finalVotes = simulateBotVotes(currentState.players, currentState.config.imposterCount, newVotes);
                const updatedPlayers = currentState.players.map(p => {
                    const votesReceived = Object.values(finalVotes).filter(id => id === p.id).length;
                    return { ...p, voteCount: votesReceived };
                });
                return { ...currentState, players: updatedPlayers, votes: finalVotes, phase: GamePhase.REVEAL };
            }
            return { ...currentState, votes: newVotes };
        }

        case 'START_IMPOSTER_GUESS':
             return { ...currentState, phase: GamePhase.IMPOSTER_GUESS };

        case 'SUBMIT_GUESS':
             audioService.playSfx('pop');
             return { ...currentState, imposterGuess: action.guess, phase: GamePhase.HOST_REVIEW };

        case 'JUDGE_GUESS': {
            if (action.isCorrect) audioService.playSfx('success');
            else audioService.playSfx('danger');

            const imposter = currentState.players.find(p => p.isImposter);
            if (!imposter) return currentState;

            let maxVotes = 0;
            currentState.players.forEach(p => { if(p.voteCount > maxVotes) maxVotes = p.voteCount; });
            const accusedPlayers = currentState.players.filter(p => p.voteCount === maxVotes);
            const majorityVotedForImposter = accusedPlayers.some(p => p.id === imposter.id);

            const newPlayers = currentState.players.map(p => {
                let roundPoints = 0;
                if (p.isHost) return p;
                if (p.isImposter) {
                    if (!majorityVotedForImposter) roundPoints += 2;
                    if (action.isCorrect) roundPoints += 1;
                } else {
                    const theirVote = currentState.votes[p.id];
                    if (theirVote === imposter.id) roundPoints += 1;
                }
                return { ...p, score: p.score + roundPoints, isReady: false };
            });

            return { ...currentState, players: newPlayers, imposterGuessCorrect: action.isCorrect, phase: GamePhase.SCOREBOARD };
        }

        case 'ACK_ROUND_END': {
             audioService.playSfx('click');
             const updatedPlayers = currentState.players.map(p => (p.id === action.playerId) ? { ...p, isReady: !p.isReady } : p);
             const readyCount = updatedPlayers.filter(p => p.isReady).length;

             if (readyCount === updatedPlayers.length) {
                if (currentState.phase === GamePhase.ROLE_REVEAL) {
                    return {
                        ...currentState,
                        players: updatedPlayers.map(p => ({ ...p, isReady: false })), 
                        phase: currentState.config.mode === 'IN_PERSON' ? GamePhase.ROUND_STARTER : GamePhase.CLUES
                    };
                }

                let nextPastHosts = [...currentState.pastHostIds];
                let nextCycle = currentState.currentCycle;
                let availableHosts = currentState.players.filter(p => !nextPastHosts.includes(p.id));

                if (availableHosts.length === 0) {
                    if (nextCycle < currentState.config.cycles) {
                        nextCycle += 1;
                        nextPastHosts = [];
                        availableHosts = [...currentState.players];
                    } else {
                        const sorted = [...updatedPlayers].sort((a,b) => b.score - a.score);
                        return { ...currentState, players: updatedPlayers, winningPlayerId: sorted[0].id, phase: GamePhase.WINNER };
                    }
                }

                const nextHost = availableHosts[Math.floor(Math.random() * availableHosts.length)];
                return {
                    ...currentState,
                    players: updatedPlayers.map(p => ({ ...p, isHost: p.id === nextHost.id, isImposter: false, isReady: false, voteCount: 0 })),
                    currentHostId: nextHost.id,
                    pastHostIds: [...nextPastHosts, nextHost.id],
                    currentCycle: nextCycle,
                    phase: GamePhase.TOPIC_SELECTION,
                    clues: [],
                    votes: {},
                    topic: '',
                    imposterGuess: null,
                    imposterGuessCorrect: null,
                };
             }
             return { ...currentState, players: updatedPlayers };
        }

        case 'RESET_GAME':
             return { ...INITIAL_STATE, gameCode: currentState.gameCode, phase: GamePhase.LOBBY, players: [] };

        default:
            return currentState;
    }
  };

  const simulateBotVotes = (allPlayers: Player[], imposterCount: number, existingVotes: Record<string,string>): Record<string, string> => {
    const votes: Record<string, string> = { ...existingVotes };
    const candidates = allPlayers.filter(p => !p.isHost);
    allPlayers.filter(p => p.isBot && !p.isHost).forEach(bot => {
        if (votes[bot.id]) return;
        const otherCandidates = candidates.filter(c => c.id !== bot.id);
        const target = otherCandidates[Math.floor(Math.random() * otherCandidates.length)];
        if (target) votes[bot.id] = target.id;
    });
    return votes;
  };

  const dispatch = (action: GameAction) => {
    if (isHost) {
        const newState = processAction(action, state);
        setState(newState);
        broadcastState(newState);
    } else if (hostConnRef.current && hostConnRef.current.open) {
        hostConnRef.current.send(action);
    }
  };

  const createGame = (name: string, avatarUrl?: string) => {
    return new Promise<void>((resolve, reject) => {
        if (peerRef.current) peerRef.current.destroy();

        const code = Math.random().toString(36).substring(2, 7).toUpperCase();
        const playerId = Math.random().toString(36).substr(2, 9);
        const peer = new Peer(PEER_PREFIX + code, {
            debug: 1,
            config: { iceServers: [{ urls: 'stun:stun.l.google.com:19302' }] }
        });

        peer.on('open', () => {
            setIsHost(true);
            setMyPlayerId(playerId);
            const creatorPlayer: Player = {
                id: playerId, name, avatarSeed: Math.random().toString(), avatarUrl,
                isHost: false, isImposter: false, isBot: false, score: 0, voteCount: 0, isReady: false
            };
            setState({ ...INITIAL_STATE, gameCode: code, phase: GamePhase.LOBBY, players: [creatorPlayer] });
            peerRef.current = peer;
            resolve();
        });

        peer.on('error', (err) => {
            if (err.type === 'unavailable-id') {
                reject(new Error("Room code busy. Try again."));
            } else {
                reject(new Error("Network server error. Please retry."));
            }
        });

        peer.on('connection', (conn) => {
            connectionsRef.current.push(conn);
            conn.on('open', () => {
                 conn.send({ type: 'SYNC_STATE', state: state });
            });
            conn.on('data', (data: any) => {
                setState(current => {
                    const updated = processAction(data as GameAction, current);
                    connectionsRef.current.forEach(c => { if (c.open) c.send({ type: 'SYNC_STATE', state: updated }); });
                    return updated;
                });
            });
            conn.on('close', () => {
                connectionsRef.current = connectionsRef.current.filter(c => c !== conn);
            });
        });
    });
  };

  const joinGame = (code: string, name: string, avatarUrl?: string) => {
    return new Promise<void>((resolve, reject) => {
        if (peerRef.current) peerRef.current.destroy();

        const playerId = sessionStorage.getItem('imposter_playerId') || Math.random().toString(36).substr(2, 9);
        const peer = new Peer({
            debug: 1,
            config: { iceServers: [{ urls: 'stun:stun.l.google.com:19302' }] }
        }); 

        // Increased timeout to 120 seconds (2 minutes) to allow for slow signaling and host app switching
        const timeout = setTimeout(() => {
            peer.destroy();
            reject(new Error("Game session not found or connection timed out. Ask the host if the room is still open."));
        }, 120000);

        peer.on('open', () => {
            const conn = peer.connect(PEER_PREFIX + code.toUpperCase(), {
              reliable: true
            });

            conn.on('open', () => {
                clearTimeout(timeout);
                hostConnRef.current = conn;
                setIsHost(false);
                setMyPlayerId(playerId);
                peerRef.current = peer;

                const player: Player = {
                    id: playerId, name, avatarSeed: Math.random().toString(),
                    avatarUrl: avatarUrl, isHost: false, isImposter: false, isBot: false, score: 0, voteCount: 0, isReady: false
                };
                conn.send({ type: 'JOIN_REQUEST', player });
                resolve();
            });

            conn.on('data', (data: any) => { 
                if (data.type === 'SYNC_STATE') setState(data.state); 
            });

            conn.on('error', (err) => {
                clearTimeout(timeout);
                console.error("Join Connection Error:", err);
                reject(new Error("Connection lost. Please check your internet and try again."));
            });
        });

        peer.on('error', (err) => {
            clearTimeout(timeout);
            if (err.type === 'peer-unavailable') {
                reject(new Error("Room " + code + " doesn't exist yet."));
            } else {
                reject(new Error("Network server error: " + err.type));
            }
        });
    });
  };

  const reconnectGame = (code: string, playerId: string) => {
      if (peerRef.current) peerRef.current.destroy();
      const peer = new Peer({
          debug: 1,
          config: { iceServers: [{ urls: 'stun:stun.l.google.com:19302' }] }
      });
      peer.on('open', () => {
          const conn = peer.connect(PEER_PREFIX + code.toUpperCase(), {
            reliable: true
          });
          conn.on('open', () => {
              hostConnRef.current = conn;
              setIsHost(false);
              setMyPlayerId(playerId);
              peerRef.current = peer;
              conn.on('data', (data: any) => { if (data.type === 'SYNC_STATE') setState(data.state); });
          });
      });
  };

  const updateConfig = (config: Partial<GameConfig>) => dispatch({ type: 'UPDATE_CONFIG', config });
  const startGame = () => dispatch({ type: 'START_GAME' });
  const addBot = () => dispatch({ type: 'ADD_BOT' });
  const setTopic = (topic: string, category: string, image?: string, manualImposterIds?: string[]) => dispatch({ type: 'SET_TOPIC', topic, category, image, manualImposterIds });
  const finishRoleReveal = () => myPlayerId && dispatch({ type: 'ACK_ROUND_END', playerId: myPlayerId });
  const confirmStarter = () => dispatch({ type: 'CONFIRM_STARTER' });
  const startVoting = () => dispatch({ type: 'START_VOTING' });
  const confirmPassDevice = () => { };
  const startImposterGuess = () => dispatch({ type: 'START_IMPOSTER_GUESS' });
  const submitClue = (text: string) => dispatch({ type: 'SUBMIT_CLUE', text });
  const submitVote = (voterId: string, votedForId: string) => dispatch({ type: 'SUBMIT_VOTE', voterId, votedForId });
  const submitImposterGuess = (guess: string) => dispatch({ type: 'SUBMIT_GUESS', guess });
  const judgeImposterGuess = (isCorrect: boolean) => dispatch({ type: 'JUDGE_GUESS', isCorrect });
  const acknowledgeRoundEnd = (playerId: string) => dispatch({ type: 'ACK_ROUND_END', playerId });
  const resetGame = () => dispatch({ type: 'RESET_GAME' });

  const amIGameHost = !!state.currentHostId && state.currentHostId === myPlayerId;

  return (
    <GameContext.Provider value={{
      state, isHost, isNetworkHost: isHost, myPlayerId, amIGameHost, createGame, joinGame, reconnectGame, updateConfig, startGame, setTopic, submitClue, submitVote, submitImposterGuess, judgeImposterGuess, acknowledgeRoundEnd, resetGame, addBot, confirmPassDevice,
      finishRoleReveal, startVoting, confirmStarter, startImposterGuess
    }}>
      {children}
    </GameContext.Provider>
  );
};

export const useGame = () => {
  const context = useContext(GameContext);
  if (!context) throw new Error("useGame must be used within a GameProvider");
  return context;
};

