export const HomeScreen: React.FC = () => {
  const { createGame, joinGame, reconnectGame } = useGame();
  const [view, setView] = useState<'MAIN' | 'JOIN' | 'CREATE'>('MAIN');
  const [joinCode, setJoinCode] = useState('');
  const [playerName, setPlayerName] = useState('');
  const [avatarUrl, setAvatarUrl] = useState<string | undefined>(undefined);
  const [showCamera, setShowCamera] = useState(false);
  const [isConnecting, setIsConnecting] = useState(false);
  const [errorMsg, setErrorMsg] = useState('');
  const [showTutorial, setShowTutorial] = useState(false);
  const [activeSession, setActiveSession] = useState<{ code: string, id: string } | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const params = new URLSearchParams(window.location.search);
    const urlCode = params.get('code');
    if (urlCode) {
        setJoinCode(urlCode.toUpperCase());
        setView('JOIN');
    }
    const storedCode = sessionStorage.getItem('imposter_gameCode');
    const storedId = sessionStorage.getItem('imposter_playerId');
    if (storedCode && storedId) setActiveSession({ code: storedCode, id: storedId });
  }, []);

  const handleAction = (callback: () => void) => {
    audioService.playMusic();
    callback();
  };

  const handleJoin = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!joinCode || !playerName || !avatarUrl) return;
    setIsConnecting(true);
    setErrorMsg('');
    try {
        await joinGame(joinCode, playerName, avatarUrl);
    } catch (err: any) {
        setIsConnecting(false);
        setErrorMsg(err.message || "Failed to join game.");
    }
  };

  const handleCreate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!playerName || !avatarUrl) return;
    setIsConnecting(true);
    setErrorMsg('');
    try {
        await createGame(playerName, avatarUrl);
    } catch (err: any) {
        setIsConnecting(false);
        setErrorMsg(err.message || "Failed to create game.");
    }
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setAvatarUrl(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  return (
    <div className="flex flex-col items-center justify-center min-h-screen p-6 text-center relative overflow-hidden bg-game-bg">
      {showTutorial && <TutorialOverlay onClose={() => setShowTutorial(false)} />}

      {isConnecting && (
        <div className="fixed inset-0 z-[150] bg-slate-900/80 backdrop-blur-md flex flex-col items-center justify-center p-6 animate-fade-in text-center">
          <div className="w-16 h-16 border-4 border-indigo-500 border-t-transparent rounded-full animate-spin mb-6"></div>
          <h2 className="text-xl font-bold text-white uppercase tracking-widest">Waiting for Host</h2>
          <p className="text-slate-400 text-sm mt-2 max-w-xs">Attempting to sync with the room signal. This may take a moment...</p>
        </div>
      )}

      <div className="absolute top-0 left-0 w-full h-full overflow-hidden pointer-events-none opacity-20">
         <div className="absolute top-0 left-1/4 w-72 h-72 bg-purple-500 rounded-full blur-3xl animate-blob"></div>
         <div className="absolute top-0 right-1/4 w-72 h-72 bg-indigo-500 rounded-full blur-3xl animate-blob animation-delay-2000"></div>
      </div>

      <div className="z-10 w-full max-w-md space-y-8">
        <div className="animate-fade-in-down">
          <GameLogo />
          <h1 className="text-6xl font-black tracking-tighter text-transparent bg-clip-text bg-gradient-to-r from-indigo-200 via-purple-200 to-pink-200 mb-1 drop-shadow-lg">IMPOSTER</h1>
          <p className="text-indigo-200/60 text-sm uppercase tracking-[0.5em] font-medium">Digital Deduction</p>
        </div>

        {errorMsg && (
            <div className="bg-red-500/10 border border-red-500/50 p-4 rounded-xl text-red-400 text-sm font-bold animate-shake">
                ⚠️ {errorMsg}
            </div>
        )}

        {view === 'MAIN' && (
          <div className="flex flex-col gap-4 animate-fade-in-up">
            {activeSession && (
                <div className="bg-indigo-500/20 border border-indigo-500/50 p-4 rounded-xl flex items-center justify-between animate-bounce-in">
                    <div className="text-left"><p className="text-xs text-indigo-300 font-bold uppercase">Quick Rejoin</p><p className="text-white font-mono">{activeSession.code}</p></div>
                    <Button onClick={() => handleAction(() => reconnectGame(activeSession.code, activeSession.id))} className="!py-2 !px-4 text-sm">REJOIN</Button>
                </div>
            )}
            <Button onClick={() => handleAction(() => setView('CREATE'))}>CREATE GAME</Button>
            <Button variant="secondary" onClick={() => handleAction(() => setView('JOIN'))}>JOIN GAME</Button>
            <button 
                onClick={() => setShowTutorial(true)} 
                className="text-xs font-black text-indigo-400 uppercase tracking-widest hover:text-indigo-300 transition-colors mt-2"
            >
                How to Play?
            </button>
          </div>
        )}

        {(view === 'JOIN' || view === 'CREATE') && (
          <form onSubmit={view === 'JOIN' ? handleJoin : handleCreate} className="flex flex-col gap-4 bg-slate-900/50 backdrop-blur-xl p-8 rounded-3xl shadow-2xl border border-white/10 animate-fade-in-up">
            <h2 className="text-xl font-bold mb-2 text-white">{view === 'JOIN' ? 'Join Lobby' : 'Create Game'}</h2>

            <div className="flex flex-col items-center gap-4 mb-4">
                {showCamera && (
                    <Camera onCapture={(img) => { setAvatarUrl(img); setShowCamera(false); }} onCancel={() => setShowCamera(false)} />
                )}
                <div className={`w-32 h-32 rounded-full bg-slate-800 border-4 flex items-center justify-center overflow-hidden relative transition-all ${!avatarUrl ? 'border-game-primary border-dashed animate-pulse' : 'border-game-accent shadow-lg scale-105'}`}>
                    {avatarUrl ? <img src={avatarUrl} alt="Preview" className="w-full h-full object-cover" /> : <span className="text-4xl text-slate-500">👤</span>}
                </div>
                <div className="flex gap-2 w-full">
                    <Button type="button" variant="secondary" className="flex-1 py-2 text-xs" onClick={() => handleAction(() => fileInputRef.current?.click())}>Upload</Button>
                    <Button type="button" variant="secondary" className="flex-1 py-2 text-xs" onClick={() => handleAction(() => setShowCamera(true))}>Take Selfie</Button>
                </div>
                <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleImageUpload} />
            </div>

            {view === 'JOIN' && (
                <input type="text" placeholder="GAME CODE" maxLength={5} className="w-full bg-black/30 border border-white/10 p-4 rounded-xl text-center text-xl font-mono uppercase text-white outline-none focus:border-indigo-500" value={joinCode} onChange={e => setJoinCode(e.target.value.toUpperCase())} />
            )}
            <input type="text" placeholder="YOUR NAME" className="w-full bg-black/30 border border-white/10 p-4 rounded-xl text-center text-xl text-white outline-none focus:border-indigo-500" value={playerName} onChange={e => setPlayerName(e.target.value)} />

            <div className="flex gap-3 mt-4">
                <Button type="button" variant="secondary" onClick={() => setView('MAIN')} className="flex-1">Back</Button>
                <Button type="submit" className="flex-1" disabled={!playerName || !avatarUrl || (view === 'JOIN' && !joinCode)}>Enter</Button>
            </div>
          </form>
        )}
      </div>
    </div>
  );
};

import React from 'react';
import { useGame } from '../context/GameContext';
import { Button } from '../components/Button';
import { Avatar } from '../components/Avatar';
import { GameConfig } from '../types';

export const LobbyScreen: React.FC = () => {
  const { state, updateConfig, startGame, addBot, isNetworkHost } = useGame();
  const { players, config, gameCode } = state;

  const handleConfigChange = (updates: Partial<GameConfig>) => {
    if (!isNetworkHost) return;
    updateConfig(updates);
  };

  const handleShare = async () => {
      const currentUrl = new URL(window.location.href);
      currentUrl.searchParams.set('code', gameCode);
      const shareUrl = currentUrl.toString();
      try {
          if (navigator.share) {
              await navigator.share({ title: 'Join Imposter', url: shareUrl });
          } else {
              await navigator.clipboard.writeText(shareUrl);
              alert(`Link copied!`);
          }
      } catch (err) {
          await navigator.clipboard.writeText(shareUrl);
          alert(`Link copied!`);
      }
  };

  const MIN_PLAYERS = 4;

  return (
    <div className="min-h-screen flex flex-col p-6 max-w-2xl mx-auto">
      <div className="flex justify-between items-center mb-6 bg-slate-900/40 p-4 rounded-2xl backdrop-blur-md border border-white/10">
        <div>
          <span className="text-slate-400 text-xs font-bold tracking-widest uppercase">Room Code</span>
          <h2 className="text-4xl font-mono font-black text-white">{gameCode}</h2>
        </div>
        <Button variant="secondary" className="!py-2 !px-4 text-xs font-bold" onClick={handleShare}>SHARE LINK</Button>
      </div>

      <div className="flex-1 overflow-y-auto mb-6">
        <div className="flex justify-between items-end mb-6">
             <h3 className="text-indigo-200 font-bold uppercase text-sm tracking-widest">Crew ({players.length})</h3>
             {isNetworkHost && (
                 <button 
                  onClick={addBot} 
                  className="text-xs bg-indigo-500/20 text-indigo-300 px-4 py-2 rounded-full border border-indigo-500/30 hover:bg-indigo-500/30 transition-colors font-bold uppercase"
                 >
                  + Add Bot
                 </button>
             )}
        </div>
        <div className="grid grid-cols-3 gap-y-8 gap-x-4 pb-8">
          {players.map(p => (
            <div key={p.id} className="animate-bounce-in">
              <Avatar 
                seed={p.avatarSeed} 
                url={p.avatarUrl} 
                name={p.name} 
                size="md" 
                className="transform hover:scale-110 transition-transform cursor-default"
              />
            </div>
          ))}
        </div>
      </div>

      <div className="bg-slate-900/60 p-6 rounded-3xl border border-white/10 space-y-6 shadow-2xl backdrop-blur-xl">
        <div className="space-y-3">
            <label className="text-xs font-bold text-slate-400 uppercase tracking-widest">Game Style</label>
            <div className={`flex gap-3 ${!isNetworkHost ? 'opacity-60 pointer-events-none' : ''}`}>
                {(['IN_PERSON', 'PHONE'] as const).map(mode => (
                    <button 
                        key={mode}
                        onClick={() => handleConfigChange({ mode })}
                        className={`flex-1 p-3 rounded-xl font-bold border transition-all ${config.mode === mode ? 'border-indigo-500 bg-indigo-500/20 text-indigo-300 shadow-[0_0_15px_rgba(99,102,241,0.2)]' : 'border-slate-700 bg-slate-800/50 text-slate-500 hover:border-slate-600'}`}
                    >
                        {mode === 'IN_PERSON' ? 'Party' : 'Remote'}
                    </button>
                ))}
            </div>
        </div>

        <div className="space-y-3">
            <label className="text-xs font-bold text-slate-400 uppercase tracking-widest">Cycles (Rounds)</label>
            <div className={`flex gap-3 ${!isNetworkHost ? 'opacity-60 pointer-events-none' : ''}`}>
                {[1, 2, 3].map(num => (
                    <button 
                        key={num}
                        onClick={() => handleConfigChange({ cycles: num })}
                        className={`flex-1 p-3 rounded-xl font-bold border transition-all ${config.cycles === num ? 'border-game-accent bg-game-accent/20 text-game-accent shadow-[0_0_15px_rgba(139,92,246,0.2)]' : 'border-slate-700 bg-slate-800/50 text-slate-500 hover:border-slate-600'}`}
                    >
                        {num}
                    </button>
                ))}
            </div>
        </div>

        {isNetworkHost ? (
            <Button fullWidth disabled={players.length < MIN_PLAYERS} onClick={startGame} className="ring-offset-2 ring-offset-slate-900 focus:ring-2 ring-game-primary">
                {players.length < MIN_PLAYERS ? `NEED ${MIN_PLAYERS - players.length} MORE` : "START GAME"}
            </Button>
        ) : (
            <div className="text-center p-5 text-slate-400 font-bold bg-slate-800/30 rounded-2xl border border-slate-700/50 animate-pulse uppercase tracking-widest text-xs">
              Waiting for host to launch...
            </div>
        )}
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { useGame } from '../context/GameContext';
import { Button } from '../components/Button';
import { Avatar } from '../components/Avatar';

export const VotingScreen: React.FC = () => {
  const { state, submitVote, myPlayerId, amIGameHost } = useGame();
  const { players, clues, votes } = state;
  const [selectedSuspect, setSelectedSuspect] = useState<string | null>(null);

  const myVote = myPlayerId ? votes[myPlayerId] : null;
  const humanPlayers = players.filter(p => !p.isBot && !p.isHost);
  const candidates = players.filter(p => !p.isHost && p.id !== myPlayerId);

  if (amIGameHost) {
      const voteCount = humanPlayers.filter(p => votes[p.id]).length;
      return (
          <div className="min-h-screen bg-game-bg flex flex-col items-center justify-center p-6 text-center">
              <h2 className="text-2xl font-black text-white mb-2 uppercase tracking-widest">Voting Progress</h2>
              <p className="text-slate-400 mb-8">Moderating: Waiting for players to decide...</p>
              <div className="w-full max-w-md bg-game-surface p-6 rounded-3xl border border-white/10 shadow-2xl space-y-4">
                  <div className="flex justify-between items-center mb-4">
                      <span className="text-xs font-bold text-slate-500 uppercase">Status</span>
                      <span className="text-xs font-bold text-game-primary uppercase">{voteCount} / {humanPlayers.length} Voted</span>
                  </div>
                  {humanPlayers.map(p => (
                      <div key={p.id} className="flex items-center justify-between bg-slate-900/50 p-3 rounded-xl border border-slate-700">
                          <div className="flex items-center gap-3">
                              <Avatar seed={p.avatarSeed} url={p.avatarUrl} size="sm" />
                              <span className="font-bold">{p.name}</span>
                          </div>
                          {votes[p.id] ? <span className="text-game-success text-xs font-black uppercase">✓ Voted</span> : <span className="text-slate-500 text-xs font-black uppercase animate-pulse">Thinking...</span>}
                      </div>
                  ))}
              </div>
          </div>
      );
  }

  if (myVote) {
      return (
          <div className="min-h-screen bg-game-bg flex flex-col items-center justify-center p-6 text-center">
              <div className="w-20 h-20 bg-game-success/20 rounded-full flex items-center justify-center mb-6 animate-bounce-in">
                  <span className="text-4xl">✓</span>
              </div>
              <h2 className="text-2xl font-black text-white mb-2 uppercase tracking-widest">Vote Cast!</h2>
              <p className="text-slate-400">Waiting for other players to finalize their decisions...</p>
          </div>
      );
  }

  return (
    <div className="min-h-screen bg-game-bg flex flex-col p-6 overflow-y-auto">
      <div className="text-center mb-10">
          <h2 className="text-3xl font-black text-white mb-1 uppercase tracking-tighter">CAST VOTE</h2>
          <p className="text-xs text-game-danger font-bold uppercase tracking-widest opacity-80">Identify the Imposter</p>
      </div>

      <div className="flex-1 grid grid-cols-2 sm:grid-cols-3 gap-8 pb-32">
          {candidates.map(p => {
              const isSelected = selectedSuspect === p.id;
              return (
                  <button 
                    key={p.id} 
                    onClick={() => setSelectedSuspect(p.id)} 
                    className="flex flex-col items-center group relative outline-none"
                  >
                      <div className={`relative transition-all duration-300 transform ${isSelected ? 'scale-110' : 'group-hover:scale-105'}`}>
                        {/* Selected Shadow Glow */}
                        {isSelected && (
                            <div className="absolute inset-0 bg-game-success/40 rounded-full blur-xl animate-pulse-fast"></div>
                        )}
                        <div className={`relative z-10 rounded-full border-4 transition-all duration-300 ${isSelected ? 'border-game-success shadow-[0_0_25px_rgba(34,197,94,0.6)]' : 'border-slate-800'}`}>
                            <Avatar seed={p.avatarSeed} url={p.avatarUrl} size="lg" className="!gap-0" />
                        </div>
                        {isSelected && (
                            <div className="absolute -top-1 -right-1 bg-game-success text-white rounded-full w-8 h-8 flex items-center justify-center shadow-lg z-20 animate-bounce-in">
                                <span className="text-lg font-black">✓</span>
                            </div>
                        )}
                      </div>
                      <span className={`mt-3 font-black uppercase tracking-widest text-sm transition-colors ${isSelected ? 'text-game-success' : 'text-slate-400'}`}>
                        {p.name}
                      </span>
                  </button>
              );
          })}
      </div>

      <div className="fixed bottom-0 left-0 right-0 p-6 bg-gradient-to-t from-game-bg via-game-bg/90 to-transparent">
          <Button 
            onClick={() => selectedSuspect && myPlayerId && submitVote(myPlayerId, selectedSuspect)} 
            disabled={!selectedSuspect} 
            fullWidth 
            variant={selectedSuspect ? 'success' : 'danger'}
            className="ring-4 ring-offset-4 ring-offset-game-bg ring-transparent active:ring-game-success/50"
          >
              {selectedSuspect ? `VOTE FOR ${players.find(p=>p.id===selectedSuspect)?.name.toUpperCase()}` : "SELECT A SUSPECT"}
          </Button>
      </div>
    </div>
  );
};

