import { GoogleGenAI, Type } from "@google/genai";

// Initialize using a named parameter and exclusively using process.env.API_KEY
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateHostTopic = async (): Promise<{ topic: string, category: string }> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: "Generate a specific secret topic and its category for a social deduction game. The topic should be a specific noun. Return as JSON with keys 'topic' and 'category'.",
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            topic: { type: Type.STRING },
            category: { type: Type.STRING }
          },
          required: ["topic", "category"]
        }
      }
    });
    // response.text is a property, not a method
    return JSON.parse(response.text);
  } catch (error) {
    console.error("Failed to generate host topic", error);
    return { topic: "The Moon", category: "Space" };
  }
};

export const generateGameTopic = async (): Promise<string> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: "Generate a single, interesting, specific noun or short phrase suitable for a game of 'Imposter'. Examples: 'The Eiffel Tower', 'Sushi', 'Mars Landing'. Return ONLY the phrase, no quotes.",
      config: {
        // When setting maxOutputTokens, thinkingBudget must also be specified to avoid empty responses
        maxOutputTokens: 20,
        thinkingConfig: { thinkingBudget: 0 },
        temperature: 1.0,
      }
    });

    return response.text.trim();
  } catch (error) {
    console.error("Failed to generate topic", error);
    return "The Ocean"; // Fallback
  }
};

export const generateClue = async (role: 'INNOCENT' | 'IMPOSTER', topic: string, category: string): Promise<string> => {
    try {
        const prompt = role === 'INNOCENT' 
            ? `You are playing 'Imposter'. Topic: '${topic}', Category: '${category}'. Give a one-word or short phrase clue that is subtle but proves you know the topic. Do not use the word '${topic}'.`
            : `You are playing 'Imposter'. You DON'T know the topic, only Category: '${category}'. Give a vague but confident one-word clue related to '${category}' to blend in.`;

        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
            config: {
                // Disabling thinking budget to ensure maxOutputTokens are reserved for the final response
                maxOutputTokens: 15,
                thinkingConfig: { thinkingBudget: 0 },
                temperature: 0.8,
            }
        });

        return response.text.trim().replace(/['"().]/g, '');
    } catch (error) {
        console.error("Failed to generate bot clue", error);
        return "Broadly speaking...";
    }
};

export const generateImposterGuess = async (category: string, clues: string[]): Promise<string> => {
    try {
        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: `You are the Imposter. Category: '${category}'. Clues given by others: ${clues.join(', ')}. Based on these, what is the secret topic? Return only the topic name.`,
            config: { 
                // Setting thinkingBudget to 0 when using small maxOutputTokens for low-latency direct responses
                maxOutputTokens: 10,
                thinkingConfig: { thinkingBudget: 0 }
            }
        });
        return response.text.trim();
    } catch (error) {
        return "I'm not sure";
    }
};

